-- ============================================
-- Function: AutoGenerateEmployeeId
-- Type: SQL_SCALAR_FUNCTION
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Mehul Panchal  -- Create date: 20/07/2013  -- Description: Based on Finance Year and Month Number Get Year  -- =============================================    -- SELECT dbo.AutoGenerateEmployeeId(2)  Create FUNCTION [dbo].[AutoGenerateEmployeeId]  (   @EmployeeId INT  )  RETURNS nvarchar(10)  AS  BEGIN   DECLARE @Result nvarchar(50)      SET @Result = CASE WHEN len(@EmployeeId)=1 THEN '00000' +CONVERT(VARCHAR, @EmployeeId)       WHEN len(@EmployeeId)=2 THEN '0000' +CONVERT(VARCHAR, @EmployeeId)       WHEN len(@EmployeeId)=3 THEN '000' +CONVERT(VARCHAR, @EmployeeId)       WHEN len(@EmployeeId)=4 THEN '00' +CONVERT(VARCHAR, @EmployeeId)       WHEN len(@EmployeeId)=5 THEN '0' +CONVERT(VARCHAR, @EmployeeId)       ELSE CONVERT(VARCHAR, @EmployeeId)      END            RETURN @Result  END  

GO

-- ============================================
-- Function: BudgetReport_ConvertTaxYearMonthToFinancialYearMonth
-- Type: SQL_SCALAR_FUNCTION
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Saleem Khan  -- Create date: 14/03/2016  -- Description: Get Notch increqase month, bonus month  -- =============================================    CREATE FUNCTION [dbo].[BudgetReport_ConvertTaxYearMonthToFinancialYearMonth]  (   @PeriodInTaxYear int  )  RETURNS int  AS  BEGIN   DECLARE @PeriodInTaxYearTemp int     --Convert to financial year   SET @PeriodInTaxYearTemp = @PeriodInTaxYear + 8   IF @PeriodInTaxYearTemp > 12   BEGIN    SET @PeriodInTaxYear = @PeriodInTaxYearTemp - 12   END   ELSE   BEGIN    SET @PeriodInTaxYear = @PeriodInTaxYearTemp   END     RETURN @PeriodInTaxYear  END  

GO

-- ============================================
-- Function: BudgetReport_GetFinancialMonthFromDate
-- Type: SQL_SCALAR_FUNCTION
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Saleem Khan  -- Create date: 14/03/2016  -- Description: Get Notch increqase month, bonus month  -- 2020-10-02 by CM - Update to new join syntax  -- =============================================    CREATE FUNCTION [dbo].[BudgetReport_GetFinancialMonthFromDate]  (   @EntryDate datetime,   @Type nvarchar(20),   @EmpID int = 0  )  RETURNS int  AS  BEGIN   DECLARE @Result nvarchar(50)   DECLARE @FinMonth INT   DECLARE @BonusMonth INT   DECLARE @BonusMonthC INT   DECLARE @BonusID INT      IF @Type = 'NOTCHINCREASE'    BEGIN    IF MONTH(@EntryDate) > 6    BEGIN     SET @FinMonth = CONVERT(int,MONTH(@EntryDate)) - 6       END    ELSE    BEGIN     SET @FinMonth = CONVERT(int,MONTH(@EntryDate)) + 6    END      SET @Result = @FinMonth   END       IF @Type = 'BONUSMONTH' AND @EmpID != 0   BEGIN   DECLARE @DateOfBirth datetime   DECLARE @JoiningDate datetime      SELECT @DateOfBirth=DateOfBirth,@JoiningDate=JoiningDate FROM dbo.Payroll_Employee WHERE Employee_ID = @EmpID      SELECT @BonusID= PM.[BonusPaymentDateID],@BonusMonthC = BonusMonth    FROM  [dbo].[Const_Payroll_BonusPaymentDate_sys] PB        INNER JOIN [dbo].[Payroll_Municipality] PM ON PB.BonusPaymentDate_ID = PM.BonusPaymentDateID      IF @BonusID = 1    BEGIN     IF MONTH(@JoiningDate) > 6     BEGIN      SET @BonusMonth = CONVERT(int,MONTH(@JoiningDate)) - 6        END     ELSE     BEGIN      SET @BonusMonth = CONVERT(int,MONTH(@JoiningDate)) + 6     END    END    ELSE IF @BonusID = 2    BEGIN     IF MONTH(@DateOfBirth) > 6     BEGIN      SET @BonusMonth = CONVERT(int,MONTH(@DateOfBirth)) - 6        END     ELSE     BEGIN      SET @BonusMonth = CONVERT(int,MONTH(@DateOfBirth)) + 6     END    END    ELSE IF @BonusID = 3    BEGIN     IF MONTH(@BonusMonthC) > 6     BEGIN      SET @BonusMonth = CONVERT(int,MONTH(@BonusMonthC)) - 6        END     ELSE     BEGIN      SET @BonusMonth = CONVERT(int,MONTH(@BonusMonthC)) + 6     END    END      SET @Result = @BonusMonth   END      RETURN @Result    END

GO

-- ============================================
-- Function: BudgetReport_GetIncreaseForYear
-- Type: SQL_SCALAR_FUNCTION
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Saleem Khan  -- Create date: 29/03/2016  -- Description: Get Budget Report minimum increases and percentage for a year  -- =============================================    CREATE FUNCTION [dbo].[BudgetReport_GetIncreaseForYear]  (   @BudgetReportID INT,   @Month INT,   @Type nvarchar(20)  )  RETURNS DECIMAL(18,2)  AS  BEGIN   DECLARE @Y1Percentage DECIMAL(18,2)   DECLARE @Y2Percentage DECIMAL(18,2)   DECLARE @Y3Percentage DECIMAL(18,2)   DECLARE @Y1Minimum DECIMAL(18,2)   DECLARE @Y2Minimum DECIMAL(18,2)   DECLARE @Y3Minimum DECIMAL(18,2)   DECLARE @Year INT   DECLARE @Result DECIMAL(18,2)     -- Get the BudgetReport Year increase details---------------------------   SELECT @Y1Percentage = ISNULL(Y1IncreasePercentage,0), @Y2Percentage = ISNULL(Y2IncreasePercentage,0), @Y3Percentage = ISNULL(Y3IncreasePercentage,0),     @Y1Minimum = ISNULL(Y1IncreaseMinimumAmount,0), @Y2Minimum = ISNULL(Y2IncreaseMinimumAmount,0), @Y3Minimum = ISNULL(Y3IncreaseMinimumAmount,0)   FROM [dbo].[Payroll_BudgetReport]   WHERE BudgetReport_ID = @BudgetReportID        IF @Month > 24    BEGIN    SET @Year = 3   END   ELSE IF @Month > 12   BEGIN    SET @Year = 2   END   ELSE IF @Month > 0   BEGIN    SET @Year = 1   END       IF @Type = 'MINIMUM'    BEGIN      IF @Year = 1    BEGIN     SET @Result = @Y1Minimum    END    ELSE IF @Year = 2    BEGIN     SET @Result = @Y2Minimum    END    ELSE IF @Year = 3    BEGIN     SET @Result = @Y3Minimum    END       END     IF @Type = 'PERCENTAGE'    BEGIN    IF @Year = 1    BEGIN     SET @Result = @Y1Percentage    END    ELSE IF @Year = 2    BEGIN     SET @Result = @Y2Percentage    END    ELSE IF @Year = 3    BEGIN     SET @Result = @Y3Percentage    END   END      RETURN @Result  END  

GO

