-- ============================================
-- Function: Const_RecursiveDivision_fxn
-- Type: SQL_TABLE_VALUED_FUNCTION
-- Schema: dbo
-- ============================================
CREATE FUNCTION [dbo].[Const_RecursiveDivision_fxn](  /**********************************************************  Created by : CB - copied from the net  Created on : 30/04/2010  Does  : Splits a string into a table based on the a given character  Used in  :   Modifications:  2016 07 07 Shardik  Increase DivisionCode 10 to 50   2016 07 18 Brooking C Add in the Indefinite recursion code   **********************************************************/   )  returns @VTable table (TID int identity(1,1),     DivisionParentID int,     Division_ID int,     DivisionDesc nvarchar(200) COLLATE SQL_Latin1_General_CP1_CI_AS,     DivisionCode varchar(50) COLLATE SQL_Latin1_General_CP1_CI_AS,     DepartmentID int)  begin      --Recursive code found on net     WITH DeptDivGroup (DivisionParentID, Division_ID, DivisionDesc, DivisionCode, DepartmentID)   AS   (   -- Anchor member definition    SELECT e.DivisionParentID, e.Division_ID, e.DivisionDesc,e.DivisionCode, e.DepartmentID    FROM dbo.Const_Division AS e    WHERE DivisionParentID IS NULL    UNION ALL   -- Recursive member definition    SELECT e.DivisionParentID,e.Division_ID, e.DivisionDesc,e.DivisionCode, e.DepartmentID     FROM dbo.Const_Division AS e    INNER JOIN DeptDivGroup AS d     ON e.DivisionParentID = d.Division_ID   )      Insert into @VTable (DivisionParentID, Division_ID, DivisionDesc, DivisionCode, DepartmentID)   Select    DivisionParentID, Division_ID, DivisionDesc, DivisionCode, DepartmentID   From     DeptDivGroup   option (maxrecursion 0)       return   end          

GO

-- ============================================
-- Function: GetEmployeeDetails
-- Type: SQL_SCALAR_FUNCTION
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author: MEHUL PANCHAL  -- Create date: 16/10/2013  -- Description: <Description, ,>  -- Select dbo.GetEmployeeDetails(104)  -- =============================================  CREATE FUNCTION [dbo].[GetEmployeeDetails]   (   @EmployeeID INT  )  RETURNS NVARCHAR(MAX)  AS  BEGIN   DECLARE @Result NVARCHAR(MAX)   DECLARE @NewLineChar AS CHAR(2) = CHAR(13) + CHAR(10)      SELECT @Result= (ISNULL(dbo.BufferString_fxn(CONVERT(NVARCHAR(50), PAY_EMP.Employee_ID),                                                                  8, '0'),'') + ','  + ISNULL(PAY_EMP.IdNo,'')  + ',' + ISNULL(PAY_EMP.passportNumber,'') +','+    ISNULL(PAY_EMP.FirstName,'')  + ' '  + ISNULL(PAY_EMP.SurName,''))      FROM payroll_Employee PAY_EMP            where PAY_EMP.EMPLOYEE_ID = @EmployeeID    SET @Result =REPLACE(@Result,',','<br />')  return @Result  END      

GO

