-- Function: GetInvoiceDescription_Payroll
-- Type: SQL_SCALAR_FUNCTION
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Mehul Pancha  -- Create date: 10062014  -- Call select dbo.[GetInvoiceDescription_Payroll](2044)  -- 2015 03 11 CB Do a distinct to prevent multiple of same description  -- =============================================  CREATE FUNCTION [dbo].[GetInvoiceDescription_Payroll]  (   @InvoiceId INT  )  RETURNS nvarchar(MAX)  AS  BEGIN   DECLARE @Result NVARCHAR(MAX)                    SELECT @Result = STUFF((SELECT ',' + CONVERT(NVARCHAR(MAX), ItemDescription)           --FROM dbo.scm_Invoicedetail          From (Select Distinct ItemDescription from scm_Invoicedetail          WHERE Enabled = 1 AND InvoiceId = @InvoiceId) Detail        FOR XML PATH('')),1,1,'')                             RETURN @Result  END  

