-- ============================================
-- Function: GetLastYearTaxYear
-- Type: SQL_SCALAR_FUNCTION
-- Schema: dbo
-- ============================================
-- =================================================================================================  -- Author:  Mehul Panchal  -- Create date: 20/07/2013  -- Description: Based on Finance Year and Month Number Get Year   -- 2016-06-22 TP:38352 - Seipei Mathole: Updated [GetLastYearFinanceYear] To [GetLastYearTaxYear]   -- 2016-06-22 TP:38352 - Updated ActiveFinYear to ActiveTaxYear  -- =================================================================================================    -- SELECT dbo.GetLastYearFinanceYear()  CREATE FUNCTION [dbo].[GetLastYearTaxYear]  (   )  RETURNS NVARCHAR(10)  AS  BEGIN   DECLARE @Result NVARCHAR(10)   DECLARE @Year1 INT   DECLARE @Year2 INT   DECLARE @ActiveTaxYear NVARCHAR(10)      SELECT @ActiveTaxYear = KeyValue FROM dbo.AAAA_ConfigSettings WHERE KeyName = 'TaxYear'      SET @Year1 = (SELECT TOP 1 Value FROM [Split_fxn] (@ActiveTaxYear, '/'))   SET @Year2 = (SELECT TOP 1 Value FROM [Split_fxn] (@ActiveTaxYear, '/') ORDER BY ID DESC)        SET @Year1 = @Year1 - 1   SET @Year2 = @Year2 - 1      SET @Result = CAST(@Year1 as VARCHAR) + '/' + CAST(@Year2 as VARCHAR)      RETURN @Result     --PRINT @Result  END  

GO

-- ============================================
-- Function: GetProjectAvailableBudget_fnc
-- Type: SQL_SCALAR_FUNCTION
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Neo Phuti  -- Create date: 21 September 2016  -- Description: Get Available Budget for a project  -- SELECT DBO.GetProjectAvailableBudget_fnc(1)  -- =============================================  CREATE FUNCTION [dbo].[GetProjectAvailableBudget_fnc]      (        @ProjectID INT       )  RETURNS DECIMAL(18, 2)  AS      BEGIN          DECLARE @AvailableBudget DECIMAL(18, 2)            SELECT  @AvailableBudget = ((SELECT ISNULL(SUM(PRD.EstimatedCost),0)                                        FROM SCM_ProcurementPlanNew PRN                   INNER JOIN SCM_ProcurementPlanDetails PRD ON PRN.ProcurementPlan_ID = PRD.ProcurementPlanID                   WHERE PRN.PlanProjectID = @ProjectID)                            -                                       (SELECT SUM(ISNULL(RSD.Quantity,0)* ISNULL(RSD.EstimatedCost,0))                     FROM SCM_ProcurementPlanNew PRN                      INNER JOIN SCM_ProcurementPlanDetails PRD ON PRN.ProcurementPlan_ID = PRD.ProcurementPlanID                     INNER JOIN SCM_Requisition R ON PRN.ProcurementPlan_ID = R.ProcurementID                     INNER JOIN SCM_RequisitionServiceDetails RSD ON R.Requisition_ID = RSD.RequisitionID                       WHERE PRN.PlanProjectID = @ProjectID))          RETURN ISNULL(@AvailableBudget, 0)      END  

GO

-- ============================================
-- Function: GetYearFromPayrollYearAndMonth
-- Type: SQL_SCALAR_FUNCTION
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  Mehul Panchal  -- Create date: 20/07/2013  -- Description: Based on Finance Year and Month Number Get Year  -- =============================================    -- SELECT dbo.GetYearFromPayrollYearAndMonth ('2012/2013', 7)  CREATE FUNCTION [dbo].[GetYearFromPayrollYearAndMonth]  (   @FinanceYear NVARCHAR(10),   @Month INT  --Calender month  )  RETURNS nvarchar(10)  AS  BEGIN   DECLARE @Result nvarchar(10)   DECLARE @FinYearStartMonth INT      SELECT @FinYearStartMonth = KeyValue FROM dbo.AAAA_ConfigSettings WHERE KeyName = 'TaxFinYearEndMonth'   SET @FinYearStartMonth = @FinYearStartMonth + 1   IF @FinYearStartMonth>12    BEGIN     SET @FinYearStartMonth=1    END   IF(@FinYearStartMonth >  @Month)   BEGIN      SET @Result = (SELECT TOP 1 Value FROM [Split_fxn] (@FinanceYear, '/') ORDER BY ID DESC)     END   ELSE   BEGIN    SET @Result = (SELECT TOP 1 Value FROM [Split_fxn] (@FinanceYear, '/'))   END       RETURN @Result  END    

GO

-- ============================================
-- Function: Led_GetPayrollControlGLDetails_fxn
-- Type: SQL_TABLE_VALUED_FUNCTION
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Jignesh Prajapati  -- Create date: 05 Oct 2016  -- Description: Get Details for Payroll Control GL Details  -- =============================================  CREATE FUNCTION [dbo].[Led_GetPayrollControlGLDetails_fxn]      (        @FinYear VARCHAR(50) ,        @ProcessingMonth INT      )  RETURNS @PayrollControlGLDetails TABLE      (        RuleDesc NVARCHAR(100) ,        ModuleID INT ,        ModuleDesc NVARCHAR(50) ,        IsPass NVARCHAR(50) ,        Variance DECIMAL(18, 2) ,        LastRunDate DATE ,        RuleOrderID INT ,        FinYear NVARCHAR(50) ,        ProcessingMonth INT ,        DebtorsControl DECIMAL(18, 2) ,        BalanceList DECIMAL(18, 2)      )  AS      BEGIN          DECLARE @SalarySuspenseScoaItemID INT ,              @TravelSuspenseScoaItemID INT ,              @LeaveSuspenseScoaItemID INT ,              @SARSSuspenseScoaItemID INT ,              @UIFSuspenseScoaItemID INT ,              @SkillsSuspenseScoaItemID INT ,              @PensionSuspenseScoaItemID INT ,              @MedicalSuspenseScoaItemID INT ,              @GroupLifeSuspenseScoaItemID INT ,              @UnionsSuspenseScoaItemID INT;            SELECT  @SalarySuspenseScoaItemID = [SalarySuspenseScoaItemID] ,                  @TravelSuspenseScoaItemID = [TravelSuspenseScoaItemID] ,                  @LeaveSuspenseScoaItemID = [LeaveSuspenseScoaItemID] ,                  @SARSSuspenseScoaItemID = [SARSSuspenseScoaItemID] ,                  @UIFSuspenseScoaItemID = [UIFSuspenseScoaItemID] ,                  @SkillsSuspenseScoaItemID = [SkillsSuspenseScoaItemID] ,                  @PensionSuspenseScoaItemID = [PensionSuspenseScoaItemID] ,                  @MedicalSuspenseScoaItemID = [MedicalSuspenseScoaItemID] ,                  @GroupLifeSuspenseScoaItemID = [GroupLifeSuspenseScoaItemID] ,                  @UnionsSuspenseScoaItemID = [UnionsSuspenseScoaItemID]          FROM    [dbo].[Payroll_Municipality];            WITH    PayrollControlItems                    AS ( SELECT   ScoaID ,                                  ScoaShortDesc ,                                  ScoaCode                         FROM     dbo.Const_SCOA_Structure                         WHERE    ScoaID IN ( @SalarySuspenseScoaItemID,                                              @TravelSuspenseScoaItemID,                                              @LeaveSuspenseScoaItemID,                                              @SARSSuspenseScoaItemID,                                              @UIFSuspenseScoaItemID,                                              @SkillsSuspenseScoaItemID,                                              @PensionSuspenseScoaItemID,                                              @MedicalSuspenseScoaItemID,                                              @GroupLifeSuspenseScoaItemID,                                              @UnionsSuspenseScoaItemID )                       ),                  PayrollControlGLEntries                    AS ( SELECT   SCOAItemID ,                                  SUM(Debit) AS Debit ,                                  SUM(Credit) AS Credit                         FROM     Led_GeneralLedger                         WHERE    SCOAItemID IN ( @SalarySuspenseScoaItemID,                                                  @TravelSuspenseScoaItemID,                                                  @LeaveSuspenseScoaItemID,                                                  @SARSSuspenseScoaItemID,                                                  @UIFSuspenseScoaItemID,                                                  @SkillsSuspenseScoaItemID,                                                  @PensionSuspenseScoaItemID,                                                  @MedicalSuspenseScoaItemID,                                                  @GroupLifeSuspenseScoaItemID,                                                  @UnionsSuspenseScoaItemID )                                  AND FinYear = @FinYear                                  AND ProcessingMonth = @ProcessingMonth                         GROUP BY SCOAItemID                       )              INSERT  INTO @PayrollControlGLDetails                      SELECT  PCI.ScoaShortDesc AS RuleDesc ,                              3 AS ModuleID ,                              'Payroll' AS ModuleDesc ,                              CASE WHEN ( PCGE.Debit = PCGE.Credit ) THEN 'Pass'                                   ELSE 'Fail'                              END AS IsPass ,                              ( PCGE.Debit - PCGE.Credit ) AS Variance ,                              GETDATE() AS LastRunDate ,                              0 AS RuleOrderID ,                              @FinYear AS FinYear ,                              @ProcessingMonth AS ProcessingMonth ,                              PCGE.Debit AS DebtorsControl ,                              PCGE.Credit AS BalanceList                      FROM    PayrollControlItems AS PCI                              LEFT OUTER JOIN PayrollControlGLEntries AS PCGE ON PCGE.SCOAItemID = PCI.ScoaID;                                        RETURN;      END;  

GO

-- ============================================
-- Function: Payroll_CreateCalendarDates
-- Type: SQL_INLINE_TABLE_VALUED_FUNCTION
-- Schema: dbo
-- ============================================
/*   Author  : Ferdi Botha   Create Date : 2019/09/18   Description : Returns a Calendar of days (in a resultset), between the Start Date and Until Date  */  CREATE function [Payroll_CreateCalendarDates](@StartDate datetime, @UntilDate datetime)  returns    table as return (     select top (datediff(day, @StartDate, @UntilDate) + 1)      dateadd(day, row_number() over(order by [a].[object_id]) - 1, @StartDate) as [Date]      from [master].[sys].[all_objects] as [a] with(nolock)       cross join [master].[sys].[all_objects] as [b] with(nolock)    );

GO

-- ============================================
-- Function: Payroll_GetEmployeeWorkingDays
-- Type: SQL_SCALAR_FUNCTION
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,Name>  -- Create date: <Create Date, ,>  -- Description: <Description, ,>  -- =============================================  CREATE FUNCTION [dbo].[Payroll_GetEmployeeWorkingDays]  (   @EmployeeId INT  )  RETURNS INT  AS  BEGIN   -- Declare the return variable here   DECLARE @Count INT   DECLARE @DayOfWeek  TABLE (DOW INT)   DECLARE @Mon BIT, @Tue BIT, @Wed BIT, @Thu BIT, @Fri BIT, @Sat BIT, @Sun BIT     -- Add the T-SQL statements to compute the return value here   SELECT @Mon = Monday, @Tue = Tuesday, @wed  = Wednesday, @Thu = Thursday, @Fri = Friday, @Sat = Saturday, @Sun = Sunday FROM dbo.Payroll_Employee   WHERE Employee_ID = @EmployeeId      IF @Sun = 1 BEGIN    INSERT INTO @DayOfWeek SELECT 1   END   IF @Mon = 1 BEGIN    INSERT INTO @DayOfWeek SELECT 2   END   IF @Tue = 1 BEGIN    INSERT INTO @DayOfWeek SELECT 3   END   IF @Wed = 1 BEGIN    INSERT INTO @DayOfWeek SELECT 4   END   IF @Thu = 1 BEGIN    INSERT INTO @DayOfWeek SELECT 5   END   IF @Fri = 1 BEGIN    INSERT INTO @DayOfWeek SELECT 6   END   IF @Sat = 1 BEGIN    INSERT INTO @DayOfWeek SELECT 7   END      SELECT @Count = COUNT(*) FROM @DayOfWeek     -- Return the result of the function   RETURN @Count    END  

GO

-- ============================================
-- Function: PayRoll_GetNewNotchUpSalaryOnMonth
-- Type: SQL_SCALAR_FUNCTION
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,Name>  -- Create date: <Create Date, ,>  -- Description: <Description, ,>  -- =============================================  CReate FUNCTION [dbo].[PayRoll_GetNewNotchUpSalaryOnMonth]   (   -- Add the parameters for the function here   @NotchUpNewSalary Decimal,   @CurrentSalary Decimal,   @Y1IncreasePercentage Decimal,   @Y2IncreasePercentage Decimal,   @Y3IncreasePercentage Decimal,   @Y1IncreaseMinimumAmount Decimal,   @Y2IncreaseMinimumAmount Decimal,    @Y3IncreaseMinimumAmount Decimal,   @Month INT  )  RETURNS Decimal  AS  BEGIN   -- Declare the return variable here   DECLARE @ResultVar Decimal     Set @ResultVar = (Case when ((Case When ((@NotchUpNewSalary + (@NotchUpNewSalary/100) *                               (CASE  WHEN @Month > 12 THEN                 @Y2IncreasePercentage Else                  Case When @Month < 13 then                   @Y1IncreasePercentage Else                    Case When @Month > 24 then                    @Y1IncreasePercentage                    else                   1                    End                   End                 END)) >                  (@NotchUpNewSalary +                 (CASE  WHEN @Month > 12 THEN                 @Y2IncreaseMinimumAmount Else                  Case When @Month < 13 then                   @Y1IncreaseMinimumAmount Else                    Case When @Month > 24 then                    @Y3IncreaseMinimumAmount                   else                   0                   End                   End                 END)))                                 Then                                (@NotchUpNewSalary + (@NotchUpNewSalary/100) *                 (CASE  WHEN @Month > 12 THEN                  @Y2IncreasePercentage Else                   Case When @Month < 13 then                    @Y1IncreasePercentage Else                     Case When @Month > 24 then                     @Y1IncreasePercentage                     else                    1                    End                    End                  END))                  Else                    (@NotchUpNewSalary +                   (CASE  WHEN @Month > 12 THEN                   @Y2IncreaseMinimumAmount Else                    Case When @Month < 13 then                     @Y1IncreaseMinimumAmount Else                      Case When @Month > 24 then                      @Y3IncreaseMinimumAmount                     else                     0                     End                     End                   END))                  end ) > @CurrentSalary) then          Case When ((@NotchUpNewSalary + (@NotchUpNewSalary/100) *                               (CASE  WHEN @Month > 12 THEN                 @Y2IncreasePercentage Else                  Case When @Month < 13 then                   @Y1IncreasePercentage Else                    Case When @Month > 24 then                    @Y1IncreasePercentage                    else                   1                    End                   End                 END)) >                  (@NotchUpNewSalary +                 (CASE  WHEN @Month > 12 THEN                 @Y2IncreaseMinimumAmount Else                  Case When @Month < 13 then                   @Y1IncreaseMinimumAmount Else                    Case When @Month > 24 then                    @Y3IncreaseMinimumAmount                   else                   0                   End                   End                 END)))                                 Then                                (@NotchUpNewSalary + (@NotchUpNewSalary/100) *                 (CASE  WHEN @Month > 12 THEN                  @Y2IncreasePercentage Else                   Case When @Month < 13 then                    @Y1IncreasePercentage Else                     Case When @Month > 24 then                     @Y1IncreasePercentage                     else                    1                    End                    End                  END))                  Else                    (@NotchUpNewSalary +                   (CASE  WHEN @Month > 12 THEN                   @Y2IncreaseMinimumAmount Else                    Case When @Month < 13 then                     @Y1IncreaseMinimumAmount Else                      Case When @Month > 24 then                      @Y3IncreaseMinimumAmount                     else                     0                     End                     End                   END))                  end       else       @CurrentSalary      End)     -- Return the result of the function   RETURN @ResultVar    END  

GO

-- ============================================
-- Function: Payroll_GetPublicHoliday
-- Type: SQL_SCALAR_FUNCTION
-- Schema: dbo
-- ============================================
  create function [dbo].[Payroll_GetPublicHoliday](@date datetime)     returns varchar(200)    as  begin     declare @day int = day(@date),     @month int = month(@date),     @holidayDesc varchar(200) = null     select top 1 @holidayDesc = [HolidayDesc]      from [Const_Holiday] with(nolock)      where (day([HolidayDate]) = @day and month([HolidayDate]) = @month and cast(isnull([CalendarYearFrom], '1900') as int) <= year(@date) and cast(isnull([CalendarYearTo], '9999') as int) >= year(@date))     return @holidayDesc    end  

GO

-- ============================================
-- Function: Payroll_IRP5CodeCountRows
-- Type: SQL_SCALAR_FUNCTION
-- Schema: dbo
-- ============================================
  create function [Payroll_IRP5CodeCountRows](@IRP5Code int null)  returns int  as    begin     declare @results int = 0     if (not @IRP5Code is null)      select @results = count([IRP5Code_ID]) from [Payroll_IRP5Code] with(nolock) where (isnull([IRP5CertCode], [IRP5Code]) = @IRP5Code and [Enabled] = 1)     return @results    end  

GO

-- ============================================
-- Function: Payroll_Operator
-- Type: SQL_SCALAR_FUNCTION
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Mehul Panchal  -- Create date: 07 Feb 2014  -- Description: dbo.Payroll_Operator 10,20,'Add'  -- =============================================  CREATE FUNCTION [dbo].[Payroll_Operator]  (   @VALUE1 DECIMAL(18,2),   @VALUE2 DECIMAL(18,2),   @OPERATOR NVARCHAR(100),   @REPLACEVALUE DECIMAL(18,2) = 0  )  RETURNS DECIMAL(18,2)  AS  BEGIN   -- Declare the return variable here   DECLARE @RESULT DECIMAL(18,2)      IF @OPERATOR = 'Add'   BEGIN    SET @RESULT = @VALUE1 + @VALUE2   END   ELSE IF @OPERATOR = 'Subtract'   BEGIN    SET @RESULT = @VALUE1 - @VALUE2   END   ELSE IF @OPERATOR = 'Multiply'   BEGIN    IF(@VALUE1 = 0 OR @VALUE2 = 0)    BEGIN     SET @RESULT = 0    END    ELSE    BEGIN     SET @RESULT = @VALUE1 * @VALUE2     END   END   ELSE IF @OPERATOR = 'Divide'   BEGIN    IF(@VALUE1 = 0 OR @VALUE2 = 0)    BEGIN     SET @RESULT = 0    END    ELSE    BEGIN     SET @RESULT = @VALUE1 / @VALUE2     END   END    ELSE IF @OPERATOR = 'Lessthan Replace'   BEGIN    IF @VALUE1 < @VALUE2    BEGIN     SET @RESULT = @REPLACEVALUE     END    ELSE    BEGIN     SET @RESULT = @VALUE1     END   END   ELSE IF @OPERATOR = 'Greaterthan Replace'   BEGIN    IF @VALUE1 > @VALUE2    BEGIN     SET @RESULT = @REPLACEVALUE     END    ELSE    BEGIN     SET @RESULT = @VALUE1     END   END   ELSE IF @OPERATOR = 'Equal Replace'   BEGIN    IF @VALUE1 = @VALUE2    BEGIN     SET @RESULT = @REPLACEVALUE     END    ELSE    BEGIN     SET @RESULT = @VALUE1     END   END   ELSE IF @OPERATOR = 'Lessthan'   BEGIN    SET @RESULT = @VALUE1    END   ELSE IF @OPERATOR = 'Greaterthan'   BEGIN    SET @RESULT = @VALUE1   END   ELSE IF @OPERATOR = 'Equal'   BEGIN    SET @RESULT = @VALUE1    END      RETURN @RESULT  END

GO

-- ============================================
-- Function: Payroll_PostalAddressStructureIndicator_fxn
-- Type: SQL_SCALAR_FUNCTION
-- Schema: dbo
-- ============================================
/*=============================================  Create date: 17/Oct/2016  Name: Jaydev Jangid  Description:  check Postal Address Structure Indicator, code 3288   Call function: select dbo.Payroll_PostalAddressStructureIndicator_fxn (262) as result  =============================================*/  create FUNCTION [dbo].[Payroll_PostalAddressStructureIndicator_fxn] ( @EmployeeID INT )   RETURNS INT  AS      BEGIN             DECLARE @ReturnCode INT;          DECLARE @PostalSameAsPhysical BIT;          DECLARE @PostalAddressTypeID INT;       SET @PostalSameAsPhysical =0      --Get The various values from the Employee table          SELECT  @PostalSameAsPhysical = PostalSameAsPhysical , @PostalAddressTypeID = PostalAddressTypeID FROM    Payroll_Employee WHERE   Employee_ID = @EmployeeID;      -- If postal address is a physical address and not the same as the residential use code 3          IF @PostalAddressTypeID = 1 AND @PostalSameAsPhysical = 0     BEGIN      SET @ReturnCode = 3;     END    -- If postal address is a non structured address use code 4          ELSE              IF @PostalAddressTypeID = 5      BEGIN       SET @ReturnCode = 4;      END    -- BUT if the two addresses are the same rather use code 1    ELSE     IF @PostalSameAsPhysical = 1      BEGIN       SET @ReturnCode = 1;      END    -- else use code 2 for the other structured postal address types    ELSE     BEGIN      SET @ReturnCode = 2;     END            SET @ReturnCode = ISNULL(@ReturnCode, 0);      --SELECT @ReturnCode      /*if @ReturnCode > 0 AND @ReturnCode < 5    SET @ReturnCode =1   ELSE    SET @ReturnCode =0*/            RETURN @ReturnCode;        END;  

GO

-- ============================================
-- Function: Payroll_ValidateIRPEmpId_fxn
-- Type: SQL_SCALAR_FUNCTION
-- Schema: dbo
-- ============================================
/*-- =============================================  Create date: 08/Oct/2016  Name: Jaydev Jangid  Description:  check Modulus 13 check on ID Number -- if return 1 then true else false  Call function: select dbo.Payroll_ValidateIRPEmpId_Fxn ('8001015009087') as result  =============================================*/  create FUNCTION [dbo].[Payroll_ValidateIRPEmpId_fxn] ( @IdNo NVARCHAR(100) )  RETURNS BIT  AS      BEGIN             DECLARE @IdNoChar INT;          DECLARE @Total INT;          DECLARE @EvenTotal INT;          DECLARE @EvenNo NVARCHAR(10);           DECLARE @Result BIT;          DECLARE @EvenTotalLength INT;             DECLARE @TotalEvenNumber INT;            IF ( LEN(@IdNo) < 12 )              SET @Result = 0;          ELSE              BEGIN                  SET @Total = 0;        --- Add ODD digit (a) point    -- 1 charactor     SET @IdNoChar = SUBSTRING(@IdNo, 1, 1);               SET @Total = @Total + @IdNoChar;      -- 3 charactor              SET @IdNoChar = SUBSTRING(@IdNo, 3, 1);               SET @Total = @Total + @IdNoChar;      -- 5 charactor              SET @IdNoChar = SUBSTRING(@IdNo, 5, 1);               SET @Total = @Total + @IdNoChar;      -- 7 charactor              SET @IdNoChar = SUBSTRING(@IdNo, 7, 1);               SET @Total = @Total + @IdNoChar;      -- 9 charactor              SET @IdNoChar = SUBSTRING(@IdNo, 9, 1);               SET @Total = @Total + @IdNoChar;      -- 11 charactor              SET @IdNoChar = SUBSTRING(@IdNo, 11, 1);               SET @Total = @Total + @IdNoChar;      --PRINT '@Total --' + CONVERT(NVARCHAR,@Total)      --- Add even digit 2+4+6+8+10   (b) point              SET @EvenNo = SUBSTRING(@IdNo, 2, 1);              SET @EvenNo = @EvenNo + SUBSTRING(@IdNo, 4, 1);              SET @EvenNo = @EvenNo + SUBSTRING(@IdNo, 6, 1);              SET @EvenNo = @EvenNo + SUBSTRING(@IdNo, 8, 1);              SET @EvenNo = @EvenNo + SUBSTRING(@IdNo, 10, 1);              SET @EvenNo = @EvenNo + SUBSTRING(@IdNo, 12, 1);      --PRINT '@EvenNo --' + CONVERT(NVARCHAR,@EvenNo)                SET @EvenTotal = CONVERT(INT, @EvenNo) * 2; -- multiply by 2       --PRINT '@@EvenTotal --' + CONVERT(NVARCHAR,@EvenTotal)    -- (c) point, adding all digit                  SET @TotalEvenNumber = 0;                SET @EvenTotalLength = LEN(@EvenTotal);                WHILE @EvenTotalLength > 0      BEGIN                      SET @TotalEvenNumber = @TotalEvenNumber + CONVERT(INT, SUBSTRING(CONVERT(NVARCHAR, @EvenTotal), @EvenTotalLength, 1));       SET @EvenTotalLength = @EvenTotalLength - 1;      END;          --PRINT '@EvenTotal --' + CONVERT(NVARCHAR,@TotalEvenNumber)    ----------------------------    -- (d) point, adding odd and event totals       SET @Total = @Total + @TotalEvenNumber;       --PRINT '@@Total --' + CONVERT(NVARCHAR,@Total)    ----------------------------    -- (e) point, fetch last digit with ID number and compare digit with ID number last value                SET @Total = SUBSTRING(CONVERT(NVARCHAR, @Total), LEN(@Total), 1);  -- fetching last digit of @Total              SET @Total = 10 - @Total;  -- deducting from 10      --PRINT 'last digit --' + CONVERT(NVARCHAR,@Total)    --PRINT 'last digit of id no --' + SUBSTRING(CONVERT(NVARCHAR,@IdNo),LEN(@IdNo),1)       IF @Total = CONVERT(INT, SUBSTRING(CONVERT(NVARCHAR, @IdNo),LEN(@IdNo), 1))       SET @Result = 1;                  ELSE                      SET @Result = 0;              END;                RETURN @Result;      END;  

GO

-- ============================================
-- Function: Payroll_ValidateIRPIncomeTax_fxn
-- Type: SQL_SCALAR_FUNCTION
-- Schema: dbo
-- ============================================
/*-- =============================================  Create date: 07/Oct/2016  Name: Jaydev Jangid  Description:  check Modulus 10 check on Income Tax Number-- if return 1 then true else false  Call function: select dbo.Payroll_ValidateIRPIncomeTax_fxn ('0369333190') as result  =============================================*/    create FUNCTION [dbo].[Payroll_ValidateIRPIncomeTax_fxn]      (        @ITNumber NVARCHAR(100)      )  RETURNS BIT  AS      BEGIN            DECLARE @ITNumberChar INT;          DECLARE @Total INT;          DECLARE @Result BIT;            IF ( LEN(@ITNumber) < 9 )              SET @Result = 0;          ELSE              BEGIN                      SET @Total = 0;     -- 1 charactor                SET @ITNumberChar = SUBSTRING(@ITNumber, 1, 1);                 SET @ITNumberChar = @ITNumberChar * 2;          IF ( @ITNumberChar > 9 ) -- if 7 x 2 = 14 then (1 + 4 = 5)      BEGIN       SET @ITNumberChar = CONVERT(INT, SUBSTRING(CONVERT(NVARCHAR, @ITNumberChar), 1, 1))+ CONVERT(INT, SUBSTRING(CONVERT(NVARCHAR, @ITNumberChar),2, 1));        END;                    SET @Total = @Total + @ITNumberChar;                  SET @ITNumberChar = 0;       -- 2 charactor                  SET @ITNumberChar = SUBSTRING(@ITNumber, 2, 1);                   SET @Total = @Total + @ITNumberChar;       -- 3 charactor                  SET @ITNumberChar = SUBSTRING(@ITNumber, 3, 1);                   SET @ITNumberChar = @ITNumberChar * 2;                     IF ( @ITNumberChar > 9 ) -- if 7 x 2 = 14 then (1 + 4 = 5)                      BEGIN                          SET @ITNumberChar = CONVERT(INT, SUBSTRING(CONVERT(NVARCHAR, @ITNumberChar),1, 1))+ CONVERT(INT, SUBSTRING(CONVERT(NVARCHAR, @ITNumberChar),2, 1));                        END;                    SET @Total = @Total + @ITNumberChar;                  SET @ITNumberChar = 0;       -- 4 charactor                  SET @ITNumberChar = SUBSTRING(@ITNumber, 4, 1);                   SET @Total = @Total + @ITNumberChar;       -- 5 charactor                  SET @ITNumberChar = SUBSTRING(@ITNumber, 5, 1);                   SET @ITNumberChar = @ITNumberChar * 2;                     IF ( @ITNumberChar > 9 ) -- if 7 x 2 = 14 then (1 + 4 = 5)                      BEGIN                          SET @ITNumberChar = CONVERT(INT, SUBSTRING(CONVERT(NVARCHAR, @ITNumberChar),1, 1))+ CONVERT(INT, SUBSTRING(CONVERT(NVARCHAR, @ITNumberChar),2, 1));                        END;                    SET @Total = @Total + @ITNumberChar;                  SET @ITNumberChar = 0;       -- 6 charactor                  SET @ITNumberChar = SUBSTRING(@ITNumber, 6, 1);                   SET @Total = @Total + @ITNumberChar;       -- 7 charactor                  SET @ITNumberChar = SUBSTRING(@ITNumber, 7, 1);                   SET @ITNumberChar = @ITNumberChar * 2;                     IF ( @ITNumberChar > 9 ) -- if 7 x 2 = 14 then (1 + 4 = 5)                      BEGIN                          SET @ITNumberChar = CONVERT(INT, SUBSTRING(CONVERT(NVARCHAR, @ITNumberChar),1, 1))+ CONVERT(INT, SUBSTRING(CONVERT(NVARCHAR, @ITNumberChar),2, 1));                        END;                    SET @Total = @Total + @ITNumberChar;                    SET @ITNumberChar = 0;       -- 8 charactor                  SET @ITNumberChar = SUBSTRING(@ITNumber, 8, 1);                   SET @Total = @Total + @ITNumberChar;       -- 9 charactor                  SET @ITNumberChar = SUBSTRING(@ITNumber, 9, 1);                   SET @ITNumberChar = @ITNumberChar * 2;                     IF ( @ITNumberChar > 9 ) -- if 7 x 2 = 14 then (1 + 4 = 5)                      BEGIN                          SET @ITNumberChar = CONVERT(INT, SUBSTRING(CONVERT(NVARCHAR, @ITNumberChar), 1, 1))+ CONVERT(INT, SUBSTRING(CONVERT(NVARCHAR, @ITNumberChar),2, 1));                        END;                    SET @Total = @Total + @ITNumberChar;       -- Last Digit of Total is not greater than zero 0 so the check digit equal 0 and the number is therefore valid.                  IF SUBSTRING(CONVERT(NVARCHAR, @Total), LEN(@Total), 1) = 0                      SET @Result = 1;                  ELSE                      SET @Result = 0;              END;                RETURN @Result;        END;  

GO

-- ============================================
-- Function: Payroll_ValidateIRPPaye_fxn
-- Type: SQL_SCALAR_FUNCTION
-- Schema: dbo
-- ============================================
/*=============================================  Create date: 08/Oct/2016  Name: Jaydev Jangid  Description:  check Modulus 10 for fields PAYE Reference Number , SDL Reference Number, UIF Reference Number. Number -- if return 1 then true else false  Call function: select dbo.Payroll_ValidateIRPPaye_fxn ('7230767891') as result  =============================================*/  create FUNCTION [dbo].[Payroll_ValidateIRPPaye_fxn]      (        @ReferenceNumber NVARCHAR(100)      )  RETURNS BIT      BEGIN            DECLARE @SDLChar INT;          DECLARE @Total INT;          DECLARE @LastDigit INT;            SET @Total = 8;             IF LEN(@ReferenceNumber) < 9              SET @Total = 0;          ELSE              BEGIN       -- 2 charactor                SET @SDLChar = SUBSTRING(@ReferenceNumber, 2, 1);                 SET @Total = @Total + @SDLChar;       -- 3 charactor                SET @SDLChar = SUBSTRING(@ReferenceNumber, 3, 1);                 SET @Total = @Total + ( @SDLChar * 2 );       -- 4 charactor                SET @SDLChar = SUBSTRING(@ReferenceNumber, 4, 1);                 SET @Total = @Total + @SDLChar;       -- 5 charactor                SET @SDLChar = SUBSTRING(@ReferenceNumber, 5, 1);                 SET @SDLChar = @SDLChar * 2;                  IF ( @SDLChar > 9 ) -- if 7 x 2 = 14 then (1 + 4 = 5)                  BEGIN       SET @SDLChar = CONVERT(INT, SUBSTRING(CONVERT(NVARCHAR, @SDLChar), 1, 1)) + CONVERT(INT, SUBSTRING(CONVERT(NVARCHAR, @SDLChar), 2, 1));                    END;                 SET @Total = @Total + @SDLChar;       -- 6 charactor                SET @SDLChar = SUBSTRING(@ReferenceNumber, 6, 1);                 SET @Total = @Total + @SDLChar;       -- 7 charactor                SET @SDLChar = SUBSTRING(@ReferenceNumber, 7, 1);                 SET @SDLChar = @SDLChar * 2;          IF ( @SDLChar > 9 ) -- if 7 x 2 = 14 then (1 + 4 = 5)      BEGIN       SET @SDLChar = CONVERT(INT, SUBSTRING(CONVERT(NVARCHAR, @SDLChar), 1, 1)) + CONVERT(INT, SUBSTRING(CONVERT(NVARCHAR, @SDLChar),2, 1));        END;       SET @Total = @Total + @SDLChar;       -- 8 charactor      SET @SDLChar = SUBSTRING(@ReferenceNumber, 8, 1);                   SET @Total = @Total + @SDLChar;       -- 9 charactor                  SET @SDLChar = SUBSTRING(@ReferenceNumber, 9, 1);                   SET @SDLChar = @SDLChar * 2;        IF ( @SDLChar > 9 ) -- if 7 x 2 = 14 then (1 + 4 = 5)      BEGIN       SET @SDLChar = CONVERT(INT, SUBSTRING(CONVERT(NVARCHAR, @SDLChar), 1, 1))+ CONVERT(INT, SUBSTRING(CONVERT(NVARCHAR, @SDLChar),2, 1));                    END;                SET @Total = @Total + @SDLChar;                IF SUBSTRING(CONVERT(NVARCHAR, @Total), 2, 1) > 0      BEGIN       SET @LastDigit = 10 - CONVERT(INT, SUBSTRING(CONVERT(NVARCHAR, @Total), 2, 1));                           IF @LastDigit = 1                              SET @Total = 1;                          ELSE                              SET @Total = 0;                      END;                  ELSE                      SET @Total = 0;              END;                    RETURN @Total;      END;  

GO

-- ============================================
-- Function: Plan_AdjustmentFundingSourceBudgetPerYear_fxn
-- Type: SQL_TABLE_VALUED_FUNCTION
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author: Sahil Nagpal  -- Description: Returns table of ammount required for a project for the given financial year    -- Calls: select * from Plan_FundingSourceBudgetPerYear_fxn('2016/2017','2016/2017','C')  -- 30-05-2019 By SNagpal: #89269 - Add multiyear concept to SCOA segments based upon financial year  -- 10-03-2023 By CM: 98477 - Look at adjustment project item tables to calculate allocated funds  -- =============================================================================    CREATE   FUNCTION [dbo].[Plan_AdjustmentFundingSourceBudgetPerYear_fxn]      (     @FinYear nvarchar(9)  ,   @CurFinYear nvarchar(9),   @BudgetType VARCHAR(10),   @AdjustmentVersionId INT,   @AdjustmentFundingVersionId INT  )    RETURNS   @tblTotals TABLE     (      ParentID int,     SCOAFundID int,    SCOADesc nvarchar(700),     ScoaCode nvarchar(50),   ScoaShortDesc nvarchar(200),   RemainingFundAmount DECIMAL(16,2)  )      AS    BEGIN        DECLARE @tmpTbl AS TABLE      (        ParentID int,       SCOAFundID int,      SCOADesc nvarchar(700),       ScoaCode nvarchar(50),     ScoaShortDesc nvarchar(200),     RemainingFundAmount DECIMAL(16,2)   )     DECLARE @CurFinYearAsNumber INT = CAST(SUBSTRING(@CurFinYear, 1, 4) AS INT)   DECLARE @FinYearAsNumber INT = CAST(SUBSTRING(@FinYear, 1, 4) AS INT)     INSERT INTO @tmpTbl      SELECT      availFund.ParentID    ,availFund.SCOAFundID    ,availFund.SCOADesc    ,availFund.ScoaCode     ,availFund.ScoaShortDesc    ,(ISNULL(availFund.AvailFundAmt,0) - ISNULL(allocatedFund.AllocFundAmount,0))   FROM    (     SELECT f.ScoaParentID as ParentID      ,f.ScoaID as SCOAFundID      ,f.ScoaDesc + ' (' + left(f.PostingLevel,1) + '/ ' + f.ScoaCode + ')' as SCOADesc      ,f.ScoaCode       ,f.ScoaShortDesc      ,ISNULL(SUM(ISNULL(d.FundingSourceBudget,0)),0) as AvailFundAmt      FROM Plan_AdjustmentFundingSourceBudget_Detail d     INNER JOIN Plan_AdjustmentFundingSourceBudget_Header h ON d.AdjustmentFundingSourceBudgetHeaderID=h.AdjustmentFundingSourceBudgetHeader_ID     INNER JOIN dbo.Const_Scoa_Funds_Structure_ByYear(@CurFinYear) f ON d.ScoaID=f.ScoaID     WHERE       h.FinancialYear = @FinYear AND d.AdjustmentFundingVersionId= @AdjustmentFundingVersionId      GROUP BY f.ScoaParentID       ,f.ScoaID       ,f.ScoaDesc ,f.PostingLevel,f.ScoaCode       ,f.ScoaCode       ,f.ScoaShortDesc    ) availFund     LEFT JOIN     (    SELECT  ScoaFundID,      ISNULL(CASE WHEN @FinYearAsNumber = @CurFinYearAsNumber THEN SUM(ISNULL(AdjustedBudgetAmount, BudgetAmount))         ELSE CASE WHEN @FinYearAsNumber = @CurFinYearAsNumber + 1 THEN SUM(ISNULL(AdjustedBudgetAmountCurP1, BudgetAmountCurP1))          ELSE CASE WHEN @FinYearAsNumber = @CurFinYearAsNumber + 2 THEN SUM(ISNULL(AdjustedBudgetAmountCurP2, BudgetAmountCurP2))          END         END        END, 0) AllocFundAmount    FROM    Plan_AdjustmentProjectItem ppi      INNER JOIN Plan_AdjustmentProject pp ON ppi.AdjustmentProjectID = pp.AdjustmentProject_ID     WHERE   pp.AdjustmentVersionId = @AdjustmentVersionId      AND CapitalOperation IN (0, 1, 4)      AND ISNULL(pp.isDeleted, 0) <> 1    GROUP BY ScoaFundID   ) allocatedFund on availFund.SCOAFundID=allocatedFund.ScoaFundID     WHERE  ISNULL(AvailFundAmt,0)-ISNULL(AllocFundAmount,0)>=0     IF (@BudgetType = 'C')   BEGIN    INSERT INTO @tblTotals    SELECT t.* FROM @tmpTbl t    INNER JOIN dbo.Const_PlanSCOAFundCapital cps ON t.SCOAFundID = cps.ScoaFundId    WHERE cps.IsEnable=1 AND cps.FinYear= @CurFinYear   END   ELSE IF (@BudgetType = 'O')   BEGIN    INSERT INTO @tblTotals    SELECT t.* FROM @tmpTbl t    INNER JOIN dbo.Const_PlanSCOAFundOperational cpso ON t.SCOAFundID = cpso.ScoaFundId    WHERE cpso.IsEnable=1 AND cpso.FinYear= @CurFinYear   END   ELSE   BEGIN    INSERT INTO @tblTotals    SELECT t.* FROM @tmpTbl t   END      RETURN  END    

GO

-- ============================================
-- Function: Plan_BudgetConsumptionDetail_fxn
-- Type: SQL_TABLE_VALUED_FUNCTION
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Chris Moodley  -- Create date: 06 August 2020  -- Description: Return budget consumption details  -- NP - 26 AUG 2020 - WI 42288  -- 20 Jan 2021 : Savvin M. : #53777 Delta01 Budget Consumption - Csv export issue(s)  --23-Feb-2021 : MS : #57965 Delta 01 Payment - Sundry Invoice payment issues  -- 15 Mar 2021 : Savvin M. : #59527 UAT- Debit and credit note Budget consumption  -- 25 Mar 2021 : Savvin M. : #60512 UAT Consumption - Project initiation shows budget for 3 financial years  -- 02 Apr 2021 : Mikolenko R. : #63055 UAT budget consumption detail and incorrect on multiyear req and transactions  -- 12 Sept 2021 : SNagpal : #64238 UAT: All lines on Order not displayed after contract is rolled forward, budget incorrect  -- 16 Sept 2021 : NP : 74428 - UAT - Budget Consumption Summary Report Incorrectly Displaying - Note that the report must only display the last consuming record  -- 06 Oct 2021 : MS #75041 UAT- Budget Consumption summary Incorrect-transactions on budget migrated contract  -- 06 Oct 2021 : MS #75041 UAT- Budget Consumption summary Incorrect-transactions on budget migrated contract - Behalf of him  -- 12 Oct 2021 : MS #77193 - Rollback change as per discussion with Nicola, Nirav  -- 22 Oct 2021 : CM #77547 - Fix how tranasaction amount is calculated on CSR approval for summary report  -- 06 Dec 2021 : CM #75106 - Change join to OUTER APPLY to return document details for imported/consolidated entries  -- 13 Aug 2024 : NP - 114183 - Budget consumption summary is incorrect on issue to capital expense  -- =============================================  CREATE FUNCTION [dbo].[Plan_BudgetConsumptionDetail_fxn]  (   -- Add the parameters for the function here   @PlanProjectItemID INT,   @StartMonth INT,   @EndMonth INT,   @IsDetailRpt INT  )  RETURNS @BudgetConsumptionDetail TABLE  (   -- Add the column definitions for the TABLE variable here   BudgetConsumption_ID INT,   TransactionDate VARCHAR(50),   TransactionAmount DECIMAL(18,2),    DocumentNumber VARCHAR(1000),    TransactionType VARCHAR(1000),    BudgetTransactionType VARCHAR(1000),    PlanProjectItemID INT,   DateCaptured DATETIME  )  AS  BEGIN   -- Multiyear amount should not be considered for Project Initiation records   DECLARE @ProjectInitiationID INT = 200;     -- Fill the table variable with the rows for your result set   IF (@IsDetailRpt = 0)   BEGIN    DECLARE @RequestType_ID INT, @Status_ID INT    SELECT @RequestType_ID = RequestType_ID FROM Const_RequestType_sys where RequestDesc = 'Inventory Request'    SELECT @Status_ID = Status_ID FROM Const_Status where StatusDesc = 'Approved' and UsedBy = 'InvenIssue'    DECLARE @IssueToCapitalExpenseRequisition TABLE      (      RequisitionNumber NVARCHAR(100)    )      INSERT INTO @IssueToCapitalExpenseRequisition    SELECT DISTINCT R.RequisitionNumber FROM SCM_Requisition R      INNER JOIN SCM_RequisitionServiceDetails RSD ON R.Requisition_ID = RSD.RequisitionID     INNER JOIN SCM_GeneralRequest GR ON R.Requisition_ID = GR.SCMRequisitionID     INNER JOIN Inven_InventoryIssue I ON I.InvRequisitionID = GR.InvRequisitionID     INNER JOIN Inven_InventoryIssueLineItem ILI ON I.Issue_ID = ILI.IssueID    WHERE GR.RequestTypeID = @RequestType_ID and I.Status = @Status_ID and        ILI.IssueToCapitalExpense = 1 and RSD.PlanProjectItemId = @PlanProjectItemID      INSERT INTO @BudgetConsumptionDetail    SELECT     MIN(Q.BudgetConsumption_ID) AS BudgetConsumption_ID,     CONVERT(VARCHAR, MIN(Q.DateCaptured), 103) AS TransactionDate,     SUM(Q.TransactionAmount) AS TransactionAmount,     Q.DocumentNumber,     BCP.BudgetConsumptionProcessDesc AS TransactionType,     dbo.Plan_GetBudgetTransactionTypeDesc(Q.BudgetConsumptionProcessID, Q.BudgetTransactionTypeID) AS BudgetTransactionType,     Q.PlanProjectItemID,     MIN(Q.DateCaptured) AS DateCaptured    FROM    (     SELECT       BC.BudgetConsumption_ID,      BC.BudgetConsumptionProcessID,      BC.BudgetTransactionTypeID,      -(CASE WHEN TransactionTableName  = 'SCM_ContractServiceRequestDetails' AND BudgetConsumptionProcessID = 129 THEN ISNULL(ABS(ConsumingTransactionAmount), 0) ELSE ISNULL(BC.CurrentlyConsumedAmount, 0) END + IIF(BC.BudgetConsumptionProcessID = @ProjectInitiationID, 0, ISNULL(BC.CurrentlyConsumedAmountMultiyear, 0))) AS TransactionAmount,      BC.InitialLine,      docDetail.DocNumber DocumentNumber,      BC.DateCaptured,      BC.PlanProjectItemID     FROM      (        SELECT         MIN(BC.BudgetConsumption_ID) AS BudgetConsumption_ID,        BC.InitialLine       FROM        Plan_BudgetConsumption BC        WHERE         BC.PlanProjectItemID = @PlanProjectItemID        AND BC.ProcessingMonth BETWEEN @StartMonth AND @EndMonth        AND ISNULL(BC.CurrentlyConsumedAmount, 0) + IIF(BC.BudgetConsumptionProcessID = @ProjectInitiationID, 0, ISNULL(BC.CurrentlyConsumedAmountMultiyear, 0)) != 0       GROUP BY BC.InitialLine      ) IL      INNER JOIN Plan_BudgetConsumption BC        ON IL.InitialLine = BC.InitialLine      OUTER APPLY Plan_GetBudgetDocumentDetail(BC.TransactionTableName, BC.PK_TransactionID) docDetail     WHERE       BC.PlanProjectItemID = @PlanProjectItemID      AND BC.ProcessingMonth BETWEEN @StartMonth AND @EndMonth      AND ((CASE WHEN docDetail.DocNumber LIKE 'PI%' THEN ABS(ISNULL(BC.CurrentlyConsumedAmount, 0)) ELSE                  (ISNULL(BC.CurrentlyConsumedAmount, 0) + IIF(BC.BudgetConsumptionProcessID = @ProjectInitiationID, 0, ISNULL(BC.CurrentlyConsumedAmountMultiyear, 0))) END)) != 0    ) Q    LEFT JOIN Const_BudgetConsumptionProcess_Sys BCP      ON Q.BudgetConsumptionProcessID = BCP.BudgetConsumptionProcess_ID    WHERE Q.DocumentNumber NOT IN ( SELECT RequisitionNumber FROM @IssueToCapitalExpenseRequisition )    GROUP BY     Q.DocumentNumber,     BCP.BudgetConsumptionProcessDesc,     Q.BudgetConsumptionProcessID,     Q.BudgetTransactionTypeID,     Q.PlanProjectItemID     END   ELSE   BEGIN        INSERT INTO @BudgetConsumptionDetail    SELECT     pbc.BudgetConsumption_ID,     CONVERT(VARCHAR, pbc.DateCaptured, 103) TransactionDate,     CASE       WHEN pbc.BudgetTransactionTypeID = 6 THEN AdjustedTansactionAmount       ELSE ConsumingTransactionAmount + IIF(pbc.BudgetConsumptionProcessID = @ProjectInitiationID, 0, ISNULL(ConsumingTransactionAmountMultiyear, 0)) END TransactionAmount,     ISNULL(docDetail.DocNumber, pbc.TransactionTableName + '_' + CONVERT(VARCHAR, pbc.PK_TransactionID)) DocumentNumber,     bcp.BudgetConsumptionProcessDesc TransactionType,     dbo.Plan_GetBudgetTransactionTypeDesc(pbc.BudgetConsumptionProcessID, pbc.BudgetTransactionTypeID) AS BudgetTransactionType,     PlanProjectItemID,     pbc.DateCaptured    FROM     Plan_BudgetConsumption pbc     LEFT JOIN Const_BudgetConsumptionProcess_Sys bcp ON pbc.BudgetConsumptionProcessID = bcp.BudgetConsumptionProcess_ID     OUTER APPLY Plan_GetBudgetDocumentDetail(pbc.TransactionTableName, pbc.PK_TransactionID) docDetail    WHERE      PlanProjectItemID = @PlanProjectItemID     AND ProcessingMonth BETWEEN @StartMonth AND @EndMonth     AND ConsumingTransactionAmount + IIF(pbc.BudgetConsumptionProcessID = @ProjectInitiationID, 0, ISNULL(ConsumingTransactionAmountMultiyear, 0)) != 0     END     RETURN   END

GO

-- ============================================
-- Function: Plan_BudgetSign_fxn
-- Type: SQL_SCALAR_FUNCTION
-- Schema: dbo
-- ============================================
CREATE FUNCTION [dbo].[Plan_BudgetSign_fxn] (  @scoaItemCode NVARCHAR(50),  @capitalOperational INT,  @creditDebit NVARCHAR(1),  @scoaItemShortDesc NVARCHAR(200),  @finYear NVARCHAR(9) ) RETURNS INT AS BEGIN   DECLARE @sign INT = 1;  DECLARE @finYearEnd INT = CONVERT(INT, SUBSTRING(@finYear, 6, 9))   SELECT @sign =    CASE WHEN @finYearEnd >= 2026 THEN   CASE     WHEN @scoaItemCode LIKE 'IL%'          AND @scoaItemShortDesc IN ('Deposits')    THEN      CASE WHEN @creditDebit = 'C' THEN -1 ELSE 1 END     WHEN @scoaItemCode LIKE 'IL%'          AND @scoaItemShortDesc IN ('Withdrawals')    THEN      CASE WHEN @creditDebit = 'D' THEN 1 ELSE -1 END     WHEN @scoaItemCode LIKE 'IL%'          AND @scoaItemShortDesc NOT IN ('Deposits', 'Withdrawals')    THEN      CASE WHEN @creditDebit = 'C' THEN -1 ELSE 1 END     ELSE      CASE       WHEN        (        (@scoaItemCode LIKE 'IL%' OR @scoaItemCode LIKE 'IR%')        AND @capitalOperational IN (0,1,2)       )       OR @creditDebit = 'C'      THEN -1 ELSE 1      END   END   ELSE    CASE      WHEN       (       (@scoaItemCode LIKE 'IL%' OR @scoaItemCode LIKE 'IR%')       AND @capitalOperational IN (0,1,2)      )      OR @creditDebit = 'C'     THEN -1 ELSE 1     END   END;   RETURN @sign;  END;

GO

-- ============================================
-- Function: Plan_DivisionDescDirectorate_fxn
-- Type: SQL_SCALAR_FUNCTION
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Sahil Nagpal  -- Create date: 06/03/2017  -- Description: Gets DivisionDesc of Directorate level  -- Calls : SELECT dbo.Plan_DivisionDescDirectorate_fxn(100)  -- =============================================  CREATE FUNCTION [dbo].[Plan_DivisionDescDirectorate_fxn]   -- Add the parameters for the function here  (   @DivisionID int  )  RETURNS VARCHAR(500)  AS  BEGIN   -- Declare the return variable here   DECLARE @DivisionDesc VARCHAR(500)    ;WITH CTE1 AS  (   SELECT  DivisionDesc,DivisionParentID,Division_ID,DirectorateLevel   FROM Const_Division    WHERE Division_ID = @DivisionID   UNION ALL    SELECT D.DivisionDesc, D.DivisionParentID, D.Division_ID,D.DirectorateLevel   FROM Const_Division D   INNER JOIN CTE1 C ON C.DivisionParentID = D.Division_ID   )    SELECT TOP 1 @DivisionDesc = CTE1.DivisionDesc FROM CTE1  WHERE DirectorateLevel = 1     -- Return the result of the function   RETURN @DivisionDesc    END        

GO

-- ============================================
-- Function: Plan_DivisionIDDirectorate_fxn
-- Type: SQL_SCALAR_FUNCTION
-- Schema: dbo
-- ============================================
    -- =============================================  -- Author:  Sahil Nagpal  -- Create date: 06/03/2017  -- Description: Gets DivisionDesc of Directorate level  -- Calls : SELECT dbo.Plan_DivisionIDDirectorate_fxn(1152)    -- Updated:  Richard Bothma  -- Create date: 15/05/2017  -- Description: Adapted original version of function (Plan_DivisionDescDirectorate_fxn) to pass ID instead of Description only      --Gets DivisionID of Directorate level  -- =============================================  CREATE FUNCTION [dbo].[Plan_DivisionIDDirectorate_fxn]   -- Add the parameters for the function here  (   @DivisionID INT  )  RETURNS INT  AS  BEGIN   -- Declare the return variable here   DECLARE @DivisionID_Returned INT    ;WITH CTE1 AS  (   SELECT  DivisionDesc,DivisionParentID,Division_ID,DirectorateLevel   FROM Const_Division    WHERE Division_ID = @DivisionID   UNION ALL    SELECT D.DivisionDesc, D.DivisionParentID, D.Division_ID,D.DirectorateLevel   FROM Const_Division D   INNER JOIN CTE1 C ON C.DivisionParentID = D.Division_ID   )    SELECT TOP 1 @DivisionID_Returned = CTE1.Division_ID FROM CTE1  WHERE DirectorateLevel = 1     -- Return the result of the function   RETURN @DivisionID_Returned    END    

GO

-- ============================================
-- Function: Plan_FundingSourceBudgetAvailableAmtPerYear_fxn
-- Type: SQL_TABLE_VALUED_FUNCTION
-- Schema: dbo
-- ============================================
    -- =============================================  -- Author:  Jignesh Prajapati  -- Create date: 14/03/2016  -- Description: Get Fund Available Amount  -- =============================================  CREATE FUNCTION [dbo].[Plan_FundingSourceBudgetAvailableAmtPerYear_fxn] ( @FinYear NVARCHAR(9) )  RETURNS @tblTotals TABLE      (        ParentID INT ,        SCOAFundID INT ,        SCOADesc NVARCHAR(700) ,        ScoaCode NVARCHAR(50) ,        ScoaShortDesc NVARCHAR(200) ,        AvailableAmt DECIMAL(16, 2)      )  AS      BEGIN             INSERT  INTO @tblTotals                  SELECT  availFund.ParentID ,                          availFund.SCOAFundID ,                          availFund.SCOADesc ,                          availFund.ScoaCode ,                          availFund.ScoaShortDesc ,                          ISNULL(AvailFundAmt, 0) - ISNULL(AllocFundAmount, 0)                  FROM    ( SELECT    f.ScoaParentID AS ParentID ,                                      f.ScoaID AS SCOAFundID ,                                      f.ScoaDesc + ' (' + LEFT(f.PostingLevel, 1)                                      + '/ ' + f.ScoaCode + ')' AS SCOADesc ,                                      f.ScoaCode ,                                      f.ScoaShortDesc ,                                      SUM(d.FundingSourceBudget) AS AvailFundAmt                            FROM      Plan_FundingSourceBudget_Detail d                                      INNER JOIN Plan_FundingSourceBudget_Header h ON d.FundingSourceBudgetHeaderID = h.FundingSourceBudgetHeader_ID                                      INNER JOIN Const_SCOA_Funds_Structure f ON d.ScoaID = f.ScoaID                            WHERE     h.FinancialYear = @FinYear                            GROUP BY  f.ScoaParentID ,                                      f.ScoaID ,                                      f.ScoaDesc ,                                      f.PostingLevel ,                                      f.ScoaCode ,                                      f.ScoaCode ,                                      f.ScoaShortDesc                          ) availFund                          LEFT JOIN ( SELECT  pf.ScoaFundID ,                                              SUM(y.YearFundAmount) AS AllocFundAmount                                      FROM    Plan_ProjectFund pf                                              INNER JOIN Plan_ProjectFundYear y ON pf.ProjectFund_ID = y.ProjectFundID                                              INNER JOIN Plan_Project pp ON pf.ProjectID = pp.Project_ID                                      WHERE   y.FinYear = @FinYear                                              AND ISNULL(pp.IsDeleted, 0) <> 1                                      GROUP BY ScoaFundID                                    ) allocatedFund ON availFund.SCOAFundID = allocatedFund.ScoaFundID;          RETURN;         END;    

GO

-- ============================================
-- Function: Plan_FundingSourceBudgetPerYear_fxn
-- Type: SQL_TABLE_VALUED_FUNCTION
-- Schema: dbo
-- ============================================
-- =============================================================================    -- Author:  RC  -- Create date: 18/05/2015    -- Description: Returns table of ammount required for a project for the given financial year    -- Calls: select * from Plan_FundingSourceBudgetPerYear_fxn('2020/2021','2019/2020','')  -- 25/02/2016 by RC : Only fund that still have availabe fund must be returned  -- 09/03/2016 by RC : Need to sum on YearFundAmount.  -- 27/09/2016 by SNagpal: Added >= in "WHERE  ISNULL(AvailFundAmt,0)-ISNULL(AllocFundAmount,0)>=0"  ---- 07-12-2016 By SNagpal: Add column for Remaining Amount  --09-12-2016 By SNagpal: Apply Isnull Conditions on amount  --13-12-2016 By SNagpal: Change the where clause of filtering Finyear. before it was from Plan_ProjectFundYear now from Plan_project.  --31-01-2017 By SNagpal: Revert the changes of where clause of filtering Finyear. before it was from Plan_project now from Plan_ProjectFundYear.  --01-02-2017 By SNagpal: Add @CurFinYear in where clause  --06-11-2017 By SNagpal: #63164 : Add Parameter BudgetType, Based upon SCOAFunds loaded from Constants  --30-05-2019 By SNagpal: #89269 - Add multiyear concept to SCOA segments based upon financial year  --24-03-2021 By CMoodley: #61107 - Only include CapitalOperation projects in 0, 1, 4  --20-05-2021 By CM: 64327 - Only include CapitalOperation projects in 0, 1, 4  --10-03-2023 By CM: 98477 - Look at project item tables to calculate allocated funds  -- =============================================================================    CREATE   FUNCTION dbo.Plan_FundingSourceBudgetPerYear_fxn      (     @FinYear nvarchar(9)  ,   @CurFinYear nvarchar(9),   @BudgetType VARCHAR(10)  )    RETURNS     @tblTotals TABLE     (       ParentID int,      SCOAFundID int,     SCOADesc nvarchar(700),      ScoaCode nvarchar(50),    ScoaShortDesc nvarchar(200),    RemainingFundAmount DECIMAL(16,2)  )    AS    BEGIN        DECLARE @tmpTbl AS TABLE      (        ParentID int,       SCOAFundID int,      SCOADesc nvarchar(700),       ScoaCode nvarchar(50),     ScoaShortDesc nvarchar(200),     RemainingFundAmount DECIMAL(16,2)   )     DECLARE @CurFinYearAsNumber INT = CAST(SUBSTRING(@CurFinYear, 1, 4) AS INT);   DECLARE @FinYearAsNumber INT = CAST(SUBSTRING(@FinYear, 1, 4) AS INT);     INSERT INTO @tmpTbl      select     availFund.ParentID    ,availFund.SCOAFundID    ,availFund.SCOADesc    ,availFund.ScoaCode     ,availFund.ScoaShortDesc    ,(ISNULL(availFund.AvailFundAmt,0) - ISNULL(allocatedFund.AllocFundAmount,0))   From    (     SELECT f.ScoaParentID as ParentID      ,f.ScoaID as SCOAFundID      ,f.ScoaDesc + ' (' + left(f.PostingLevel,1) + '/ ' + f.ScoaCode + ')' as SCOADesc      ,f.ScoaCode       ,f.ScoaShortDesc      ,ISNULL(SUM(ISNULL(d.FundingSourceBudget,0)),0) as AvailFundAmt      FROM Plan_FundingSourceBudget_Detail d     INNER JOIN Plan_FundingSourceBudget_Header h ON d.FundingSourceBudgetHeaderID=h.FundingSourceBudgetHeader_ID     INNER JOIN dbo.Const_Scoa_Funds_Structure_ByYear(@CurFinYear) f ON d.ScoaID=f.ScoaID     WHERE       h.FinancialYear = @FinYear      GROUP BY f.ScoaParentID       ,f.ScoaID       ,f.ScoaDesc ,f.PostingLevel,f.ScoaCode       ,f.ScoaCode       ,f.ScoaShortDesc    ) availFund   LEFT JOIN    (     SELECT        ScoaFundID,        ISNULL(CASE WHEN @FinYearAsNumber = @CurFinYearAsNumber THEN ISNULL(SUM(BudgetAmount), 0)        ELSE CASE WHEN @FinYearAsNumber = @CurFinYearAsNumber + 1 THEN ISNULL(SUM(BudgetAmountCurP1), 0)         ELSE CASE WHEN @FinYearAsNumber = @CurFinYearAsNumber + 2 THEN ISNULL(SUM(BudgetAmountCurP2), 0)         END        END       END, 0) As AllocFundAmount     FROM    Plan_ProjectItem ppi       INNER JOIN Plan_Project pp ON ppi.ProjectID = pp.Project_ID     WHERE   ppi.FinYear = @CurFinYear       AND CapitalOperation IN (0, 1, 4)       AND ISNULL(IsDeleted, 0) <> 1     GROUP BY ScoaFundID    ) allocatedFund on availFund.SCOAFundID=allocatedFund.ScoaFundID   WHERE  ISNULL(AvailFundAmt,0)-ISNULL(AllocFundAmount,0)>=0     IF (@BudgetType = 'C')   BEGIN    INSERT INTO @tblTotals    SELECT t.* FROM @tmpTbl t    INNER JOIN dbo.Const_PlanSCOAFundCapital cps ON t.SCOAFundID = cps.ScoaFundId    WHERE cps.IsEnable=1 AND cps.FinYear= @CurFinYear   END   ELSE IF (@BudgetType = 'O')   BEGIN    INSERT INTO @tblTotals    SELECT t.* FROM @tmpTbl t    INNER JOIN dbo.Const_PlanSCOAFundOperational cpso ON t.SCOAFundID = cpso.ScoaFundId    WHERE cpso.IsEnable=1 AND cpso.FinYear= @CurFinYear   END   ELSE   BEGIN    INSERT INTO @tblTotals    SELECT t.* FROM @tmpTbl t   END      RETURN  END    

GO

-- ============================================
-- Function: Plan_GetBudgetAmountsByProjectItemID_fxn
-- Type: SQL_TABLE_VALUED_FUNCTION
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  Raindree Chetty  -- Create date: 11/08/2017  -- Description: Get Project budget values by PlanProjectItemID  -- Call : select * from dbo.[Plan_GetBudgetAmountsByProjectItemID_fxn](0)  --   -- =============================================  CREATE FUNCTION [dbo].[Plan_GetBudgetAmountsByProjectItemID_fxn]  (    @PlanProjectItemID INT  )  RETURNS @Budget TABLE  (   PlanProjectItemID INT ,   BudgetAmount DECIMAL(18,2),   BudgetAmountCurP1 DECIMAL(18,2),   BudgetAmountCurP2 DECIMAL(18,2)  )  BEGIN   INSERT INTO @Budget   (PlanProjectItemID, BudgetAmount, BudgetAmountCurP1, BudgetAmountCurP2)   SELECT PlanProjectItem_ID    ,( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND pp.CapitalOperation IN (0,1,2))OR ppi.CreditDebit = 'C')    THEN -ppi.BudgetAmount ELSE ppi.BudgetAmount END ) AS BudgetAmount     ,( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND pp.CapitalOperation IN (0,1,2))OR ppi.CreditDebit = 'C')     THEN -ppi.BudgetAmountCurP1 ELSE ppi.BudgetAmountCurP1 END ) AS BudgetAmountCurP1     ,( CASE WHEN (((css.ScoaCode LIKE 'IR%' OR css.ScoaCode LIKE 'IL%') AND pp.CapitalOperation IN (0,1,2))OR ppi.CreditDebit = 'C')     THEN -ppi.BudgetAmountCurP2 ELSE ppi.BudgetAmountCurP2 END ) AS BudgetAmountCurP2    FROM Plan_Project pp    INNER JOIN Plan_ProjectItem ppi ON pp.Project_ID=ppi.ProjectID    INNER JOIN Const_SCOA_Structure css ON ppi.ScoaItemID=css.ScoaID   WHERE PlanProjectItem_ID=@PlanProjectItemID OR  @PlanProjectItemID=0   RETURN;  END      

GO

-- ============================================
-- Function: Plan_GetBudgetDocumentDetail
-- Type: SQL_TABLE_VALUED_FUNCTION
-- Schema: dbo
-- ============================================
-- ==========================================================================================    -- Author:  Richa Mills    -- Create date: 19 Feb 2019    -- Description: Return Document Numbers for specific Docs    -- 18-05-2020 by CM: Include additional document types    -- 03-06-2020 by CM: Return document details for Led_PaymentInstructionDetails    -- 07-07-2020 by V Shemet: #37642 Display actual Payment Instruction number    -- 08-07-2020 by V Shemet: #37641 Display actual CSR number    -- 08-07-2020 by V Shemet: #37704 GRA to display GRA number and merge lines    -- 10-07-2020 by CM: #37388 Return document details for SCM_InvoiceCreditDetail    -- 14 Jul 2020 by CM: #38562 Handle case where Document Number is NULL for Led_Journal_Multiple    -- 17 Jul 2020 by CM: #38658 Return document number for SCM_TenderBBBEEPreferencePoints table    -- 02 Aug 2020 by SNagpal: #38445 Return document number for SCM_ContractExtensionAndVariation  -- Select * from [dbo].[Plan_GetBudgetDocumentDetail] ('SCM_ContractExtensionAndVariation', 16)   -- 01 Mar 2022 by SNagpal: #83995 Reports displays Requisition Numbers on the reports when Tenders have been created  -- ==========================================================================================    CREATE FUNCTION [dbo].[Plan_GetBudgetDocumentDetail] ( @TableName VARCHAR(MAX),@PK int )    RETURNS      @tbl TABLE       (      DocType VARCHAR(500),      DocNumber VARCHAR(500)     )    AS    BEGIN      IF @TableName = 'Plan_ProjectItem'      INSERT INTO @tbl      SELECT 'Opening Budget' AS DocType, 'Plan_ProjectItem_' + CONVERT(VARCHAR, @Pk) DocNumber           ELSE IF @TableName = 'Plan_Virements'      INSERT INTO @tbl      SELECT 'Virement' DocType,'Plan_Virements_' + CONVERT(VARCHAR,@Pk) DocNumber           ELSE IF @TableName = 'SCM_RequisitionServiceDetails'      INSERT INTO @tbl      SELECT  'Requisition' AS DocType,RequisitionNumber AS DocNumber FROM SCM_Requisition WHERE Requisition_ID in       (SELECT RequisitionId FROM SCM_RequisitionServiceDetails WHERE RequisitionDetail_ID = @PK)          ELSE IF @TableName = 'SCM_ServiceInvoiceDetails'      INSERT INTO @tbl      SELECT 'Service Invoice' AS DocType, ServiceInvoiceNumber AS DocNumber FROM SCM_ServiceInvoice WHERE ServiceInvoice_ID in       (SELECT ServiceInvoiceId FROM SCM_ServiceInvoiceDetails WHERE ServiceInvoiceDetail_ID = @PK)          ELSE IF @TableName = 'SCM_GRNDetails'      INSERT INTO @tbl      SELECT 'GRN' AS DocType, GrnVendorNumber AS DocNumber FROM SCM_Grn WHERE Grn_Id in      (SELECT GrnId FROM SCM_GrnDetails WHERE GrnDetail_Id = @PK)          ELSE IF @TableName = 'SCM_OrderTypeDetail'      INSERT INTO @tbl      SELECT 'Order' AS DocType, OrderNumber AS DocNumber FROM SCM_Order WHERE Order_ID in       (SELECT OrderId FROM SCM_OrderTypeDetail WHERE OrderDetailID = @PK)          ELSE IF @TableName = 'SCM_QuotationServiceDetail'      INSERT INTO @tbl      SELECT 'Quotation' AS DocType, QuotationNumber AS DocNumber FROM Scm_Quotation WHERE Quotation_Id in      (SELECT QuotationId FROM SCM_QuotationServiceDetail WHERE QuotationServiceDel_ID = @Pk)          ELSE IF @TableName = 'SCM_InvoiceDetail'      INSERT INTO @tbl      SELECT 'Invoice' AS DocType, VendorInvoiceNumber AS DocNumber FROM SCM_Invoice WHERE Invoice_ID in      (SELECT InvoiceId FROM Scm_InvoiceDetail WHERE InvoiceDetail_ID = @PK)          ELSE IF @TableName = 'SCM_InformalTenderServiceDetail'      INSERT INTO @tbl      SELECT 'Informal Tender' DocType,InformalTenderNumber DocNumber FROM SCM_InformalTender WHERE InformalTender_ID in      (SELECT InformalTenderId FROM SCM_InformalTenderServiceDetail WHERE TenderServiceDel_ID = @PK)          ELSE IF @TableName = 'SCM_SundryPaymentServiceDetails'      INSERT INTO @tbl      SELECT 'Sundry Invoice' DocType,SundryPaymentNumber DocNumber FROM SCM_SundryPayment WHERE SundryPayment_ID in      (SELECT SundryPaymentID FROM SCM_SundryPaymentServiceDetails WHERE SundryPaymentDetail_ID = @PK)          ELSE IF @TableName = 'SCM_ContractDetailItems'      INSERT INTO @tbl      SELECT 'Contract Detail' DocType,ContractNumber DocNumber FROM SCM_ContractDetails WHERE Contract_ID in      (SELECT ContractID FROM SCM_ContractDetailItems WHERE ContractDetailItems_ID = @PK)          ELSE IF @TableName = 'SCM_RequisitionTenderLink'      INSERT INTO @tbl         SELECT 'Tender Requisition' DocType,TenderNumber DocNumber FROM SCM_Tender WHERE Tender_ID in     (SELECT TenderID FROM SCM_RequisitionTenderLink WHERE RequisitionTenderLink_ID = @PK)    --SELECT 'Tender Requisition' DocType,RequisitionNumber DocNumber FROM SCM_Requisition WHERE Requisition_ID in      --(SELECT RequisitionID FROM SCM_RequisitionServiceDetails WHERE RequisitionDetail_ID IN       --(SELECT RequisitionDetailID FROM SCM_RequisitionTenderLink WHERE RequisitionTenderLink_ID = @PK))          ELSE IF @TableName = 'Asset_DepreciationSchedule_Item'      INSERT INTO @tbl       SELECT 'Asset Depreciation Schedule' DocType,'Asset_DepreciationSchedule_Item' + '_' + CONVERT(VARCHAR, @PK) DocNumber             ELSE IF @TableName = 'Asset_Disposal_Approval'      INSERT INTO @tbl       SELECT 'Asset Disposal' DocType,'Asset_Disposal_Approval' + '_' + CONVERT(VARCHAR, @PK) DocNumber           ELSE IF @TableName = 'Asset_Impairment'      INSERT INTO @tbl       SELECT 'Asset Impairment' DocType,'Asset_Impairment' + '_' + CONVERT(VARCHAR, @PK) DocNumber           ELSE IF @TableName = 'Asset_Register_Transactions'      INSERT INTO @tbl       SELECT 'Asset Register' DocType,'Asset_Register_Transactions' + '_' + CONVERT(VARCHAR, @PK) DocNumber           ELSE IF @TableName = 'Inven_InventoryRequisition'      INSERT INTO @tbl      SELECT 'Inventory Requisition' DocType,InvRequistionNumber DocNumber FROM Inven_InventoryRequisition WHERE InvRequisition_ID = @PK          ELSE IF @TableName = 'Inven_InventoryRequisitionLineItem'      INSERT INTO @tbl      SELECT 'Inventory Requisition Line Item' DocType,InvRequistionNumber DocNumber FROM Inven_InventoryRequisition WHERE InvRequisition_ID IN       (SELECT InvRequisitionID FROM Inven_InventoryRequisitionLineItem WHERE InvRequisitionLineItem_ID = @PK)          ELSE IF @TableName = 'Inven_InventoryIssue'      INSERT INTO @tbl      SELECT 'Inventory Issue' DocType,UniqueInventoryReference DocNumber FROM Inven_InventoryIssue WHERE Issue_ID = @PK          ELSE IF @TableName = 'Inven_InventoryIssueLineItem'      INSERT INTO @tbl      SELECT 'Inventory Requisition Line Item' DocType,UniqueInventoryReference DocNumber FROM Inven_InventoryIssue WHERE Issue_ID IN       (SELECT IssueID FROM Inven_InventoryIssueLineItem WHERE InvIssueLineItem_ID = @PK)          ELSE IF @TableName = 'Led_Journal_Multiple'      INSERT INTO @tbl      SELECT 'Multiple Journal' DocType, ISNULL(DocumentNumber, TransactionID) DocNumber FROM Led_Journal_Multiple WHERE MultipleJournal_ID = @PK          ELSE IF @TableName = 'Led_Journal_Normal'      INSERT INTO @tbl      SELECT 'Normal Journal' DocType,DocumentNumber DocNumber FROM Led_Journal_Normal WHERE NormalJournal_ID = @PK          ELSE IF @TableName = 'Led_Journal_Asset'      INSERT INTO @tbl      SELECT 'Asset Journal' DocType,DocumentNumber DocNumber FROM Led_Journal_Asset WHERE AssetJournal_ID = @PK          ELSE IF @TableName = 'Led_Journal_Inven'      INSERT INTO @tbl      SELECT 'Inventory Journal' DocType,DocumentNumber DocNumber FROM Led_Journal_Inven WHERE InvenJournal_ID = @PK          ELSE IF @TableName = 'Led_PaymentInstructionDetails'      INSERT INTO @tbl      SELECT 'Payment Instructions' DocType, PaymentReferenceNumber AS DocNumber FROM SCM_Payment WHERE Payment_ID IN       (SELECT PaymentID        FROM Led_PaymentInstructionDetails Led_PID       INNER JOIN Led_PaymentInstructions Led_PI ON Led_PID.PaymentInstructions_ID = Led_PI.PaymentInstructions_ID       WHERE Led_PID.PaymentInstructionDetail_ID = @PK)          ELSE IF @TableName = 'SCM_ContractServiceRequestDetails'      INSERT INTO @tbl      SELECT 'SCM_ContractServiceRequestDetails' DocType, ServiceRequestNumber AS DocNumber FROM SCM_ContractServiceRequest WHERE ContractServiceRequest_ID IN       (SELECT ContractServiceRequestId        FROM SCM_ContractServiceRequestDetails       WHERE ContractServiceRequestDetails_ID = @PK)          ELSE IF @TableName = 'SCM_GRADetails'      INSERT INTO @tbl      SELECT 'SCM_GRADetails' DocType, GRAVendorNumber AS DocNumber FROM SCM_GRA WHERE GRA_ID IN       (SELECT GRAID        FROM SCM_GRADetails       WHERE GRADetail_ID = @PK)          ELSE IF @TableName = 'SCM_InvoiceCreditDetail'      INSERT INTO @tbl      SELECT 'Invoice Credit Detail' DocType, CreditDebitNumber AS DocNumber FROM SCM_InvoiceCreditDebtNote WHERE ID IN       (SELECT InvoiceCreditID FROM SCM_InvoiceCreditDetail WHERE InvoiceCreditDetail_ID = @PK)          ELSE IF @TableName = 'Inven_InventoryReturnLineItem'      INSERT INTO @tbl      SELECT 'Inventory Return To Store Line Item' DocType, IIR.UniqueInventoryReference as DocNumber       FROM dbo.Inven_InventoryReturnLineItem IIRL            LEFT JOIN Inven_InventoryReturn IIR ON IIR.Return_ID = IIRL.ReturnID       WHERE IIRL.InvReturnLineItem_ID = @PK          ELSE IF @TableName = 'SCM_TenderBBBEEPreferencePoints'      INSERT INTO @tbl      SELECT 'Tender BBBEE Points' DocType, TenderNumber DocNumber FROM SCM_Tender WHERE Tender_ID IN      (SELECT TenderID FROM SCM_TenderBBBEEPreferencePoints WHERE PreferencePoints_ID = @PK)        ELSE IF @TableName = 'SCM_ContractExtensionAndVariation'      INSERT INTO @tbl      SELECT 'SCM_ContractExtensionAndVariation' AS DocType,ContractNumber AS DocNumber FROM SCM_ContractDetails WHERE Contract_ID in      (SELECT ContractID FROM SCM_ContractExtensionAndVariation WHERE Extension_ID = @PK)        ELSE      INSERT INTO @tbl      SELECT @TableName AS DocType, @TableName + '_' + CONVERT(VARCHAR, @PK) AS DocNumber         RETURN    END

GO

-- ============================================
-- Function: Plan_GetBudgetDocumentDetailLink_fxn
-- Type: SQL_SCALAR_FUNCTION
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Chris Moodley  -- Create date: 09 July 2020  -- Description: Return document link between processes  -- 17 Jul 2020 by CM: #38658 Return document link for SCM_TenderBBBEEPreferencePoints table  -- =============================================  CREATE FUNCTION [dbo].[Plan_GetBudgetDocumentDetailLink_fxn]  (   -- Add the parameters for the function here   @TableName VARCHAR(MAX),   @PK int  )  RETURNS VARCHAR(MAX)  AS  BEGIN   -- Declare the return variable here   DECLARE @DocumentDetailLink VARCHAR(MAX)     -- Add the T-SQL statements to compute the return value here   IF @TableName = 'Plan_ProjectItem'   SELECT @DocumentDetailLink = 'Plan_ProjectItem_' + CONVERT(VARCHAR, @PK)     ELSE IF @TableName = 'Plan_Virements'   SELECT @DocumentDetailLink = 'Plan_Virements_' + CONVERT(VARCHAR, @PK)     ELSE IF @TableName = 'Led_PaymentInstructionDetails'   SELECT @DocumentDetailLink = 'Led_PaymentInstructionDetails_' + CONVERT(VARCHAR, @PK)     ELSE IF @TableName = 'Led_Cashbook'   SELECT @DocumentDetailLink = 'Led_Cashbook_' + CONVERT(VARCHAR, @PK)     ELSE IF @TableName = 'SCM_ContractExtensionAndVariation'   SELECT @DocumentDetailLink = 'SCM_RequisitionServiceDetails_' + CONVERT(VARCHAR, RequisitionDetailID) FROM SCM_ContractExtensionAndVariation WHERE Extension_ID = @PK     ELSE IF @TableName = 'Inven_InventoryIssueLineItem'   SELECT @DocumentDetailLink = 'SCM_RequisitionServiceDetails_' + CONVERT(VARCHAR, RequisitionDetailID) FROM Inven_InventoryIssueLineItem WHERE InvIssueLineItem_ID = @PK     ELSE IF @TableName = 'SCM_GRNDetails'   SELECT @DocumentDetailLink = 'SCM_RequisitionServiceDetails_' + CONVERT(VARCHAR, RequisitionDelID)    FROM SCM_GRNDetails grn LEFT JOIN dbo.SCM_OrderTypeDetail sotd ON grn.OrderDetailID = sotd.OrderDetailID   WHERE GRNDetail_ID = @PK     ELSE IF @TableName = 'SCM_ContractServiceRequestDetails'   SELECT @DocumentDetailLink = 'SCM_RequisitionServiceDetails_' + CONVERT(VARCHAR, RequisitionDetailID)    FROM SCM_ContractServiceRequestDetails scsrd LEFT JOIN dbo.SCM_ServiceInvoiceDetails ssid ON scsrd.ServiceInvoiceDetail_ID = ssid.ServiceInvoiceDetail_ID   WHERE ContractServiceRequestDetails_ID = @PK     ELSE IF @TableName = 'SCM_InformalTenderServiceDetail'   SELECT @DocumentDetailLink = 'SCM_RequisitionServiceDetails_' + CONVERT(VARCHAR, RequisitionDetailID) FROM SCM_InformalTenderServiceDetail WHERE TenderServiceDel_ID = @PK     ELSE IF @TableName = 'Asset_DepreciationSchedule_Item'   SELECT @DocumentDetailLink = 'Asset_DepreciationSchedule_Item_' + CONVERT(VARCHAR, Asset_DepreciationSchedule_Item_ID) FROM Asset_DepreciationSchedule_Item WHERE Asset_DepreciationSchedule_Item_ID = @PK     ELSE IF @TableName = 'Asset_Disposal_Approval'   SELECT @DocumentDetailLink = 'Asset_Disposal_Approval_' + CONVERT(VARCHAR, AssetDisposalApproval_ID) FROM Asset_Disposal_Approval WHERE AssetDisposalApproval_ID = @PK     ELSE IF @TableName = 'Asset_Impairment'   SELECT @DocumentDetailLink = 'Asset_Impairment_' + CONVERT(VARCHAR, Impairment_ID) FROM Asset_Impairment WHERE Impairment_ID = @PK     ELSE IF @TableName = 'Asset_Register_Transactions'   SELECT @DocumentDetailLink = 'Asset_Register_Transactions_' + CONVERT(VARCHAR, ID) FROM Asset_Register_Transactions WHERE ID = @PK     ELSE IF @TableName = 'SCM_ContractDetailItems'   SELECT @DocumentDetailLink = 'SCM_RequisitionServiceDetails_' + CONVERT(VARCHAR, RequisitionDetailID) FROM SCM_ContractDetailItems WHERE ContractDetailItems_ID = @PK     ELSE IF @TableName = 'SCM_InvoiceCreditDetail'   SELECT @DocumentDetailLink = 'SCM_RequisitionServiceDetails_' + CONVERT(VARCHAR, ISNULL(sotd.RequisitionDelID, sid.RequisitionDetailID))    FROM SCM_InvoiceCreditDetail sicd    LEFT JOIN SCM_InvoiceDetail sidl ON sicd.InvoiceDetailID = sidl.InvoiceDetail_ID   LEFT JOIN SCM_OrderTypeDetail sotd ON sidl.OrderDetailID = sotd.OrderDetailID OR sotd.OrderDetailID = sicd.OrderDetailID   LEFT JOIN SCM_ContractServiceRequestDetails csrd ON sidl.ContractServiceRequestDetailsId = csrd.ContractServiceRequestDetails_ID   LEFT JOIN SCM_ServiceInvoiceDetails sid ON csrd.ServiceInvoiceDetail_ID = sid.ServiceInvoiceDetail_ID   WHERE InvoiceCreditDetail_ID = @PK     ELSE IF @TableName = 'Led_PettyCashExpense'   SELECT @DocumentDetailLink = 'Led_PettyCashExpense_' + CONVERT(VARCHAR, PettyCashExpenseID) FROM Led_PettyCashExpense WHERE PettyCashExpenseID = @PK     ELSE IF @TableName = 'SCM_OrderTypeDetail'   SELECT @DocumentDetailLink = 'SCM_RequisitionServiceDetails_' + CONVERT(VARCHAR, RequisitionDelID) FROM SCM_OrderTypeDetail WHERE OrderDetailID = @PK     ELSE IF @TableName = 'SCM_SundryPaymentServiceDetails'   SELECT @DocumentDetailLink = 'SCM_SundryPaymentServiceDetails_' + CONVERT(VARCHAR, SundryPaymentDetail_ID) FROM SCM_SundryPaymentServiceDetails WHERE SundryPaymentDetail_ID = @PK     ELSE IF @TableName = 'Led_Journal_Multiple'   SELECT @DocumentDetailLink = 'Led_Journal_Multiple_' + CONVERT(VARCHAR, MultipleJournal_ID) FROM Led_Journal_Multiple WHERE MultipleJournal_ID = @PK     ELSE IF @TableName = 'Led_Journal_Normal'   SELECT @DocumentDetailLink = 'Led_Journal_Normal_' + CONVERT(VARCHAR, NormalJournal_ID) FROM Led_Journal_Normal WHERE NormalJournal_ID = @PK     ELSE IF @TableName = 'Led_Journal_Asset'   SELECT @DocumentDetailLink = 'Led_Journal_Asset_' + CONVERT(VARCHAR, AssetJournal_ID) FROM Led_Journal_Asset WHERE AssetJournal_ID = @PK     ELSE IF @TableName = 'Led_Journal_Inven'   SELECT @DocumentDetailLink = 'Led_Journal_Inven_' + CONVERT(VARCHAR, InvenJournal_ID) FROM Led_Journal_Inven WHERE InvenJournal_ID = @PK     ELSE IF @TableName = 'SCM_InvoiceDetail'   SELECT @DocumentDetailLink = 'SCM_RequisitionServiceDetails_' + CONVERT(VARCHAR, ISNULL(sotd.RequisitionDelID, sid.RequisitionDetailID))    FROM SCM_InvoiceDetail sidl    LEFT JOIN SCM_OrderTypeDetail sotd ON sidl.OrderDetailID = sotd.OrderDetailID   LEFT JOIN SCM_ContractServiceRequestDetails csrd ON sidl.ContractServiceRequestDetailsId = csrd.ContractServiceRequestDetails_ID   LEFT JOIN SCM_ServiceInvoiceDetails sid ON csrd.ServiceInvoiceDetail_ID = sid.ServiceInvoiceDetail_ID   WHERE InvoiceDetail_ID = @PK     ELSE IF @TableName = 'SCM_RequisitionTenderLink'   SELECT @DocumentDetailLink = 'SCM_RequisitionServiceDetails_' + CONVERT(VARCHAR, RequisitionDetailID) FROM SCM_RequisitionTenderLink WHERE RequisitionTenderLink_ID = @PK     ELSE IF @TableName = 'SCM_RequisitionServiceDetails'   SELECT @DocumentDetailLink = 'SCM_RequisitionServiceDetails_' + CONVERT(VARCHAR, RequisitionDetail_ID) FROM SCM_RequisitionServiceDetails WHERE RequisitionDetail_ID = @PK     ELSE IF @TableName = 'SCM_GRADetails'   SELECT DISTINCT @DocumentDetailLink = 'SCM_RequisitionServiceDetails_' + CONVERT(VARCHAR, RequisitionDetail_ID)    FROM dbo.SCM_GRADetails GRAD    LEFT JOIN dbo.SCM_GRNDetails GD ON GD.GRNID = GRAD.GRN_Id    LEFT JOIN dbo.SCM_OrderTypeDetail OD ON OD.OrderDetailID = GD.OrderDetailID    LEFT JOIN dbo.SCM_RequisitionServiceDetails RSD ON RSD.RequisitionDetail_ID = OD.RequisitionDelID   WHERE GRADetail_ID = @PK     ELSE IF @TableName = 'SCM_QuotationServiceDetail'   SELECT @DocumentDetailLink = 'SCM_RequisitionServiceDetails_' + CONVERT(VARCHAR, RequisitionDetailID) FROM SCM_QuotationServiceDetail WHERE QuotationServiceDel_ID = @PK     ELSE IF @TableName = 'Inven_InventoryReturnLineItem'   SELECT @DocumentDetailLink = 'Inven_InventoryReturnLineItem_ID_' + CONVERT(VARCHAR, InvReturnLineItem_ID) FROM Inven_InventoryReturnLineItem WHERE InvReturnLineItem_ID = @PK     ELSE IF @TableName = 'SCM_TenderBBBEEPreferencePoints'   SELECT @DocumentDetailLink = 'SCM_RequisitionServiceDetails_' + CONVERT(VARCHAR, RequisitionDetailID)    FROM SCM_TenderBBBEEPreferencePoints stbpp LEFT JOIN dbo.SCM_RequisitionTenderLink srtl ON stbpp.TenderRequisitionLinkID = srtl.RequisitionTenderLink_ID   WHERE PreferencePoints_ID = @PK     -- Return the result of the function   RETURN @DocumentDetailLink    END

GO

-- ============================================
-- Function: Plan_GetBudgetTransactionOutstandingAmount_fxn
-- Type: SQL_SCALAR_FUNCTION
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Mike Savvin  -- Create date: 01 Jan 2021  -- Description: Function to define the outstanding amount of the entity  -- =============================================  CREATE FUNCTION [dbo].[Plan_GetBudgetTransactionOutstandingAmount_fxn]  (   -- Add the parameters for the function here   @TableName VARCHAR(MAX),   @PK INT  )  RETURNS DECIMAL(18, 2)  AS  BEGIN   -- Declare the return variable here   DECLARE @OutstandingAmount DECIMAL(18, 2)     -- Add the T-SQL statements to compute the return value here   IF @TableName = 'SCM_RequisitionServiceDetails'   SELECT @OutstandingAmount =     CASE WHEN EXISTS    (     SELECT 1     FROM SCM_QuotationServiceDetail QSD     INNER JOIN SCM_RequisitionServiceDetails RSD      ON RSD.RequisitionDetail_ID = QSD.RequisitionDetailID     INNER JOIN SCM_Quotation Q      ON QSD.QuotationID = Q.Quotation_ID     WHERE ISNULL(Q.Cancel, 0) = 0      AND RSD.RequisitionDetail_ID = @PK       UNION       SELECT 1     FROM SCM_InformalTenderServiceDetail ITSD     INNER JOIN SCM_RequisitionServiceDetails RSD      ON RSD.RequisitionDetail_ID = ITSD.RequisitionDetailID     INNER JOIN SCM_InformalTender IT      ON ITSD.InformalTenderID = IT.InformalTender_ID     WHERE ISNULL(IT.Cancel, 0) = 0      AND RSD.RequisitionDetail_ID = @PK       UNION       SELECT 1     FROM SCM_RequisitionTenderLink RTL     INNER JOIN SCM_Tender T      ON T.Tender_ID = RTL.TenderID     INNER JOIN SCM_RequisitionServiceDetails RSD      ON RSD.RequisitionDetail_ID = RTL.RequisitionDetailID     WHERE ISNULL(T.TenderCancel, 0) = 0      AND RSD.RequisitionDetail_ID = @PK       UNION       SELECT 1     FROM Inven_InventoryIssueLineItem IIL     INNER JOIN SCM_RequisitionServiceDetails RSD      ON RSD.RequisitionDetail_ID = IIL.RequisitionDetailID     INNER JOIN Inven_InventoryIssue II      ON II.Issue_ID = IIL.IssueID     WHERE ISNULL(II.CancelReason, '') != ''      AND ISNULL(IIL.Completed, 0) = 1      AND RSD.RequisitionDetail_ID = @PK       UNION       SELECT 1     FROM SCM_RequisitionServiceDetails RSD     INNER JOIN SCM_Requisition R      ON R.Requisition_ID = RSD.RequisitionID     WHERE ISNULL(R.Enabled, 0) = 0      AND RSD.RequisitionDetail_ID = @PK    )    THEN      0    ELSE    (     SELECT TOP (1)       (EstimatedCost * Quantity) AS Amount     FROM SCM_RequisitionServiceDetails RSD     WHERE RSD.RequisitionDetail_ID = @PK    )    END     IF @TableName = 'SCM_QuotationServiceDetail'   SELECT @OutstandingAmount =     CASE WHEN EXISTS    (     SELECT 1     FROM SCM_ContractDetailItems CDI     INNER JOIN SCM_RequisitionServiceDetails RSD      ON RSD.RequisitionDetail_ID = CDI.RequisitionDetailID     INNER JOIN SCM_QuotationServiceDetail QSD      ON QSD.RequisitionDetailID = RSD.RequisitionDetail_ID     WHERE ISNULL(CDI.Enabled, 0) = 1      AND QSD.QuotationServiceDel_ID = @PK       UNION       SELECT 1     FROM SCM_QuotationServiceDetail QSD     INNER JOIN SCM_Quotation Q      ON Q.Quotation_ID = QSD.QuotationID     WHERE ISNULL(Q.Cancel, 0) = 1      AND QSD.QuotationServiceDel_ID = @PK    )    THEN      0    ELSE    (     SELECT TOP (1)      (      ISNULL(QSVD.Cost, QSD.EstimatedCost * QSD.Quantity) -      (       SELECT ISNULL(SUM(OTD.Amount), 0)       FROM SCM_OrderTypeDetail OTD       INNER JOIN SCM_RequisitionServiceDetails RSD        ON RSD.RequisitionDetail_ID = OTD.RequisitionDelID       INNER JOIN SCM_QuotationServiceDetail QSD        ON QSD.RequisitionDetailID = RSD.RequisitionDetail_ID       WHERE (ISNULL(OTD.IsVoid, 0) = 0 OR ISNULL(OTD.IsCompletedOnVoid, 0) = 1)        AND QSD.QuotationServiceDel_ID = @PK       )     ) AS Amount     FROM SCM_QuotationServiceDetail QSD     LEFT JOIN SCM_QuotationServiceVendorDetail QSVD      ON QSVD.QuotationServiceDetailID = QSD.QuotationServiceDel_ID AND ISNULL(QSVD.Successful, 0) = 1     WHERE QSD.QuotationServiceDel_ID = @PK    )    END     IF @TableName = 'SCM_InformalTenderServiceDetail'   SELECT @OutstandingAmount =     CASE WHEN EXISTS    (     SELECT 1     FROM SCM_ContractDetailItems CDI     INNER JOIN SCM_RequisitionServiceDetails RSD      ON RSD.RequisitionDetail_ID = CDI.RequisitionDetailID     INNER JOIN SCM_InformalTenderServiceDetail ITSD      ON ITSD.RequisitionDetailID = RSD.RequisitionDetail_ID     WHERE ISNULL(CDI.Enabled, 0) = 1      AND ITSD.TenderServiceDel_ID = @PK       UNION       SELECT 1     FROM SCM_InformalTenderServiceDetail ITSD     INNER JOIN SCM_InformalTender IT      ON IT.InformalTender_ID = ITSD.InformalTenderID     WHERE ISNULL(IT.Cancel, 0) = 1      AND ITSD.TenderServiceDel_ID = @PK    )    THEN      0    ELSE    (     SELECT TOP (1)      (      ISNULL(ITSVD.Cost, ITSD.EstimatedCost * ITSD.Quantity) -      (       SELECT ISNULL(SUM(OTD.Amount), 0)       FROM SCM_OrderTypeDetail OTD       INNER JOIN SCM_RequisitionServiceDetails RSD        ON RSD.RequisitionDetail_ID = OTD.RequisitionDelID       INNER JOIN SCM_InformalTenderServiceDetail ITSD        ON ITSD.RequisitionDetailID = RSD.RequisitionDetail_ID       WHERE (ISNULL(OTD.IsVoid, 0) = 0 OR ISNULL(OTD.IsCompletedOnVoid, 0) = 1)        AND ITSD.TenderServiceDel_ID = @PK       )     ) AS Amount     FROM SCM_InformalTenderServiceDetail ITSD     LEFT JOIN SCM_InformalTenderServiceVendorDetail ITSVD      ON ITSVD.TenderServiceDelID = ITSD.TenderServiceDel_ID AND ISNULL(ITSVD.Successful, 0) = 1     WHERE ITSD.TenderServiceDel_ID = @PK    )    END     IF @TableName = 'SCM_RequisitionTenderLink'   SELECT @OutstandingAmount =     CASE WHEN EXISTS    (     SELECT 1     FROM SCM_RequisitionTenderLink RTL     INNER JOIN SCM_TenderBBBEEPreferencePoints BPP      ON BPP.TenderRequisitionLinkID = RTL.RequisitionTenderLink_ID     WHERE RTL.RequisitionTenderLink_ID = @PK       UNION       SELECT 1     FROM SCM_RequisitionTenderLink RTL     INNER JOIN SCM_Tender T      ON T.Tender_ID = RTL.TenderID     WHERE ISNULL(T.TenderCancel, 0) = 1      AND RTL.RequisitionTenderLink_ID = @PK    )    THEN      0    ELSE    (     SELECT TOP (1)       (RSD.EstimatedCost * RSD.Quantity) AS Amount     FROM SCM_RequisitionTenderLink RTL     INNER JOIN SCM_RequisitionServiceDetails RSD      ON RSD.RequisitionDetail_ID = RTL.RequisitionDetailID     WHERE RTL.RequisitionTenderLink_ID = @PK    )    END     IF @TableName = 'SCM_TenderBBBEEPreferencePoints'   SELECT @OutstandingAmount =     CASE WHEN EXISTS    (     SELECT 1     FROM SCM_TenderBBBEEPreferencePoints BPP     INNER JOIN SCM_RequisitionBillOfQuantity BOQ      ON BPP.BillOfQuantityID = BOQ.BillOfQuantityId     INNER JOIN SCM_ContractDetailItems CDI      ON CDI.BillOfQuantityID = BOQ.BillOfQuantityId     WHERE ISNULL(CDI.Enabled, 0) = 1      AND BPP.PreferencePoints_ID = @PK       UNION       SELECT 1     FROM SCM_TenderBBBEEPreferencePoints BPP     INNER JOIN SCM_Tender T      ON T.Tender_ID = BPP.TenderID     WHERE ISNULL(T.TenderCancel, 0) = 1      AND BPP.PreferencePoints_ID = @PK    )    THEN      0    ELSE    (     SELECT TOP (1)       (BPP.Cost) AS Amount     FROM SCM_TenderBBBEEPreferencePoints BPP     INNER JOIN SCM_TenderAwardedVendor TAV      ON TAV.PreferencePointsID = BPP.PreferencePoints_ID     WHERE BPP.PreferencePoints_ID = @PK    )    END     IF @TableName = 'SCM_ContractDetailItems'   SELECT @OutstandingAmount =     CASE WHEN EXISTS    (     SELECT 1     FROM SCM_ContractDetailItems CDI     WHERE ISNULL(CDI.Enabled, 0) = 0      AND CDI.ContractDetailItems_ID = @PK    )    THEN      0    ELSE    (     SELECT TOP (1)      (      CDI.Cost -      (       SELECT ISNULL(SUM(OTD.Amount), 0)       FROM SCM_OrderTypeDetail OTD       INNER JOIN SCM_ContractDetailItems CDI        ON CDI.ContractDetailItems_ID = OTD.ContractDetailItemsID       WHERE (ISNULL(OTD.IsVoid, 0) = 0 OR ISNULL(OTD.IsCompletedOnVoid, 0) = 1)        AND CDI.ContractDetailItems_ID = @PK       )      -      (       SELECT ISNULL(SUM(CSRD.TotalAmountExcl), 0)       FROM SCM_ContractServiceRequestDetails CSRD       INNER JOIN SCM_ContractServiceRequest CSR        ON CSR.ContractServiceRequest_ID = CSRD.ContractServiceRequestId       INNER JOIN SCM_ServiceInvoiceDetails SID        ON SID.ServiceInvoiceDetail_ID = CSRD.ServiceInvoiceDetail_ID       INNER JOIN SCM_ContractDetailItems CDI        ON CDI.ContractDetailItems_ID = SID.ContractDetailItemsID       WHERE ISNULL(CSR.IsVoid, 0) = 0        AND CDI.ContractDetailItems_ID = @PK       )     ) AS Amount     FROM SCM_ContractDetailItems CDI     WHERE CDI.ContractDetailItems_ID = @PK    )    END     IF @TableName = 'SCM_OrderTypeDetail'   SELECT @OutstandingAmount =     CASE WHEN EXISTS    (     SELECT 1     FROM SCM_OrderTypeDetail OTD     WHERE ISNULL(OTD.IsVoid, 0) = 1      AND OTD.OrderDetailID = @PK    )    THEN      0    ELSE    (     SELECT TOP (1)      (      OTD.Amount -      (       SELECT ISNULL(SUM(GRND.ReceivedUnitPrice * (GRND.GoodsReceived - ISNULL(GRND.QuantityVoided, 0))), 0)       FROM SCM_GRNDetails GRND       INNER JOIN SCM_OrderTypeDetail OTD        ON OTD.OrderDetailID = GRND.OrderDetailID       WHERE OTD.OrderDetailID = @PK       )     ) AS Amount     FROM SCM_OrderTypeDetail OTD     WHERE OTD.OrderDetailID = @PK    )    END     IF @TableName = 'SCM_GRNDetails'   SELECT @OutstandingAmount =     (     SELECT TOP (1)      (      GRND.ReceivedUnitPrice * (GRND.GoodsReceived - ISNULL(GRND.QuantityVoided, 0) -       (       SELECT SUM(ID.QuantityReceived)       FROM SCM_InvoiceDetail ID       INNER JOIN SCM_GRNDetails GRND        ON GRND.GRNDetail_ID = ID.GRRDetailID       WHERE ISNULL(ID.IsVoid, 0) = 0        AND GRND.GRNDetail_ID = @PK      ))     ) AS Amount     FROM SCM_GRNDetails GRND     WHERE GRND.GRNDetail_ID = @PK    )     IF @TableName = 'SCM_ContractServiceRequestDetails'   SELECT @OutstandingAmount =     CASE WHEN EXISTS    (     SELECT 1     FROM SCM_ContractServiceRequestDetails CSRD     INNER JOIN SCM_ContractServiceRequest CSR      ON CSR.ContractServiceRequest_ID = CSRD.ContractServiceRequestId     WHERE ISNULL(CSR.IsVoid, 0) = 1      AND CSRD.ContractServiceRequestDetails_ID = @PK    )    THEN      0    ELSE    (     SELECT TOP (1)      (      CSRD.TotalAmountExcl -      (       SELECT ISNULL(SUM(ID.Amount), 0)       FROM SCM_InvoiceDetail ID       INNER JOIN SCM_ContractServiceRequestDetails CSRD        ON CSRD.ContractServiceRequestDetails_ID = ID.ContractServiceRequestDetailsId       WHERE ISNULL(ID.IsVoid, 0) = 0        AND CSRD.ContractServiceRequestDetails_ID = @PK       )     ) AS Amount     FROM SCM_ContractServiceRequestDetails CSRD     WHERE CSRD.ContractServiceRequestDetails_ID = @PK    )    END     IF @TableName = 'SCM_InvoiceDetail'   SELECT @OutstandingAmount =     CASE WHEN EXISTS    (     SELECT 1     FROM SCM_InvoiceDetail ID     WHERE ISNULL(ID.IsVoid, 0) = 1      AND ID.InvoiceDetail_ID = @PK    )    THEN      0    ELSE    (     SELECT TOP (1)      (      ID.Amount -      (       SELECT ISNULL(SUM(PID.VoteAmount), 0)       FROM SCM_PaymentAllocation PA       INNER JOIN Led_PaymentInstructionDetails PID        ON PA.PaymentInstructionDetailID = PID.PaymentInstructionDetail_ID       INNER JOIN SCM_Payment P        ON P.Payment_ID = PA.PaymentID       INNER JOIN SCM_InvoiceDetail ID        ON ID.InvoiceDetail_ID = PA.InvoiceDetailID       WHERE ISNULL(P.IsVoid, 0) = 0        AND ID.InvoiceDetail_ID = @PK       )      -      (       SELECT SUM(IIF(ICDN.NoteType = 1, ICD.Amount, -ICD.Amount))       FROM SCM_InvoiceCreditDetail ICD       INNER JOIN SCM_InvoiceDetail ID        ON ID.InvoiceDetail_ID = ICD.InvoiceDetailID       INNER JOIN SCM_InvoiceCreditDebtNote ICDN        ON ICDN.ID = ICD.InvoiceCreditID       WHERE ID.InvoiceDetail_ID = @PK      )     ) AS Amount     FROM SCM_InvoiceDetail ID     WHERE ID.InvoiceDetail_ID = @PK    )    END     IF @TableName = 'SCM_SundryPaymentServiceDetails'   SELECT @OutstandingAmount =     CASE WHEN EXISTS    (     SELECT 1     FROM SCM_SundryPaymentServiceDetails SPSD     INNER JOIN SCM_SundryPayment SP      ON SP.SundryPayment_ID = SPSD.SundryPaymentID     WHERE ISNULL(SP.IsVoid, 0) = 1      AND SPSD.SundryPaymentDetail_ID = @PK    )    THEN      0    ELSE    (     SELECT TOP (1)      (      SPSD.Amount -      (       SELECT ISNULL(SUM(PID.VoteAmount), 0)       FROM SCM_PaymentAllocation PA       INNER JOIN Led_PaymentInstructionDetails PID        ON PA.PaymentInstructionDetailID = PID.PaymentInstructionDetail_ID       INNER JOIN SCM_Payment P        ON P.Payment_ID = PA.PaymentID       INNER JOIN SCM_SundryPaymentServiceDetails SPSD        ON SPSD.SundryPaymentDetail_ID = PA.SundryPaymentDetailID       WHERE ISNULL(P.IsVoid, 0) = 0        AND SPSD.SundryPaymentDetail_ID = @PK       )     ) AS Amount     FROM SCM_SundryPaymentServiceDetails SPSD     WHERE SPSD.SundryPaymentDetail_ID = @PK    )    END     IF @TableName = 'Led_PaymentInstructionDetails'   SELECT @OutstandingAmount =     CASE WHEN EXISTS    (     SELECT 1     FROM SCM_PaymentAllocation PA     INNER JOIN Led_PaymentInstructionDetails PID      ON PA.PaymentInstructionDetailID = PID.PaymentInstructionDetail_ID     INNER JOIN SCM_Payment P      ON P.Payment_ID = PA.PaymentID     WHERE ISNULL(P.IsVoid, 0) = 1      AND PID.PaymentInstructionDetail_ID = @PK    )    THEN      0    ELSE    (     SELECT TOP (1)       PID.VoteAmount AS Amount     FROM Led_PaymentInstructionDetails PID     WHERE PID.PaymentInstructionDetail_ID = @PK    )    END     IF @TableName = 'Inven_InventoryIssueLineItem'   SELECT @OutstandingAmount =     CASE WHEN EXISTS    (     SELECT 1     FROM Inven_InventoryIssueLineItem IIL     WHERE ISNULL(IIL.IssueToCapitalExpense, 0) = 1      AND IIL.InvIssueLineItem_ID = @PK    )    THEN      0    ELSE    (     SELECT TOP (1)       (IIL.Quantity * IIL.Price) AS Amount     FROM Inven_InventoryIssueLineItem IIL     WHERE IIL.InvIssueLineItem_ID = @PK    )    END     -- Return the result of the function   RETURN @OutstandingAmount    END

GO

-- ============================================
-- Function: Plan_GetBudgetTransactionTypeDesc
-- Type: SQL_SCALAR_FUNCTION
-- Schema: dbo
-- ============================================
-- Create date: 24 Jun 2020  -- Description: Format budget transaction type desc    CREATE FUNCTION [dbo].[Plan_GetBudgetTransactionTypeDesc]  (   @BudgetConsumptionProcessID int,   @BudgetTransactionTypeID int  )  RETURNS NVARCHAR(200)  AS  BEGIN   DECLARE @Result NVARCHAR(200);   SELECT TOP 1 @Result = BudgetTransDesc FROM Const_BudgetTransactionType_sys   WHERE BudgetTransactionType_ID = @BudgetTransactionTypeID      SELECT  @Result =        CASE         WHEN @BudgetConsumptionProcessID = 103       THEN 'Supervisor ' + @Result          ELSE @Result         END      RETURN @Result  END

GO

-- ============================================
-- Function: Plan_GetProjectDivisionByDivisionId_fxn
-- Type: SQL_SCALAR_FUNCTION
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Sahil Nagpal  -- Create date: 19/08/2016  -- Description: Gets Specific Division for a projectItem  -- SELECT dbo.Plan_GetProjectDivisionByDivisionId_fxn(26)  -- =============================================  CREATE FUNCTION [dbo].[Plan_GetProjectDivisionByDivisionId_fxn] ( @DivisionID INT )  RETURNS NVARCHAR(MAX)  AS      BEGIN          DECLARE @ObjStr VARCHAR(MAX);     --Recursive code found on net          WITH    DeptDivGroup ( DivisionParentID, Division_ID, DivisionDesc, DivisionCode, DepartmentID )                    AS (   -- Anchor member definition                         SELECT   e.DivisionParentID ,                                  e.Division_ID ,                                  e.DivisionDesc ,                                  e.DivisionCode ,                                  e.DepartmentID                         FROM     dbo.Const_Division AS e                         WHERE    DivisionParentID IS NULL                         UNION ALL   -- Recursive member definition                         SELECT   e.DivisionParentID ,                                  e.Division_ID ,                                  e.DivisionDesc ,                                  e.DivisionCode ,                                  e.DepartmentID                         FROM     dbo.Const_Division AS e                                  INNER JOIN DeptDivGroup AS d ON e.DivisionParentID = d.Division_ID                       )              SELECT DISTINCT                      @ObjStr = ( cd.DepartmentCode + '/' + DivisionCode + ' '                                  + DepartmentDesc + ' / ' + DivisionDesc )              FROM    DeptDivGroup rs                      INNER JOIN Plan_ProjectDivisions pd ON pd.DivisionID = rs.Division_ID                      INNER JOIN Const_Department cd ON rs.DepartmentID = cd.Department_ID              WHERE   pd.DivisionID = @DivisionID;       -- Return the result of the function          RETURN ISNULL(@ObjStr,'');           END;    

GO

-- ============================================
-- Function: Plan_ProjectDepartment_fxn
-- Type: SQL_SCALAR_FUNCTION
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  Jignesh Prajapati  -- Create date: 05/04/2016  -- Description: Gets list of Department for a project  -- Calls : SELECT dbo.Plan_ProjectDepartment_fxn(57,0)  -- =============================================  CREATE FUNCTION [dbo].[Plan_ProjectDepartment_fxn]   -- Add the parameters for the function here      (        @ProjectID INT ,        @ShowCode BIT      )  RETURNS NVARCHAR(MAX)  AS      BEGIN   -- Declare the return variable here          DECLARE @listStr VARCHAR(MAX);      -- Add the T-SQL statements to compute the return value here          SELECT  @listStr = COALESCE(@listStr + ',', '')                  + CONVERT(NVARCHAR(300), ISNULL(DepartmentCODE, ''))          FROM    ( SELECT DISTINCT                              ( CASE WHEN @ShowCode = 1                                     THEN CDep.DepartmentCode + ' : '                                          + CDep.DepartmentDesc                                     ELSE CDep.DepartmentDesc                                END ) AS DepartmentCODE                    FROM      dbo.Plan_ProjectDivisions PPD                              INNER JOIN dbo.Const_Division CD ON CD.Division_ID = PPD.DivisionID                              INNER JOIN dbo.Const_Department CDep ON CDep.Department_ID = CD.DepartmentID                    WHERE     PPD.ProjectID = @ProjectID                  ) AS PlanProjectDepartment;     -- Return the result of the function          RETURN ISNULL(@listStr,'');        END;    

GO

-- ============================================
-- Function: Plan_ProjectDivision_fxn
-- Type: SQL_SCALAR_FUNCTION
-- Schema: dbo
-- ============================================
  -- =============================================  -- Author:  Jignesh Prajapati  -- Create date: 05/04/2016  -- Description: Gets list of Division for a project  -- Calls : SELECT dbo.Plan_ProjectDivision_fxn(57,0)  -- =============================================  CREATE FUNCTION [dbo].[Plan_ProjectDivision_fxn]   -- Add the parameters for the function here      (        @ProjectID INT ,        @ShowCode BIT      )  RETURNS NVARCHAR(MAX)  AS      BEGIN   -- Declare the return variable here          DECLARE @listStr VARCHAR(MAX);      -- Add the T-SQL statements to compute the return value here          SELECT  @listStr = COALESCE(@listStr + ',', '')                  + CONVERT(NVARCHAR(300), ISNULL(DivisionCODE, ''))          FROM    ( SELECT DISTINCT                              ( CASE WHEN @ShowCode = 1                                     THEN CD.DivisionCode + ' : '                                          + CD.DivisionDesc                                     ELSE CD.DivisionDesc                                END ) AS DivisionCODE                    FROM      dbo.Plan_ProjectDivisions PPD                              INNER JOIN dbo.Const_Division CD ON CD.Division_ID = PPD.DivisionID                    WHERE     PPD.ProjectID = @ProjectID                  ) AS PlanProjectDivision;     -- Return the result of the function          RETURN ISNULL(@listStr,'');        END;    

GO

-- ============================================
-- Function: PMS_DepartmentIndicatorPerYear_fxn
-- Type: SQL_TABLE_VALUED_FUNCTION
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Chris Moodley  -- Create date: 08 November 2020  -- Description: Return KPIs linked to departments per financial year per scorecard type  -- =============================================  CREATE FUNCTION [dbo].[PMS_DepartmentIndicatorPerYear_fxn]  (    -- Add the parameters for the function here   @FinYear NVARCHAR(9),   @ScorecardTypeID INT  )  RETURNS     @tblTotals TABLE     (       DepartmentID INT,      DepartmentDesc VARCHAR(MAX),      KpiID INT   )  AS  BEGIN    -- Add the SELECT statement with parameter references here   INSERT INTO @tblTotals   SELECT DISTINCT payPos.DepartmentID, dept.DepartmentDesc, ind.Kpi_ID   FROM     PMS_Indicator ind    INNER JOIN IDP_Item idp ON ind.ItemID = idp.Item_ID    INNER JOIN PMS_IndicatorScorecardType scoreCard ON scoreCard.KpiID = ind.Kpi_ID     INNER JOIN Payroll_Employee emp ON ind.ResponsiblePost = emp.Employee_ID    INNER JOIN Payroll_Position payPos ON emp.PositionID = payPos.Position_ID    INNER JOIN Const_Department dept ON payPos.DepartmentID = dept.Department_ID   WHERE    FinancialYear = @FinYear AND ScorecardTypeID = CASE WHEN @ScorecardTypeID = 0 THEN scoreCard.ScorecardTypeID ELSE @ScorecardTypeID END AND scoreCard.ScorecardTypeApplicable = 1     RETURN    END

GO

-- ============================================
-- Function: PMS_GetOrganisationalPerNKpa_fxn
-- Type: SQL_TABLE_VALUED_FUNCTION
-- Schema: dbo
-- ============================================
-- =============================================================================    -- Author:  RC  -- Create date: 10/11/2015    -- Description: Returns table of KPIs and measurable inidicators and measurable indicator actuals and measure types.  -- Calls: select * from PMS_GetOrganisationalPerNKpa_fxn(2,1,'2015/2016')  -- Used in:PMS_GetKpiPerKpa_sp  --  :   -- =============================================================================    CREATE FUNCTION [dbo].[PMS_GetOrganisationalPerNKpa_fxn]     (     @ScoreCardType INT = 2,   @Quarter int=1,   @FinYear VARCHAR(9) = '2015/2016'  )    RETURNS     @tblKPIPerformance TABLE     (      NationalKPADetail_ID int,    NationalKPADesc nvarchar(200),    PerformancePerc decimal(16,2)  )    AS    BEGIN        DECLARE @NationalKPAHeaderID int     SELECT @NationalKPAHeaderID=NationalKPAHeader_ID    FROM [dbo].[Const_IDPNationalKPA_Header]    WHERE FinancialYear=@FinYear     INSERT INTO @tblKPIPerformance      SELECT NKPADet.NationalKPADetail_ID,NKPADet.NationalKPADesc,ISNULL(NKPAD.PerformancePerc,0) AS PerformancePerc   FROM     Const_IDPNationalKPA_Detail NKPADet    INNER JOIN IDP_Item IDP ON NKPADet.NationalKPADetail_ID=IDP.NationalKPADetailID    LEFT JOIN      (      SELECT NKP.NKPAItemID,NKP.NKPADesc,Perfomance/NumOfTargets as PerformancePerc      FROM        (        SELECT NKPA.NKPAItemID,NKPA.NKPADesc, Sum(Perform.KPIPerformance) As Perfomance, Targets.NumOfTargets         FROM PMS_NKPAIndicatorPerYear_fxn(@FinYear, @ScoreCardType) NKPA          INNER JOIN PMS_Indicator Indi ON NKPA.KPIItemID=Indi.ItemID          INNER JOIN IDP_Item IDP ON Indi.ItemID=IDP.Item_ID          INNER JOIN PMS_IndicatorPerformancePerQuarter_fxn(@Quarter) Perform ON Indi.Kpi_ID=Perform.KpiID          INNER JOIN PMS_IndicatorScorecardType Score ON Indi.Kpi_ID=Score.KpiID          INNER JOIN           (           SELECT NKPAItemId, NKPADesc, Count(*) AS NumOfTargets            FROM PMS_NKPAIndicatorPerYear_fxn(@FinYear, @ScoreCardType) NKPA             INNER JOIN PMS_Indicator Indi on  NKPA.KPIItemID=Indi.ItemID           GROUP BY NKPAItemId, NKPADesc          ) Targets ON NKPA.NKPAItemId=Targets.NKPAItemId        WHERE Score.ScorecardTypeID=@ScoreCardType        GROUP BY NKPA.NKPAItemID,NKPA.NKPADesc, Targets.NumOfTargets       ) NKP     ) NKPAD ON  NKPAD.NKPAItemId=IDP.Item_ID   WHERE NKPADet.NationalKPAHeaderID=@NationalKPAHeaderID     RETURN       END

GO

-- ============================================
-- Function: PMS_IndicatorPerformancePerQuarter_fxn
-- Type: SQL_TABLE_VALUED_FUNCTION
-- Schema: dbo
-- ============================================
       -- =============================================================================    -- Author:  RC  -- Create date: 10/11/2015    -- Description: Returns table of KPIs and measurable inidicators and measurable indicator actuals and measure types.  -- Calls: select * from PMS_IndicatorPerformancePerQuarter_fxn(1)  -- Used in:[PMS_GetOrganisationalPerNKpa_fxn]  -- 25/11/2015 RC : Error on calculation of task performance fixed.   -- =============================================================================    CREATE FUNCTION [dbo].[PMS_IndicatorPerformancePerQuarter_fxn]     (     @Quarter int  )    RETURNS     @tblKPIPerformance TABLE     (      KpiID int,     KPIPerformance decimal(16,2)  )    AS    BEGIN       DECLARE @tempTask TABLE   (           KpiID int,       TaskProgress decimal(16,2),     NumOfTasks int   )    -- Number of Tasks - cannot include items on hold  INSERT INTO @tempTask  SELECT KpiID, SUM(TaskProgress) AS  TaskProgress,COUNT(*) AS NumOfTasks  FROM  (  SELECT IndiTask.KpiID, (SUM(ISNULL(IndiTaskActual.ProgressPercent,0))/COUNT(*)) AS TaskProgress,KpiTask_ID     FROM PMS_IndicatorTask IndiTask  INNER JOIN PMS_IndicatorTaskActual IndiTaskActual ON IndiTask.KpiTask_ID=IndiTaskActual.KpiTaskID    AND IndiTask.QuarterDue=IndiTaskActual.[Quarter]    AND IndiTask.QuarterDue=@Quarter   AND IndiTask.KpiID NOT IN    (    SELECT KpiID FROM [dbo].[PMS_IndicatorActual]    WHERE OnHold=1    UNION    SELECT KpiID FROM PMS_IndicatorMonthActivity IndiMonAct    INNER JOIN PMS_IndicatorMonthActivityActual IndiMonActActually ON IndiMonAct.KpiMonthActivity_ID=IndiMonActActually.KpiMonthActivity_ID    WHERE IndiMonActActually.OnHold=1   )  GROUP BY IndiTask.KpiID,IndiTask.KpiTask_ID  )AS Tasks  GROUP BY KpiID    DECLARE @tempMeasure TABLE   (           KpiID int,       TargetMeasure NVARCHAR(200),     ActualMeasure NVARCHAR(200),     DataTypeID int,      TargetMeasureVal decimal(16,2),     ActualMeasureVal decimal(16,2),     TargetMeasureDate datetime,     ActualMeasureDate datetime,     PercentAchieved decimal(16,2)   )    INSERT INTO @tempMeasure     SELECT     IndiMeasure.KpiID    ,CASE WHEN @Quarter=1 THEN IndiMeasure.Q1TargetMeasure     WHEN @Quarter=2 THEN IndiMeasure.Q2TargetMeasure     WHEN @Quarter=3 THEN IndiMeasure.Q3TargetMeasure     ELSE IndiMeasure.Q4TargetMeasure    END AS TargetMeasure    ,IndiMeasureActual.ActualMeasure    ,IndiUnitMeasure.DataTypeID    ,null,null,null,null,null  FROM [dbo].[PMS_IndicatorMeasureable] IndiMeasure  INNER JOIN PMS_IndicatorMeasureableActual IndiMeasureActual ON IndiMeasure.KpiMeasureable_ID=IndiMeasureActual.KpiMeasureableID  INNER JOIN Const_PMSIndicatorUnitMeasure IndiUnitMeasure ON IndiMeasure.UnitMeasureID=IndiUnitMeasure.UnitMeasure_ID  WHERE IndiMeasureActual.[Quarter] =@Quarter  AND IndiMeasure.KpiID NOT IN    (    SELECT KpiID FROM [dbo].[PMS_IndicatorActual]    WHERE OnHold=1    UNION    SELECT KpiID FROM PMS_IndicatorMonthActivity IndiMonAct    INNER JOIN PMS_IndicatorMonthActivityActual IndiMonActActually ON IndiMonAct.KpiMonthActivity_ID=IndiMonActActually.KpiMonthActivity_ID    WHERE IndiMonActActually.OnHold=1   )    UPDATE @tempMeasure  set TargetMeasureVal= CASE WHEN Measure. DataTypeID=1 Then CAST(Replace(COALESCE(NULLIF(TargetMeasure,''), '0'),',','') AS DECIMAL(16, 2))    WHEN Measure. DataTypeID=2 Then CAST(Replace(COALESCE(NULLIF(TargetMeasure,''), '0'),',','') AS DECIMAL(16, 2))    WHEN Measure. DataTypeID=3 Then CAST(Replace(COALESCE(NULLIF(TargetMeasure,''), '0'),',','') AS DECIMAL(16, 2))    WHEN Measure. DataTypeID=4 Then CAST(Replace(COALESCE(NULLIF(TargetMeasure,''), '0'),',','') AS DECIMAL(16, 2))   END   ,ActualMeasureVal= CASE WHEN Measure. DataTypeID=1 Then CAST(Replace(COALESCE(NULLIF(ActualMeasure,''), '0'),',','') AS DECIMAL(16, 2))    WHEN Measure. DataTypeID=2 Then CAST(Replace(COALESCE(NULLIF(ActualMeasure,''), '0'),',','') AS DECIMAL(16, 2))    WHEN Measure. DataTypeID=3 Then CAST(Replace(COALESCE(NULLIF(ActualMeasure,''), '0'),',','') AS DECIMAL(16, 2))    WHEN Measure. DataTypeID=4 Then CAST(Replace(COALESCE(NULLIF(ActualMeasure,''), '0'),',','') AS DECIMAL(16, 2))   END   ,TargetMeasureDate= CASE  WHEN Measure. DataTypeID=5 Then convert(datetime, TargetMeasure,103)    END   , ActualMeasureDate=CASE  WHEN Measure. DataTypeID=5 Then convert(datetime, ActualMeasure,103)    END   FROM @tempMeasure Measure    UPDATE @tempMeasure  SET PercentAchieved=    CASE WHEN DataTypeID<5 THEN -- numeric targets    CASE WHEN  ActualMeasureVal=TargetMeasureVal THEN 100      WHEN  0<ActualMeasureVal AND ActualMeasureVal<TargetMeasureVal THEN 33      WHEN ActualMeasureVal=0 THEN 0      WHEN ActualMeasureVal>TargetMeasureVal THEN 133    END   WHEN DataTypeID=5 THEN -- date targets    CASE WHEN  ActualMeasureDate=TargetMeasureDate THEN 100      WHEN  ActualMeasureDate>TargetMeasureDate THEN 33      WHEN ActualMeasureDate is NULL  THEN 0      WHEN ActualMeasureDate<TargetMeasureDate THEN 133    END   END  FROM @tempMeasure    INSERT INTO @tblKPIPerformance      SELECT Measure.KpiID, (isNULL(Measure.PercentAchieved,0) +ISNULL(Task.TaskProgress,0))/(1+ISNULL(Task.NumOfTasks,0)) AS KPIPerformance   FROM @tempMeasure Measure   LEFT JOIN @tempTask Task ON Measure.KpiID=Task.KpiID   UNION   SELECT Task.KpiID,Task.TaskProgress/Task.NumOfTasks  AS KPIPerformance   FROM @tempTask Task   WHERE Task.KpiID NOT IN (Select KpiID from @tempMeasure)    RETURN     END    

GO

-- ============================================
-- Function: PMS_KPIAchievedPerDepartmentPerQuarter_fxn
-- Type: SQL_TABLE_VALUED_FUNCTION
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Chris Moodley  -- Create date: 06 November 2020  -- Description: Return percentage KPIs achieved per financial year, per quarter, per scorecard type, per department  -- =============================================  CREATE FUNCTION [dbo].[PMS_KPIAchievedPerDepartmentPerQuarter_fxn]  (   -- Add the parameters for the function here   @FinYear VARCHAR(10),   @ScorecardTypeID INT,   @Quarter INT  )  RETURNS   @KPIAchievedPerDepartment TABLE   (   -- Add the column definitions for the TABLE variable here   DepartmentID INT,   DepartmentDesc NVARCHAR(400),   Total INT,   TotalAchieved INT,   TotalPartiallyAchieved INT,   TotalNotAchieved INT,   TotalOnhold INT,   TotalNotApplicable INT,   TotalOverAchieved INT,   UnableAssess INT,   PercentageKPIAchieved DECIMAL(16, 2)  )  AS  BEGIN   -- Fill the table variable with the rows for your result set   INSERT INTO @KPIAchievedPerDepartment   SELECT DepartmentID, DepartmentDesc, COUNT(KpiID), 0, 0, 0, 0, 0, 0, 0, 0   FROM PMS_DepartmentIndicatorPerYear_fxn(@FinYear, @ScorecardTypeID)   GROUP BY DepartmentID, DepartmentDesc     -- Achieved   UPDATE @KPIAchievedPerDepartment   SET TotalAchieved = Achieved   FROM @KPIAchievedPerDepartment kpiDept    INNER JOIN    (     SELECT kpiDept.DepartmentID, kpiDept.DepartmentDesc, COUNT(*) AS Achieved     FROM       PMS_DepartmentIndicatorPerYear_fxn(@FinYear, @ScorecardTypeID) kpiDept      INNER JOIN PMS_Indicator Indi ON kpiDept.KpiID = Indi.Kpi_ID      INNER JOIN Payroll_Employee emp ON Indi.ResponsiblePost = emp.Employee_ID      INNER JOIN Payroll_Position payPos ON emp.PositionID = payPos.Position_ID      INNER JOIN Const_Department dept ON payPos.DepartmentID = dept.Department_ID      INNER JOIN PMS_IndicatorActual indActual ON Indi.Kpi_ID = indActual.KpiID      LEFT JOIN PMS_IndicatorMeasureable indMeasureable ON Indi.Kpi_ID = indMeasureable.KpiID      LEFT JOIN PMS_IndicatorMeasureableActual indMeasureableActual ON indMeasureable.KpiMeasureable_ID = indMeasureableActual.KpiMeasureableID AND indMeasureableActual.[Quarter] = @Quarter      INNER JOIN Const_PMSIndicatorProgress cpp ON COALESCE(indActual.KpiProgressIDAnalysis, indActual.KpiProgressID) = cpp.Progress_ID     WHERE ISNULL(ProgressTargetMet, 0) = 1 AND indActual.[Quarter] = @Quarter AND ISNULL(OnHold, 0) <> 1 AND ISNULL(isKpiApplicable, 1) <> 0     GROUP BY kpiDept.DepartmentID, kpiDept.DepartmentDesc    ) Achieved ON kpiDept.DepartmentID = Achieved.DepartmentID     --partly achieved   UPDATE @KPIAchievedPerDepartment   SET TotalPartiallyAchieved = PartlyAchieved   FROM     @KPIAchievedPerDepartment kpiDept    INNER JOIN    (     SELECT kpiDept.DepartmentID, kpiDept.DepartmentDesc, COUNT(*) AS PartlyAchieved     FROM       PMS_DepartmentIndicatorPerYear_fxn(@FinYear, @ScorecardTypeID) kpiDept      INNER JOIN PMS_Indicator Indi ON kpiDept.KpiID = Indi.Kpi_ID      INNER JOIN Payroll_Employee emp ON Indi.ResponsiblePost = emp.Employee_ID      INNER JOIN Payroll_Position payPos ON emp.PositionID = payPos.Position_ID      INNER JOIN Const_Department dept ON payPos.DepartmentID = dept.Department_ID      INNER JOIN PMS_IndicatorActual indActual ON Indi.Kpi_ID = indActual.KpiID      LEFT JOIN PMS_IndicatorMeasureable indMeasureable ON Indi.Kpi_ID = indMeasureable.KpiID      LEFT JOIN PMS_IndicatorMeasureableActual indMeasureableActual ON indMeasureable.KpiMeasureable_ID = indMeasureableActual.KpiMeasureableID AND indMeasureableActual.[Quarter] = @Quarter      INNER JOIN Const_PMSIndicatorProgress cpp ON COALESCE(indActual.KpiProgressIDAnalysis, indActual.KpiProgressID) = cpp.Progress_ID     WHERE Progress_ID = 3 AND indActual.[Quarter] = @Quarter AND indActual.[Quarter] = @Quarter AND ISNULL(OnHold, 0) <> 1 AND ISNULL(isKpiApplicable, 1) <> 0     GROUP BY kpiDept.DepartmentID, kpiDept.DepartmentDesc    ) Partly ON kpiDept.DepartmentID = Partly.DepartmentID     --Not achieved   UPDATE @KPIAchievedPerDepartment   SET TotalNotAchieved = NotAchieved   FROM     @KPIAchievedPerDepartment kpiDept    INNER JOIN    (     SELECT kpiDept.DepartmentID, kpiDept.DepartmentDesc, COUNT(*) AS NotAchieved     FROM       PMS_DepartmentIndicatorPerYear_fxn(@FinYear, @ScorecardTypeID) kpiDept      INNER JOIN PMS_Indicator Indi ON kpiDept.KpiID = Indi.Kpi_ID      INNER JOIN Payroll_Employee emp ON Indi.ResponsiblePost = emp.Employee_ID      INNER JOIN Payroll_Position payPos ON emp.PositionID = payPos.Position_ID      INNER JOIN Const_Department dept ON payPos.DepartmentID = dept.Department_ID      INNER JOIN PMS_IndicatorActual indActual ON Indi.Kpi_ID = indActual.KpiID      LEFT JOIN PMS_IndicatorMeasureable indMeasureable ON Indi.Kpi_ID = indMeasureable.KpiID      LEFT JOIN PMS_IndicatorMeasureableActual indMeasureableActual ON indMeasureable.KpiMeasureable_ID = indMeasureableActual.KpiMeasureableID AND indMeasureableActual.[Quarter] = @Quarter      INNER JOIN Const_PMSIndicatorProgress cpp ON COALESCE(indActual.KpiProgressIDAnalysis, indActual.KpiProgressID) = cpp.Progress_ID     WHERE Progress_ID = 4 AND indActual.[Quarter] = @Quarter AND indActual.[Quarter] = @Quarter AND ISNULL(OnHold, 0) <> 1 AND ISNULL(isKpiApplicable, 1) <> 0     GROUP BY kpiDept.DepartmentID, kpiDept.DepartmentDesc    ) NotAchieved ON kpiDept.DepartmentID = NotAchieved.DepartmentID     -- Over Achieved   UPDATE @KPIAchievedPerDepartment   SET TotalOverAchieved = OverAchieved   FROM     @KPIAchievedPerDepartment kpiDept    INNER JOIN    (     SELECT kpiDept.DepartmentID, kpiDept.DepartmentDesc, COUNT(*) AS OverAchieved     FROM       PMS_DepartmentIndicatorPerYear_fxn(@FinYear, @ScorecardTypeID) kpiDept      INNER JOIN PMS_Indicator Indi ON kpiDept.KpiID = Indi.Kpi_ID      INNER JOIN Payroll_Employee emp ON Indi.ResponsiblePost = emp.Employee_ID      INNER JOIN Payroll_Position payPos ON emp.PositionID = payPos.Position_ID      INNER JOIN Const_Department dept ON payPos.DepartmentID = dept.Department_ID      INNER JOIN PMS_IndicatorActual indActual ON Indi.Kpi_ID = indActual.KpiID      LEFT JOIN PMS_IndicatorMeasureable indMeasureable ON Indi.Kpi_ID = indMeasureable.KpiID      LEFT JOIN PMS_IndicatorMeasureableActual indMeasureableActual ON indMeasureable.KpiMeasureable_ID = indMeasureableActual.KpiMeasureableID AND indMeasureableActual.[Quarter] = @Quarter      INNER JOIN Const_PMSIndicatorProgress cpp ON COALESCE(indActual.KpiProgressIDAnalysis, indActual.KpiProgressID) = cpp.Progress_ID     WHERE ISNULL(ProgressTargetExceeded, 0) = 1 AND indActual.[Quarter] = @Quarter AND indActual.[Quarter] = @Quarter AND ISNULL(OnHold, 0) <> 1 AND ISNULL(isKpiApplicable, 1) <> 0     GROUP BY kpiDept.DepartmentID, kpiDept.DepartmentDesc    ) OverAchieved ON kpiDept.DepartmentID = OverAchieved.DepartmentID     -- Number of Targets ON Hold   UPDATE @KPIAchievedPerDepartment   SET TotalOnHold = NumOnHold   FROM     @KPIAchievedPerDepartment kpiDept    INNER JOIN    (     SELECT kpiDept.DepartmentID, kpiDept.DepartmentDesc, COUNT(*) AS NumOnHold      FROM       PMS_DepartmentIndicatorPerYear_fxn(@FinYear, @ScorecardTypeID) kpiDept      INNER JOIN PMS_Indicator Indi ON kpiDept.KpiID = Indi.Kpi_ID      INNER JOIN Payroll_Employee emp ON Indi.ResponsiblePost = emp.Employee_ID      INNER JOIN Payroll_Position payPos ON emp.PositionID = payPos.Position_ID      INNER JOIN Const_Department dept ON payPos.DepartmentID = dept.Department_ID      INNER JOIN PMS_IndicatorActual IndicatorActual ON Indi.Kpi_ID = IndicatorActual.KpiID      LEFT JOIN PMS_IndicatorMeasureable indMeasureable ON Indi.Kpi_ID = indMeasureable.KpiID      LEFT JOIN PMS_IndicatorMeasureableActual indMeasureableActual ON indMeasureable.KpiMeasureable_ID = indMeasureableActual.KpiMeasureableID AND indMeasureableActual.[Quarter] = @Quarter     WHERE IndicatorActual.OnHold = 1 AND IndicatorActual.[Quarter] = @Quarter AND IndicatorActual.[Quarter] = @Quarter AND ISNULL(isKpiApplicable, 1) <> 0     GROUP BY kpiDept.DepartmentID, kpiDept.DepartmentDesc    ) OnHold ON kpiDept.DepartmentID = OnHold.DepartmentID     -- Number of Targets Not Applicable   UPDATE @KPIAchievedPerDepartment   SET TotalNotApplicable = NumNotApplicable   FROM     @KPIAchievedPerDepartment kpiDept    INNER JOIN    (     SELECT kpiDept.DepartmentID, kpiDept.DepartmentDesc, COUNT(*) AS NumNotApplicable       FROM       PMS_DepartmentIndicatorPerYear_fxn(@FinYear, @ScorecardTypeID) kpiDept      INNER JOIN PMS_Indicator Indi ON kpiDept.KpiID = Indi.Kpi_ID      INNER JOIN Payroll_Employee emp ON Indi.ResponsiblePost = emp.Employee_ID      INNER JOIN Payroll_Position payPos ON emp.PositionID = payPos.Position_ID      INNER JOIN Const_Department dept ON payPos.DepartmentID = dept.Department_ID      INNER JOIN PMS_IndicatorMeasureable indMeasureable ON Indi.Kpi_ID = indMeasureable.KpiID      INNER JOIN PMS_IndicatorMeasureableActual indMeasureableActual ON indMeasureableActual.KpiMeasureableID = indMeasureable.KpiMeasureable_ID     WHERE indMeasureableActual.[Quarter] = @Quarter AND ISNULL(isKpiApplicable, 1) = 0     GROUP BY kpiDept.DepartmentID, kpiDept.DepartmentDesc    ) NA ON kpiDept.DepartmentID =  NA.DepartmentID     UPDATE @KPIAchievedPerDepartment   SET UnableAssess = Total - (ISNULL(TotalAchieved,0) + ISNULL(TotalPartiallyAchieved,0) + ISNULL(TotalNotAchieved,0) + ISNULL(TotalOverAchieved,0) + ISNULL(TotalOnHold,0) + ISNULL(TotalNotApplicable, 0))     UPDATE @KPIAchievedPerDepartment   SET PercentageKPIAchieved = ((TotalAchieved + TotalOverAchieved) * 100) / (CASE WHEN (Total - TotalOnHold - TotalNotApplicable) = 0 THEN 1 ELSE (Total - TotalOnHold - TotalNotApplicable) END)     RETURN   END

GO

-- ============================================
-- Function: PMS_KPIAchievedPerNKPAPerQuarter_fxn
-- Type: SQL_TABLE_VALUED_FUNCTION
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Chris Moodley  -- Create date: 06 November 2020  -- Description: Return percentage KPIs achieved per financial year, per quarter, per scorecard type  -- =============================================  CREATE FUNCTION [dbo].[PMS_KPIAchievedPerNKPAPerQuarter_fxn]  (   -- Add the parameters for the function here   @FinYear VARCHAR(10),   @ScorecardTypeID INT,   @Quarter INT,   @NationalKPAHeaderID INT  )  RETURNS   @KPIAchievedPerNKPA TABLE   (   -- Add the column definitions for the TABLE variable here   NationalKPADetailID INT,   NKPADesc NVARCHAR(400),   Total INT,   TotalAchieved INT,   TotalPartiallyAchieved INT,   TotalNotAchieved INT,   TotalOnhold INT,   TotalNotApplicable INT,   TotalOverAchieved INT,   UnableAssess INT,   PercentageKPIAchieved DECIMAL(16, 2)  )  AS  BEGIN   -- Fill the table variable with the rows for your result set   INSERT INTO @KPIAchievedPerNKPA   SELECT  NKPADet.NationalKPADetail_ID,NKPADet.NationalKPADesc, ISNULL(NumOfTargets, 0), 0, 0, 0, 0, 0, 0, 0, 0   FROM     Const_IDPNationalKPA_Detail NKPADet    INNER JOIN IDP_Item IDP ON NKPADet.NationalKPADetail_ID = IDP.NationalKPADetailID    LEFT JOIN    (-- Number of Targets set per NKPA     SELECT NKPAItemId, NKPADesc, Count(*) AS NumOfTargets from PMS_NKPAIndicatorPerYear_fxn(@FinYear, @ScorecardTypeID) NKPA     INNER JOIN PMS_Indicator Indi on  NKPA.KPIItemID=Indi.ItemID     GROUP BY NKPAItemId, NKPADesc    ) NKPANumOfTarget ON IDP.Item_ID = NKPANumOfTarget.NKPAItemId    WHERE NKPADet.NationalKPAHeaderID = @NationalKPAHeaderID    ORDER BY NationalKPANumber     -- achieved   UPDATE @KPIAchievedPerNKPA   SET TotalAchieved = Achieved   FROM @KPIAchievedPerNKPA NKPADet    INNER JOIN IDP_Item IDP ON NKPADet.NationalKPADetailID = IDP.NationalKPADetailID    INNER JOIN    (     SELECT NKPAItemId, NKPADesc, Count(*) AS Achieved     FROM       PMS_NKPAIndicatorPerYear_fxn(@FinYear, @ScorecardTypeID) NKPA      INNER JOIN PMS_Indicator Indi on  NKPA.KPIItemID=Indi.ItemID      INNER JOIN PMS_IndicatorActual indActual ON Indi.Kpi_ID = indActual.KpiID      LEFT JOIN PMS_IndicatorMeasureable indMeasureable ON Indi.Kpi_ID = indMeasureable.KpiID      LEFT JOIN PMS_IndicatorMeasureableActual indMeasureableActual ON indMeasureable.KpiMeasureable_ID = indMeasureableActual.KpiMeasureableID AND indMeasureableActual.[Quarter] = @Quarter      INNER JOIN Const_PMSIndicatorProgress cpp ON COALESCE(indActual.KpiProgressIDAnalysis, indActual.KpiProgressID) = cpp.Progress_ID     WHERE ISNULL(ProgressTargetMet, 0) = 1 AND indActual.[Quarter] = @Quarter AND ISNULL(OnHold, 0) <> 1 AND ISNULL(isKpiApplicable, 1) <> 0     GROUP BY NKPAItemId, NKPADesc    ) Achieved ON IDP.Item_ID = Achieved.NKPAItemId     --partly achieved   UPDATE @KPIAchievedPerNKPA   SET TotalPartiallyAchieved = PartlyAchieved   FROM @KPIAchievedPerNKPA NKPADet   INNER JOIN IDP_Item IDP ON NKPADet.NationalKPADetailID = IDP.NationalKPADetailID   INNER JOIN   (    SELECT NKPAItemId, NKPADesc, Count(*) AS PartlyAchieved     FROM      PMS_NKPAIndicatorPerYear_fxn(@FinYear, @ScorecardTypeID) NKPA     INNER JOIN PMS_Indicator Indi on  NKPA.KPIItemID = Indi.ItemID     INNER JOIN PMS_IndicatorActual indActual ON Indi.Kpi_ID = indActual.KpiID     LEFT JOIN PMS_IndicatorMeasureable indMeasureable ON Indi.Kpi_ID = indMeasureable.KpiID     LEFT JOIN PMS_IndicatorMeasureableActual indMeasureableActual ON indMeasureable.KpiMeasureable_ID = indMeasureableActual.KpiMeasureableID AND indMeasureableActual.[Quarter] = @Quarter     INNER JOIN Const_PMSIndicatorProgress cpp ON COALESCE(indActual.KpiProgressIDAnalysis, indActual.KpiProgressID) = cpp.Progress_ID    WHERE Progress_ID = 3 AND indActual.[Quarter] = @Quarter AND indActual.[Quarter] = @Quarter AND ISNULL(OnHold, 0) <> 1 AND ISNULL(isKpiApplicable, 1) <> 0    GROUP BY NKPAItemId, NKPADesc   ) Partly ON IDP.Item_ID = Partly.NKPAItemId     --Not achieved   UPDATE @KPIAchievedPerNKPA   SET TotalNotAchieved = NotAchieved   FROM     @KPIAchievedPerNKPA NKPADet    INNER JOIN IDP_Item IDP ON NKPADet.NationalKPADetailID = IDP.NationalKPADetailID    INNER JOIN    (     SELECT NKPAItemId, NKPADesc, Count(*) AS NotAchieved     FROM       PMS_NKPAIndicatorPerYear_fxn(@FinYear, @ScorecardTypeID) NKPA      INNER JOIN PMS_Indicator Indi on  NKPA.KPIItemID=Indi.ItemID      INNER JOIN PMS_IndicatorActual indActual ON Indi.Kpi_ID = indActual.KpiID      LEFT JOIN PMS_IndicatorMeasureable indMeasureable ON Indi.Kpi_ID = indMeasureable.KpiID      LEFT JOIN PMS_IndicatorMeasureableActual indMeasureableActual ON indMeasureable.KpiMeasureable_ID = indMeasureableActual.KpiMeasureableID AND indMeasureableActual.[Quarter] = @Quarter      INNER JOIN Const_PMSIndicatorProgress cpp ON COALESCE(indActual.KpiProgressIDAnalysis, indActual.KpiProgressID) = cpp.Progress_ID     WHERE Progress_ID = 4 AND indActual.[Quarter] = @Quarter AND indActual.[Quarter] = @Quarter AND ISNULL(OnHold, 0) <> 1 AND ISNULL(isKpiApplicable, 1) <> 0     GROUP BY NKPAItemId, NKPADesc    ) NotAchieved ON IDP.Item_ID = NotAchieved.NKPAItemId     -- Over Achieved   UPDATE @KPIAchievedPerNKPA   SET TotalOverAchieved = OverAchieved   FROM     @KPIAchievedPerNKPA NKPADet    INNER JOIN IDP_Item IDP ON NKPADet.NationalKPADetailID = IDP.NationalKPADetailID    INNER JOIN    (     SELECT NKPAItemId, NKPADesc, Count(*) AS OverAchieved     FROM       PMS_NKPAIndicatorPerYear_fxn(@FinYear, @ScorecardTypeID) NKPA      INNER JOIN PMS_Indicator Indi on  NKPA.KPIItemID=Indi.ItemID      INNER JOIN PMS_IndicatorActual indActual ON Indi.Kpi_ID = indActual.KpiID      LEFT JOIN PMS_IndicatorMeasureable indMeasureable ON Indi.Kpi_ID = indMeasureable.KpiID      LEFT JOIN PMS_IndicatorMeasureableActual indMeasureableActual ON indMeasureable.KpiMeasureable_ID = indMeasureableActual.KpiMeasureableID AND indMeasureableActual.[Quarter] = @Quarter      INNER JOIN Const_PMSIndicatorProgress cpp ON COALESCE(indActual.KpiProgressIDAnalysis, indActual.KpiProgressID) = cpp.Progress_ID     WHERE ISNULL(ProgressTargetExceeded, 0) = 1 AND indActual.[Quarter] = @Quarter AND indActual.[Quarter] = @Quarter AND ISNULL(OnHold, 0) <> 1 AND ISNULL(isKpiApplicable, 1) <> 0     GROUP BY NKPAItemId, NKPADesc    ) OverAchieved ON IDP.Item_ID = OverAchieved.NKPAItemId     -- Number of Targets ON Hold   UPDATE @KPIAchievedPerNKPA   SET TotalOnHold = NumOnHold   FROM     @KPIAchievedPerNKPA NKPADet    INNER JOIN IDP_Item IDP ON NKPADet.NationalKPADetailID = IDP.NationalKPADetailID    INNER JOIN    (     SELECT NKPAItemId, NKPADesc, Count(*) AS NumOnHold       FROM       (       SELECT DISTINCT NKPAItemId, NKPADesc, Indi.ItemID       FROM PMS_NKPAIndicatorPerYear_fxn(@FinYear, @ScorecardTypeID      ) NKPA      INNER JOIN PMS_Indicator Indi ON  NKPA.KPIItemID=Indi.ItemID      INNER JOIN PMS_IndicatorActual IndicatorActual ON Indi.Kpi_ID = IndicatorActual.KpiID      LEFT JOIN PMS_IndicatorMeasureable indMeasureable ON Indi.Kpi_ID = indMeasureable.KpiID      LEFT JOIN PMS_IndicatorMeasureableActual indMeasureableActual ON indMeasureable.KpiMeasureable_ID = indMeasureableActual.KpiMeasureableID AND indMeasureableActual.[Quarter] = @Quarter     WHERE IndicatorActual.OnHold = 1 AND IndicatorActual.[Quarter] = @Quarter AND IndicatorActual.[Quarter] = @Quarter AND ISNULL(isKpiApplicable, 1) <> 0    ) OnHold    GROUP BY NKPAItemId, NKPADesc   ) OnHold ON IDP.Item_ID = OnHold.NKPAItemId     -- Number of Targets Not Applicable   UPDATE @KPIAchievedPerNKPA   SET TotalNotApplicable = NumNotApplicable   FROM     @KPIAchievedPerNKPA NKPADet    INNER JOIN IDP_Item IDP ON NKPADet.NationalKPADetailID = IDP.NationalKPADetailID    INNER JOIN    (     SELECT NKPAItemId, NKPADesc, Count(*) AS NumNotApplicable       FROM       (       SELECT DISTINCT NKPAItemId, NKPADesc, Indi.ItemID       FROM PMS_NKPAIndicatorPerYear_fxn(@FinYear, @ScorecardTypeID      ) NKPA      INNER JOIN PMS_Indicator Indi ON  NKPA.KPIItemID = Indi.ItemID      INNER JOIN PMS_IndicatorMeasureable indMeasureable ON Indi.Kpi_ID = indMeasureable.KpiID      INNER JOIN PMS_IndicatorMeasureableActual indMeasureableActual ON indMeasureableActual.KpiMeasureableID = indMeasureable.KpiMeasureable_ID     WHERE indMeasureableActual.[Quarter] = @Quarter AND ISNULL(isKpiApplicable, 1) = 0    ) OnHold    GROUP BY NKPAItemId, NKPADesc   ) OnHold ON IDP.Item_ID = OnHold.NKPAItemId     UPDATE @KPIAchievedPerNKPA   SET UnableAssess = Total - (ISNULL(TotalAchieved,0) + ISNULL(TotalPartiallyAchieved,0) + ISNULL(TotalNotAchieved,0) + ISNULL(TotalOverAchieved,0) + ISNULL(TotalOnHold,0) + ISNULL(TotalNotApplicable, 0))     UPDATE @KPIAchievedPerNKPA   SET PercentageKPIAchieved = ((TotalAchieved + TotalOverAchieved) * 100) / (CASE WHEN (Total - TotalOnHold - TotalNotApplicable) = 0 THEN 1 ELSE (Total - TotalOnHold - TotalNotApplicable) END)     RETURN     END

GO

-- ============================================
-- Function: PMS_NKPAIndicatorPerYear_fxn
-- Type: SQL_TABLE_VALUED_FUNCTION
-- Schema: dbo
-- ============================================
-- =============================================================================    -- Author:  RC  -- Create date: 31/07/2015    -- Description: Returns table of National KPA linked to KPIs for the given financial year    -- The ItemID field in the PMS_Indicator table links to the leaf node on the in the IDP_Item table field Item_ID  -- This is required to calculate Organisational, Individual and departmental Performance percentage  -- Calls: select * from PMS_NKPAIndicatorPerYear_fxn('2014/2015')  -- Used in:  --  :   -- =============================================================================    CREATE FUNCTION [dbo].[PMS_NKPAIndicatorPerYear_fxn]     (     @FinYear NVARCHAR(9),   @ScorecardTypeID INT  )    RETURNS     @tblTotals TABLE     (       NKPAItemId INT,      NKPADesc VARCHAR(MAX),      KPIItemID INT   )    AS    BEGIN        WITH Hierarchy(NKPAItemId, NKPADesc, ParentId, Childs)   AS   (    SELECT Item_ID,  ItemDesc, ItemParentID, CAST('' AS VARCHAR(MAX))     FROM IDP_Item AS LastGeneration     WHERE FinancialYear = @FinYear AND Item_ID NOT IN (SELECT COALESCE(ItemParentID, 0) FROM IDP_Item WHERE FinancialYear = @FinYear)         UNION ALL    SELECT PrevGeneration.Item_ID, PrevGeneration.ItemDesc, PrevGeneration.ItemParentID,    CAST(CASE WHEN Child.Childs = ''     THEN(CAST(Child.NKPAItemId AS VARCHAR(MAX)))     ELSE(Child.Childs)    END AS VARCHAR(MAX))     FROM IDP_Item AS PrevGeneration     INNER JOIN Hierarchy AS Child ON PrevGeneration.Item_ID = Child.ParentId         WHERE FinancialYear = @FinYear   )     INSERT INTO @tblTotals      SELECT DISTINCT NKPAItemId, NKPADesc, CAST(Childs AS INT) AS KPIItemID   FROM Hierarchy h     INNER JOIN PMS_Indicator ind ON CAST(h.Childs AS INT) = ind.ItemID     INNER JOIN PMS_IndicatorScorecardType pist ON ind.Kpi_ID = pist.KpiID   WHERE h.ParentId IS NULL    AND pist.ScorecardTypeID = CASE WHEN @ScorecardTypeID = 0 THEN pist.ScorecardTypeID ELSE @ScorecardTypeID END AND pist.ScorecardTypeApplicable = 1    ORDER BY NKPAItemId      OPTION(MAXRECURSION 32767)     RETURN        END

GO

-- ============================================
-- Function: SCM_BudgetConsumptionTransactionDataMigration
-- Type: SQL_TABLE_VALUED_FUNCTION
-- Schema: dbo
-- ============================================
CREATE FUNCTION [dbo].[SCM_BudgetConsumptionTransactionDataMigration]()  RETURNS   @ResultSet TABLE     (     FinYear nvarchar(9),           PlanProjectItemID int ,           BudgetTxnId int,           ModuleId int,           PkTxnId int,            TableName nvarchar(100),           TxnAmount decimal(18, 2),           ProcessingMonth int,           BudgetConsumtionProcessId int,           TransactionCaptureDate datetime   )  AS  BEGIN      DECLARE @FinYearInclude TABLE (item varchar(25));      INSERT INTO @FinYearInclude VALUES ('2019/2020'),('2020/2021');      DECLARE @SCMModuleId INT = 9;      DECLARE @CaptureBudgetTxnId INT = 7;      DECLARE @ReserveBudgetTxnId INT = 2;      DECLARE @CommitBudgetTxnId INT = 3;      DECLARE @ActualBudgetTxnId INT = 4;      DECLARE @ReverseCommitBudgetTxnId INT = 10;  -------------- REQUISITION --------------      INSERT INTO @ResultSet -- RequisitionCapture      SELECT           sr.FinancialYear,          srsd.PlanProjectItemId,          @CaptureBudgetTxnId,          @SCMModuleId,          srsd.RequisitionDetail_ID,          'SCM_RequisitionServiceDetails',          CASE WHEN srsd.EstimatedCost = 0                   THEN -CAST(ISNULL(dbo.SCM_CalculateTransactionAmountByRequisitionDetailId_fnc(srsd.RequisitionDetail_ID, 'Quantity', srsd.Quantity) ,0.00) AS decimal(18, 2))                  ELSE -CAST(ISNULL(srsd.EstimatedCost * srsd.Quantity ,0.00) AS decimal(18, 2))          END,          NULL, -- to do          101, --  RequisitionCapture          srsd.DateCaptured      FROM dbo.SCM_RequisitionServiceDetails srsd          INNER JOIN dbo.SCM_Requisition sr ON srsd.RequisitionID = sr.Requisition_ID          INNER JOIN dbo.SCM_GeneralRequest sgr ON sr.Requisition_ID = sgr.SCMRequisitionID    INNER JOIN dbo.Const_RequestType_sys crts ON sgr.RequestTypeID = crts.RequestType_ID      WHERE sr.FinancialYear IN (SELECT item FROM @FinYearInclude)            AND (ISNULL(sr.IsDeleted, 0) = 0 OR ISNULL(sr.Enabled, 0) = 1)            AND crts.RequestDesc != 'Departmental Request'        INSERT INTO @ResultSet -- RequisitionApprovalSupervisor      SELECT           sr.FinancialYear,          srsd.PlanProjectItemId,          @CaptureBudgetTxnId,          @SCMModuleId,          srsd.RequisitionDetail_ID,          'SCM_RequisitionServiceDetails',          CASE WHEN srsd.EstimatedCost = 0                   THEN -CAST(ISNULL(dbo.SCM_CalculateTransactionAmountByRequisitionDetailId_fnc(srsd.RequisitionDetail_ID, 'Quantity', srsd.Quantity) ,0.00) AS decimal(18, 2))                  ELSE -CAST(ISNULL(srsd.EstimatedCost * srsd.Quantity ,0.00) AS decimal(18, 2))          END,          NULL,          103, --  RequisitionApprovalSupervisor          srsd.DateCaptured      FROM dbo.SCM_RequisitionServiceDetails srsd          INNER JOIN dbo.SCM_Requisition sr ON srsd.RequisitionID = sr.Requisition_ID          INNER JOIN dbo.SCM_GeneralRequest sgr ON sr.Requisition_ID = sgr.SCMRequisitionID    INNER JOIN dbo.Const_RequestType_sys crts ON sgr.RequestTypeID = crts.RequestType_ID      WHERE sr.FinancialYear IN (SELECT item FROM @FinYearInclude)            AND (ISNULL(sr.IsDeleted, 0) = 0 OR ISNULL(sr.Enabled, 0) = 1)            AND crts.RequestDesc != 'Departmental Request'            AND ISNULL(sr.SupervisorApproval, 0) = 1        INSERT INTO @ResultSet -- RequisitionApprovalHOD      SELECT           sr.FinancialYear,          srsd.PlanProjectItemId,          @ReserveBudgetTxnId,          @SCMModuleId,          srsd.RequisitionDetail_ID,          'SCM_RequisitionServiceDetails',          CASE WHEN srsd.EstimatedCost = 0                   THEN -CAST(ISNULL(dbo.SCM_CalculateTransactionAmountByRequisitionDetailId_fnc(srsd.RequisitionDetail_ID, 'Quantity', srsd.Quantity) ,0.00) AS decimal(18, 2))                  ELSE -CAST(ISNULL(srsd.EstimatedCost * srsd.Quantity ,0.00) AS decimal(18, 2))          END,          NULL,          104, --  RequisitionApprovalHOD          srsd.DateCaptured      FROM dbo.SCM_RequisitionServiceDetails srsd          INNER JOIN dbo.SCM_Requisition sr ON srsd.RequisitionID = sr.Requisition_ID          INNER JOIN dbo.SCM_GeneralRequest sgr ON sr.Requisition_ID = sgr.SCMRequisitionID    INNER JOIN dbo.Const_RequestType_sys crts ON sgr.RequestTypeID = crts.RequestType_ID      WHERE sr.FinancialYear IN (SELECT item FROM @FinYearInclude)            AND (ISNULL(sr.IsDeleted, 0) = 0 OR ISNULL(sr.Enabled, 0) = 1)            AND crts.RequestDesc != 'Departmental Request'            AND ISNULL(sr.HODApproval, 0) = 1  -------------- REQUISITION --------------    -------------- QUOTATION --------------      INSERT INTO @ResultSet -- QuotationCapture      SELECT           sq.FinancialYear,          sqsd.PlanProjectItemID,          @ReserveBudgetTxnId,          @SCMModuleId,          sqsd.QuotationServiceDel_ID,          'SCM_QuotationServiceDetail',          -CAST(ISNULL(sqsd.EstimatedCost * sqsd.Quantity ,0.00) AS decimal(18, 2)),          NULL,          107, --  QuotationCapture          sqsd.DateCaptured      FROM dbo.SCM_QuotationServiceDetail sqsd          INNER JOIN dbo.SCM_Quotation sq ON sqsd.QuotationID = sq.Quotation_ID      WHERE sq.FinancialYear IN (SELECT item FROM @FinYearInclude)            AND ISNULL(sq.Cancel,0)  = 0        INSERT INTO @ResultSet -- QuotationAdjudication      SELECT           sq.FinancialYear,          sqsd.PlanProjectItemID,          @ReserveBudgetTxnId,          @SCMModuleId,          sqsd.QuotationServiceDel_ID,          'SCM_QuotationServiceDetail',          -CAST(ISNULL(sqsd.EstimatedCost * sqsd.Quantity ,0.00) AS decimal(18, 2)),          NULL,          108, --  QuotationAdjudication          sqsd.DateCaptured      FROM dbo.SCM_QuotationServiceDetail sqsd          INNER JOIN dbo.SCM_Quotation sq ON sqsd.QuotationID = sq.Quotation_ID      WHERE sq.FinancialYear IN (SELECT item FROM @FinYearInclude)            AND ISNULL(sq.Cancel,0)  = 0            AND EXISTS (SELECT 1 FROM dbo.SCM_QuotationServiceVendorDetail sqsvd WHERE sq.Quotation_ID = sqsvd.QuotationId)        INSERT INTO @ResultSet -- QuotationAward      SELECT           sq.FinancialYear,          sqsd.PlanProjectItemID,          @ReserveBudgetTxnId,          @SCMModuleId,          sqsd.QuotationServiceDel_ID,          'SCM_QuotationServiceDetail',          -CAST(ISNULL(sqsvd.Cost ,0.00) AS decimal(18, 2)), -- to do          NULL,          109, --  QuotationAward          sqsd.DateCaptured      FROM dbo.SCM_QuotationServiceDetail sqsd          INNER JOIN dbo.SCM_Quotation sq ON sqsd.QuotationID = sq.Quotation_ID          INNER JOIN dbo.SCM_QuotationServiceVendorDetail sqsvd ON sqsd.QuotationServiceDel_ID = sqsvd.QuotationServiceDetailID AND ISNULL(sqsvd.Successful,0) = 1      WHERE sq.FinancialYear IN (SELECT item FROM @FinYearInclude)            AND ISNULL(sq.Cancel,0)  = 0        INSERT INTO @ResultSet -- QuotationApproval      SELECT           sq.FinancialYear,          sqsd.PlanProjectItemID,          @ReserveBudgetTxnId,          @SCMModuleId,          sqsd.QuotationServiceDel_ID,          'SCM_QuotationServiceDetail',          -CAST(ISNULL(sqsvd.Cost ,0.00) AS decimal(18, 2)), -- to do          NULL,          110, --  QuotationApproval          sqsd.DateCaptured      FROM dbo.SCM_QuotationServiceDetail sqsd          INNER JOIN dbo.SCM_Quotation sq ON sqsd.QuotationID = sq.Quotation_ID          INNER JOIN dbo.SCM_QuotationServiceVendorDetail sqsvd ON sqsd.QuotationServiceDel_ID = sqsvd.QuotationServiceDetailID  AND ISNULL(sqsvd.Successful,0) = 1      WHERE sq.FinancialYear IN (SELECT item FROM @FinYearInclude)            AND ISNULL(sq.Cancel, 0)  = 0            AND ISNULL(sq.Approved, 0)  = 1  -------------- QUOTATION --------------      -------------- INFORMAL TENDER --------------      INSERT INTO @ResultSet -- InformalTenderCapture      SELECT           sit.FinancialYear,          sitsd.PlanProjectItemID,          @ReserveBudgetTxnId,          @SCMModuleId,          sitsd.TenderServiceDel_ID,          'SCM_InformalTenderServiceDetail',          -CAST(ISNULL(sitsd.EstimatedCost * sitsd.Quantity ,0.00) AS decimal(18, 2)),          NULL,          113, --  InformalTenderCapture          sitsd.DateCaptured      FROM dbo.SCM_InformalTender sit          INNER JOIN dbo.SCM_InformalTenderServiceDetail sitsd ON sit.InformalTender_ID = sitsd.InformalTenderID      WHERE sit.FinancialYear IN (SELECT item FROM @FinYearInclude)            AND ISNULL(sit.Cancel,0)  = 0        INSERT INTO @ResultSet -- InformalTenderAdjudication      SELECT           sit.FinancialYear,          sitsd.PlanProjectItemID,          @ReserveBudgetTxnId,          @SCMModuleId,          sitsd.TenderServiceDel_ID,          'SCM_InformalTenderServiceDetail',          -CAST(ISNULL(sitsd.EstimatedCost * sitsd.Quantity ,0.00) AS decimal(18, 2)),          NULL,          114, --  InformalTenderAdjudication          sitsd.DateCaptured      FROM dbo.SCM_InformalTender sit          INNER JOIN dbo.SCM_InformalTenderServiceDetail sitsd ON sit.InformalTender_ID = sitsd.InformalTenderID      WHERE sit.FinancialYear IN (SELECT item FROM @FinYearInclude)            AND ISNULL(sit.Cancel,0)  = 0            AND EXISTS (SELECT 1 FROM dbo.SCM_InformalTenderServiceVendorDetail sitsvd WHERE sitsvd.InformalTenderID = sit.InformalTender_ID)        INSERT INTO @ResultSet -- InformalTenderAward      SELECT           sit.FinancialYear,          sitsd.PlanProjectItemID,          @ReserveBudgetTxnId,          @SCMModuleId,          sitsd.TenderServiceDel_ID,          'SCM_InformalTenderServiceDetail',          -CAST(ISNULL(sitsvd.Cost ,0.00) AS decimal(18, 2)),          NULL,          115, --  InformalTenderAward          sitsd.DateCaptured     FROM dbo.SCM_InformalTender sit          INNER JOIN dbo.SCM_InformalTenderServiceDetail sitsd ON sit.InformalTender_ID = sitsd.InformalTenderID          INNER JOIN dbo.SCM_InformalTenderServiceVendorDetail sitsvd ON sitsd.TenderServiceDel_ID = sitsvd.TenderServiceDelID AND ISNULL(sitsvd.Successful,0) = 1      WHERE sit.FinancialYear IN (SELECT item FROM @FinYearInclude)            AND ISNULL(sit.Cancel,0)  = 0        INSERT INTO @ResultSet -- InformalTenderApproval      SELECT           sit.FinancialYear,          sitsd.PlanProjectItemID,          @ReserveBudgetTxnId,          @SCMModuleId,          sitsd.TenderServiceDel_ID,          'SCM_InformalTenderServiceDetail',          -CAST(ISNULL(sitsvd.Cost ,0.00) AS decimal(18, 2)),          NULL,          116, --  InformalTenderApproval          sitsd.DateCaptured     FROM dbo.SCM_InformalTender sit          INNER JOIN dbo.SCM_InformalTenderServiceDetail sitsd ON sit.InformalTender_ID = sitsd.InformalTenderID          INNER JOIN dbo.SCM_InformalTenderServiceVendorDetail sitsvd ON sitsd.TenderServiceDel_ID = sitsvd.TenderServiceDelID AND ISNULL(sitsvd.Successful,0) = 1      WHERE sit.FinancialYear IN (SELECT item FROM @FinYearInclude)            AND ISNULL(sit.Cancel,0)  = 0            AND ISNULL(sit.Approved, 0)  = 1  -------------- INFORMAL TENDER --------------      -------------- TENDER --------------      INSERT INTO @ResultSet -- TenderCapture      SELECT           st.FinancialYear,          srsd.PlanProjectItemID,          @ReserveBudgetTxnId,          @SCMModuleId,          srtl.RequisitionTenderLink_ID,          'SCM_RequisitionTenderLink',          -CAST(ISNULL(srsd.EstimatedCost * srsd.Quantity ,0.00) AS decimal(18, 2)),          NULL,          119, --  TenderCapture          srtl.DateCaptured      FROM dbo.SCM_Tender st          INNER JOIN dbo.SCM_RequisitionTenderLink srtl ON st.Tender_ID = srtl.TenderID          INNER JOIN dbo.SCM_RequisitionServiceDetails srsd ON srsd.RequisitionDetail_ID = srtl.RequisitionDetailID      WHERE st.FinancialYear IN (SELECT item FROM @FinYearInclude)            AND ISNULL(st.TenderCancel,0)  = 0          INSERT INTO @ResultSet -- TenderAdjudication      SELECT           st.FinancialYear,          srsd.PlanProjectItemID,          @ReserveBudgetTxnId,          @SCMModuleId,          srtl.RequisitionTenderLink_ID,          'SCM_RequisitionTenderLink',          -CAST(ISNULL(srsd.EstimatedCost * srsd.Quantity ,0.00) AS decimal(18, 2)),          NULL,          120, --  TenderAdjudication          srtl.DateCaptured      FROM dbo.SCM_Tender st          INNER JOIN dbo.SCM_RequisitionTenderLink srtl ON st.Tender_ID = srtl.TenderID          INNER JOIN dbo.SCM_RequisitionServiceDetails srsd ON srsd.RequisitionDetail_ID = srtl.RequisitionDetailID      WHERE st.FinancialYear IN (SELECT item FROM @FinYearInclude)            AND ISNULL(st.TenderCancel,0)  = 0            AND EXISTS (SELECT 1 FROM dbo.SCM_TenderAdjudication sta WHERE sta.TenderID = st.Tender_ID)          INSERT INTO @ResultSet -- TenderAward      SELECT           st.FinancialYear,          srsd.PlanProjectItemID,          @ReserveBudgetTxnId,          @SCMModuleId,          stbp.PreferencePoints_ID,          'SCM_TenderBBBEEPreferencePoints',          -CAST(ISNULL(stbp.Cost,0.00) AS decimal(18, 2)),           NULL,          121, --  TenderAward          srtl.DateCaptured      FROM dbo.SCM_Tender st          INNER JOIN dbo.SCM_RequisitionTenderLink srtl ON st.Tender_ID = srtl.TenderID          INNER JOIN dbo.SCM_RequisitionServiceDetails srsd ON srsd.RequisitionDetail_ID = srtl.RequisitionDetailID          INNER JOIN dbo.SCM_TenderBBBEEPreferencePoints stbp ON srtl.RequisitionTenderLink_ID = stbp.TenderRequisitionLinkID          INNER JOIN dbo.SCM_TenderAwardedVendor stav ON stbp.PreferencePoints_ID = stav.PreferencePointsID      WHERE st.FinancialYear IN (SELECT item FROM @FinYearInclude)            AND ISNULL(st.TenderCancel,0)  = 0          INSERT INTO @ResultSet -- TenderApproval      SELECT           st.FinancialYear,          srsd.PlanProjectItemID,          @ReserveBudgetTxnId,          @SCMModuleId,          stbp.PreferencePoints_ID,          'SCM_TenderBBBEEPreferencePoints',          -CAST(ISNULL(stbp.Cost,0.00) AS decimal(18, 2)),           NULL,          122, --  TenderApproval          st.ApprovalDate      FROM dbo.SCM_Tender st          INNER JOIN dbo.SCM_RequisitionTenderLink srtl ON st.Tender_ID = srtl.TenderID          INNER JOIN dbo.SCM_RequisitionServiceDetails srsd ON srsd.RequisitionDetail_ID = srtl.RequisitionDetailID          INNER JOIN dbo.SCM_TenderBBBEEPreferencePoints stbp ON srtl.RequisitionTenderLink_ID = stbp.TenderRequisitionLinkID          INNER JOIN dbo.SCM_TenderAwardedVendor stav ON stbp.PreferencePoints_ID = stav.PreferencePointsID      WHERE st.FinancialYear IN (SELECT item FROM @FinYearInclude)            AND ISNULL(st.TenderCancel,0) = 0            AND ISNULL(st.ApprovalType,0) = 1  -------------- TENDER --------------      -------------- CONTRACT --------------      DECLARE @ContractCapturedStatus INT = 1;      DECLARE @ContractApprovedStatus INT = (SELECT TOP 1 csss.Status_ID FROM dbo.Const_SCMVendorStatus_sys csss WHERE csss.Module='Contract' AND csss.Status='Approved');        INSERT INTO @ResultSet -- ContractCapture      SELECT           scd.FinancialYear,          srsd.PlanProjectItemID,          @ReserveBudgetTxnId,          @SCMModuleId,          scdi.ContractDetailItems_ID,          'SCM_ContractDetailItems',          -CAST((scdi.TotalAmount - scdi.VatAmount) AS decimal(18, 2)),          NULL,          125, --  ContractCapture          scdi.DateCaptured      FROM dbo.SCM_ContractDetails scd          INNER JOIN dbo.SCM_ContractDetailItems scdi ON scd.Contract_ID = scdi.ContractID          INNER JOIN dbo.SCM_RequisitionServiceDetails srsd ON srsd.RequisitionDetail_ID = scdi.RequisitionDetailID      WHERE scd.FinancialYear IN (SELECT item FROM @FinYearInclude)            AND ISNULL(scd.IsVoid, 0) = 0            AND scd.ContractStatusId IN (@ContractCapturedStatus, @ContractApprovedStatus)        INSERT INTO @ResultSet -- ContractApprovalLastLevel      SELECT           scd.FinancialYear,          srsd.PlanProjectItemID,          @ReserveBudgetTxnId,          @SCMModuleId,          scdi.ContractDetailItems_ID,          'SCM_ContractDetailItems',          -CAST((scdi.TotalAmount - scdi.VatAmount) AS decimal(18, 2)),          NULL,          164, --  ContractApprovalLastLevel          scdi.DateCaptured      FROM dbo.SCM_ContractDetails scd          INNER JOIN dbo.SCM_ContractDetailItems scdi ON scd.Contract_ID = scdi.ContractID          INNER JOIN dbo.SCM_RequisitionServiceDetails srsd ON srsd.RequisitionDetail_ID = scdi.RequisitionDetailID      WHERE scd.FinancialYear IN (SELECT item FROM @FinYearInclude)            AND ISNULL(scd.IsVoid, 0) = 0            AND scd.ContractStatusId = @ContractApprovedStatus  -------------- CONTRACT --------------      -------------- CONTRACT SERVICE REQUEST --------------      INSERT INTO @ResultSet -- ContractServiceRequestCapture      SELECT           scsr.Finyear,          srsd.PlanProjectItemID,          @ReserveBudgetTxnId,          @SCMModuleId,          scsrd.ContractServiceRequestDetails_ID,          'SCM_ContractServiceRequest',          -CAST(ISNULL(scsrd.TotalAmountExcl ,0.00) AS decimal(18, 2)),          NULL,          128, --  ContractServiceRequestCapture          scsr.DateCaptured      FROM dbo.SCM_ContractServiceRequest scsr          INNER JOIN dbo.SCM_ContractServiceRequestDetails scsrd ON scsr.ContractServiceRequest_ID = scsrd.ContractServiceRequestId          INNER JOIN dbo.SCM_ServiceInvoiceDetails ssid ON scsrd.ServiceInvoiceDetail_ID = ssid.ServiceInvoiceDetail_ID          INNER JOIN dbo.SCM_RequisitionServiceDetails srsd ON ssid.RequisitionDetailID = srsd.RequisitionDetail_ID      WHERE scsr.Finyear IN (SELECT item FROM @FinYearInclude)            AND ISNULL(scsr.IsVoid, 0) = 0        INSERT INTO @ResultSet -- ContractServiceRequestApproval      SELECT           scsr.Finyear,          srsd.PlanProjectItemID,          @CommitBudgetTxnId,          @SCMModuleId,          scsrd.ContractServiceRequestDetails_ID,          'SCM_ContractServiceRequest',          -CAST(ISNULL(scsrd.TotalAmountExcl ,0.00) AS decimal(18, 2)),          NULL,          129, --  ContractServiceRequestApproval          scsr.ApprovedDate      FROM dbo.SCM_ContractServiceRequest scsr          INNER JOIN dbo.SCM_ContractServiceRequestDetails scsrd ON scsr.ContractServiceRequest_ID = scsrd.ContractServiceRequestId          INNER JOIN dbo.SCM_ServiceInvoiceDetails ssid ON scsrd.ServiceInvoiceDetail_ID = ssid.ServiceInvoiceDetail_ID          INNER JOIN dbo.SCM_RequisitionServiceDetails srsd ON ssid.RequisitionDetailID = srsd.RequisitionDetail_ID      WHERE scsr.Finyear IN (SELECT item FROM @FinYearInclude)            AND ISNULL(scsr.IsVoid, 0) = 0            AND ISNULL(scsr.Approved, 0) = 1  -------------- CONTRACT SERVICE REQUEST --------------      -------------- ORDER --------------      DECLARE @OrderVoidedStatus INT = (SELECT TOP 1 csss.Status_ID FROM dbo.Const_SCMVendorStatus_sys csss WHERE csss.Module='Order' AND csss.Status='Voided');      DECLARE @OrderDeclinedStatus INT = (SELECT TOP 1 csss.Status_ID FROM dbo.Const_SCMVendorStatus_sys csss WHERE csss.Module='Order' AND csss.Status='Declined');        INSERT INTO @ResultSet -- OrderCapture      SELECT           so.FinancialYear,          sotd.PlanProjectItemID,          @ReserveBudgetTxnId,          @SCMModuleId,          sotd.OrderDetailID,          'SCM_OrderTypeDetail',          -CAST(sotd.Amount AS decimal(18, 2)),          NULL,          132, --  OrderCapture          so.DateCaptured      FROM dbo.SCM_Order so          INNER JOIN dbo.SCM_OrderTypeDetail sotd ON so.Order_ID = sotd.OrderID      WHERE so.FinancialYear IN (SELECT item FROM @FinYearInclude)            AND ISNULL(sotd.IsVoid, 0) = 0            AND so.StatusID NOT IN (@OrderVoidedStatus, @OrderDeclinedStatus)        INSERT INTO @ResultSet -- OrderApproval      SELECT           so.FinancialYear,          sotd.PlanProjectItemID,          @CommitBudgetTxnId,          @SCMModuleId,          sotd.OrderDetailID,          'SCM_OrderTypeDetail',          -CAST(sotd.Amount AS decimal(18, 2)),          NULL,          133, --  OrderApproval          so.ApprovedDate      FROM dbo.SCM_Order so          INNER JOIN dbo.SCM_OrderTypeDetail sotd ON so.Order_ID = sotd.OrderID      WHERE so.FinancialYear IN (SELECT item FROM @FinYearInclude)            AND ISNULL(sotd.IsVoid, 0) = 0            AND so.StatusID NOT IN (@OrderVoidedStatus, @OrderDeclinedStatus)            AND ISNULL(so.ApprovedBy, 0) != 0  -------------- ORDER --------------      -------------- GRN -------------- // NOTE - isn`t poossible to void for old data      INSERT INTO @ResultSet -- GRNCapture      SELECT           sg.FinancialYear,          sgd.PlanProjectItemID,          @CommitBudgetTxnId,          @SCMModuleId,          sgd.GRNDetail_ID,          'SCM_GRNDetails',          -CAST(sgd.Amount AS decimal(18, 2)),          NULL,          136, --  GRNCapture          sg.DateCaptured      FROM dbo.SCM_GRN sg          INNER JOIN dbo.SCM_GRNDetails sgd ON sg.GRN_ID = sgd.GRNID      WHERE sg.FinancialYear IN (SELECT item FROM @FinYearInclude)  -------------- GRN --------------    -------------- Good Return Advice --------------       INSERT INTO @ResultSet -- GoodReturnAdvice      SELECT           sg.FinancialYear,          sgdn.PlanProjectItemID,          @ReverseCommitBudgetTxnId,          @SCMModuleId,          sgd.GRADetail_ID,          'SCM_GRADetails',          CAST(sgd.Amount AS decimal(18, 2)),          NULL,          138, --  GoodReturnAdvice          sg.DateCaptured      FROM dbo.SCM_GRA sg          INNER JOIN dbo.SCM_GRADetails sgd ON sg.GRA_ID = sgd.GRAID          INNER JOIN dbo.SCM_GoodsReturn sgr ON sgd.ReturnId = sgr.ID          INNER JOIN dbo.SCM_GRNDetails sgdn ON sgr.GRNDetailId = sgdn.GRNDetail_ID      WHERE sg.FinancialYear IN (SELECT item FROM @FinYearInclude)  -------------- Good Return Advice --------------     -------------- Invoice --------------       DECLARE @InvoiceVoidedStatus INT = (SELECT TOP 1 csss.Status_ID FROM dbo.Const_SCMVendorStatus_sys csss WHERE csss.Module='Invoice' AND csss.Status='Voided');      DECLARE @InvoiceDeclinedStatus INT = (SELECT TOP 1 csss.Status_ID FROM dbo.Const_SCMVendorStatus_sys csss WHERE csss.Module='Invoice' AND csss.Status='Declined');        INSERT INTO @ResultSet -- InvoiceGeneration      SELECT           si.FinancialYear,          sid.PlanProjectItemID,          @CommitBudgetTxnId,          @SCMModuleId,          sid.InvoiceDetail_ID,          'SCM_InvoiceDetail',          -CAST(sid.Amount AS decimal(18, 2)),          NULL,          139, --  InvoiceGeneration          si.DateCaptured      FROM dbo.SCM_Invoice si          INNER JOIN dbo.SCM_InvoiceDetail sid ON si.Invoice_ID = sid.InvoiceID      WHERE si.FinancialYear IN (SELECT item FROM @FinYearInclude)            AND si.StatusID NOT IN (@InvoiceVoidedStatus, @InvoiceDeclinedStatus)            AND ISNULL(sid.IsVoid, 0) = 0        INSERT INTO @ResultSet -- InvoiceApprovalLastLevel      SELECT           si.FinancialYear,          sid.PlanProjectItemID,          @ActualBudgetTxnId,          @SCMModuleId,          sid.InvoiceDetail_ID,          'SCM_InvoiceDetail',          -CAST(sid.Amount AS decimal(18, 2)),          NULL,          141, --  InvoiceApprovalLastLevel          si.FinalApprovedDate      FROM dbo.SCM_Invoice si          INNER JOIN dbo.SCM_InvoiceDetail sid ON si.Invoice_ID = sid.InvoiceID      WHERE si.FinancialYear IN (SELECT item FROM @FinYearInclude)            AND si.StatusID NOT IN (@InvoiceVoidedStatus, @InvoiceDeclinedStatus)            AND ISNULL(sid.IsVoid, 0) = 0            AND ISNULL(si.FinalApprovedBy, 0) != 0  -------------- Invoice --------------       -------------- Sundry Invoice --------------       INSERT INTO @ResultSet -- SundryInvoiceGeneration      SELECT           ssp.FinancialYear,          sspsd.PlanProjectItemID,          @CaptureBudgetTxnId,          @SCMModuleId,          sspsd.SundryPaymentDetail_ID,          'SCM_SundryPaymentServiceDetails',          -CAST(sspsd.Amount AS decimal(18, 2)),          NULL,          144, --  SundryInvoiceGeneration          ssp.DateCaptured      FROM dbo.SCM_SundryPayment ssp          INNER JOIN dbo.SCM_SundryPaymentServiceDetails sspsd ON ssp.SundryPayment_ID = sspsd.SundryPaymentID      WHERE ssp.FinancialYear IN (SELECT item FROM @FinYearInclude)            AND ssp.StatusID NOT IN (@InvoiceVoidedStatus, @InvoiceDeclinedStatus)            AND ISNULL(ssp.IsVoid, 0) = 0        INSERT INTO @ResultSet -- SundryInvoiceApprovalSupervisor      SELECT           ssp.FinancialYear,          sspsd.PlanProjectItemID,          @CaptureBudgetTxnId,          @SCMModuleId,          sspsd.SundryPaymentDetail_ID,          'SCM_SundryPaymentServiceDetails',          -CAST(sspsd.Amount AS decimal(18, 2)),          NULL,          145, --  SundryInvoiceApprovalSupervisor          ssp.DateCaptured      FROM dbo.SCM_SundryPayment ssp          INNER JOIN dbo.SCM_SundryPaymentServiceDetails sspsd ON ssp.SundryPayment_ID = sspsd.SundryPaymentID      WHERE ssp.FinancialYear IN (SELECT item FROM @FinYearInclude)            AND ssp.StatusID NOT IN (@InvoiceVoidedStatus, @InvoiceDeclinedStatus)            AND ISNULL(ssp.IsVoid, 0) = 0            AND ISNULL(ssp.SupervisorApproval, 0) = 1        INSERT INTO @ResultSet -- SundryInvoiceApprovalLastLevel      SELECT           ssp.FinancialYear,          sspsd.PlanProjectItemID,          @ActualBudgetTxnId,          @SCMModuleId,          sspsd.SundryPaymentDetail_ID,          'SCM_SundryPaymentServiceDetails',          -CAST(sspsd.Amount AS decimal(18, 2)),          NULL,          146, --  SundryInvoiceApprovalLastLevel          ssp.DateCaptured      FROM dbo.SCM_SundryPayment ssp          INNER JOIN dbo.SCM_SundryPaymentServiceDetails sspsd ON ssp.SundryPayment_ID = sspsd.SundryPaymentID      WHERE ssp.FinancialYear IN (SELECT item FROM @FinYearInclude)            AND ssp.StatusID NOT IN (@InvoiceVoidedStatus, @InvoiceDeclinedStatus)            AND ISNULL(ssp.IsVoid, 0) = 0            AND ISNULL(ssp.SupervisorApproval, 0) = 1            AND ISNULL(ssp.HODApproval, 0) = 1  -------------- Sundry Invoice --------------       -------------- Credit Note --------------       DECLARE @CreditNoteTransactionType INT = (SELECT TOP 1 cst.SCMTransactionType_ID FROM dbo.Const_SCMTransactionType cst WHERE cst.SCMTransactionDesc='SCM Credit Note');        INSERT INTO @ResultSet -- CreditNoteGeneration      SELECT           lgl.FinYear,          sicd.PlanProjectItemId,          @ActualBudgetTxnId,          @SCMModuleId,          sicd.InvoiceCreditDetail_ID,          'SCM_InvoiceCreditDetail',          -CAST(sicd.Amount AS decimal(18, 2)),          lgl.ProcessingMonth,          150, --  CreditNoteGeneration          sicdn.DateCaptured      FROM dbo.SCM_InvoiceCreditDebtNote sicdn          INNER JOIN dbo.SCM_InvoiceCreditDetail sicd ON sicdn.ID = sicd.InvoiceCreditID          LEFT JOIN dbo.Led_GeneralLedger lgl ON sicd.InvoiceCreditDetail_ID = lgl.ExtraLinkID_1               AND lgl.ExtraLinkDesc='SCM_InvoiceCreditDetail' AND sicd.SCOAItemID = lgl.SCOAItemID      WHERE lgl.FinYear IN (SELECT item FROM @FinYearInclude)            AND sicdn.NoteType = 1 -- credit       ORDER BY sicd.InvoiceCreditDetail_ID    -------------- Credit Note --------------       -------------- Debit Note --------------       DECLARE @DebitNoteTransactionType INT = (SELECT TOP 1 cst.SCMTransactionType_ID FROM dbo.Const_SCMTransactionType cst WHERE cst.SCMTransactionDesc='SCM Debit Note');        INSERT INTO @ResultSet -- DebitNoteGeneration      SELECT           lgl.FinYear,          sicd.PlanProjectItemId,          @ActualBudgetTxnId,          @SCMModuleId,          sicd.InvoiceCreditDetail_ID,          'SCM_InvoiceCreditDetail',          CAST(sicd.Amount AS decimal(18, 2)),          lgl.ProcessingMonth,          149, --  DebitNoteGeneration          sicdn.DateCaptured      FROM dbo.SCM_InvoiceCreditDebtNote sicdn          INNER JOIN dbo.SCM_InvoiceCreditDetail sicd ON sicdn.ID = sicd.InvoiceCreditID          LEFT JOIN dbo.Led_GeneralLedger lgl ON sicd.InvoiceCreditDetail_ID = lgl.ExtraLinkID_1               AND lgl.ExtraLinkDesc='SCM_InvoiceCreditDetail' AND sicd.SCOAItemID = lgl.SCOAItemID      WHERE lgl.FinYear IN (SELECT item FROM @FinYearInclude)            AND sicdn.NoteType = 2 -- debit             AND sicdn.CommandDescription != 'GRA Debit'      ORDER BY sicd.InvoiceCreditDetail_ID    -------------- Debit Note --------------     -------------- Payment --------------       DECLARE @PaymentVoidedStatus INT = (SELECT TOP 1 csss.Status_ID FROM dbo.Const_SCMVendorStatus_sys csss WHERE csss.Module='Payment' AND csss.Status='Voided');      DECLARE @PaymentDeclinedStatus INT = (SELECT TOP 1 csss.Status_ID FROM dbo.Const_SCMVendorStatus_sys csss WHERE csss.Module='Payment' AND csss.Status='Declined');      DECLARE @PaymentCancelledStatus INT = (SELECT TOP 1 csss.Status_ID FROM dbo.Const_SCMVendorStatus_sys csss WHERE csss.Module='Payment' AND csss.Status='Cancelled');        INSERT INTO @ResultSet -- PaymentInstructionGeneration      SELECT           COALESCE(si.FinancialYear, ssp.FinancialYear, sihd.Finyear),          COALESCE(sid.PlanProjectItemID, sspsd.PlanProjectItemID, sihd.PlanProjectItemID),          @ActualBudgetTxnId,          @SCMModuleId,          lpid.PaymentInstructionDetail_ID,          'Led_PaymentInstructionDetails',          -CAST((spa.AllocationAmount - ISNULL(spa.VATApportionmentAmount, 0.0)) AS decimal(18, 2)),          NULL,          151, --  PaymentInstructionGeneration          sp.DateCaptured      FROM dbo.SCM_Payment sp          INNER JOIN dbo.SCM_PaymentAllocation spa ON sp.Payment_ID = spa.PaymentID          INNER JOIN dbo.Led_PaymentInstructionDetails lpid ON spa.PaymentInstructionDetailID = lpid.PaymentInstructionDetail_ID          LEFT JOIN dbo.SCM_InvoiceDetail sid ON spa.InvoiceDetailID = sid.InvoiceDetail_ID          LEFT JOIN dbo.SCM_Invoice si ON si.Invoice_ID = sid.InvoiceID          LEFT JOIN dbo.SCM_SundryPaymentServiceDetails sspsd ON spa.SundryPaymentDetailID = sspsd.SundryPaymentDetail_ID          LEFT JOIN dbo.SCM_SundryPayment ssp ON ssp.SundryPayment_ID  =sspsd.SundryPaymentID          LEFT JOIN dbo.SCM_InvoiceHistoryDetail sihd ON spa.InvoiceHistoryDetail_ID = sihd.InvoiceHistoryDetail_ID      WHERE COALESCE(si.FinancialYear, ssp.FinancialYear, sihd.Finyear) IN (SELECT item FROM @FinYearInclude)            AND COALESCE(sid.PlanProjectItemID, sspsd.PlanProjectItemID, sihd.PlanProjectItemID) IS NOT NULL            AND ISNULL(sp.IsVoid, 0) = 0            AND sp.StatusID NOT IN (@PaymentVoidedStatus,@PaymentDeclinedStatus,@PaymentCancelledStatus )      ORDER BY sp.Payment_ID          INSERT INTO @ResultSet -- PaymentInstructionApprovalIntermediateLevel      SELECT           COALESCE(si.FinancialYear, ssp.FinancialYear, sihd.Finyear),          COALESCE(sid.PlanProjectItemID, sspsd.PlanProjectItemID, sihd.PlanProjectItemID),          @ActualBudgetTxnId,          @SCMModuleId,          lpid.PaymentInstructionDetail_ID,          'Led_PaymentInstructionDetails',          -CAST((spa.AllocationAmount - ISNULL(spa.VATApportionmentAmount, 0.0)) AS decimal(18, 2)),          NULL,          152, --  PaymentInstructionApprovalIntermediateLevel          sp.DateCaptured      FROM dbo.SCM_Payment sp          INNER JOIN dbo.SCM_PaymentAllocation spa ON sp.Payment_ID = spa.PaymentID          INNER JOIN dbo.Led_PaymentInstructionDetails lpid ON spa.PaymentInstructionDetailID = lpid.PaymentInstructionDetail_ID          LEFT JOIN dbo.SCM_InvoiceDetail sid ON spa.InvoiceDetailID = sid.InvoiceDetail_ID          LEFT JOIN dbo.SCM_Invoice si ON si.Invoice_ID = sid.InvoiceID          LEFT JOIN dbo.SCM_SundryPaymentServiceDetails sspsd ON spa.SundryPaymentDetailID = sspsd.SundryPaymentDetail_ID          LEFT JOIN dbo.SCM_SundryPayment ssp ON ssp.SundryPayment_ID  =sspsd.SundryPaymentID          LEFT JOIN dbo.SCM_InvoiceHistoryDetail sihd ON spa.InvoiceHistoryDetail_ID = sihd.InvoiceHistoryDetail_ID      WHERE COALESCE(si.FinancialYear, ssp.FinancialYear, sihd.Finyear) IN (SELECT item FROM @FinYearInclude)            AND COALESCE(sid.PlanProjectItemID, sspsd.PlanProjectItemID, sihd.PlanProjectItemID) IS NOT NULL            AND ISNULL(sp.IsVoid, 0) = 0            AND sp.StatusID NOT IN (@PaymentVoidedStatus,@PaymentDeclinedStatus,@PaymentCancelledStatus )            AND ISNULL(sp.SupervisorApproved, 0) != 0      ORDER BY sp.Payment_ID        INSERT INTO @ResultSet -- PaymentInstructionApprovalLastLevel      SELECT           COALESCE(si.FinancialYear, ssp.FinancialYear, sihd.Finyear),          COALESCE(sid.PlanProjectItemID, sspsd.PlanProjectItemID, sihd.PlanProjectItemID),          @ActualBudgetTxnId,          @SCMModuleId,          lpid.PaymentInstructionDetail_ID,          'Led_PaymentInstructionDet

GO

-- ============================================
-- Function: Section71_Budget_fxn
-- Type: SQL_TABLE_VALUED_FUNCTION
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  Chris Moodley  -- Create date: 04 December 2019  -- Description: Return correct budgte to use for A schedule  -- =============================================  CREATE FUNCTION [dbo].[Section71_Budget_fxn]  (   -- Add the parameters for the function here    @FinYear VARCHAR(10)    )  RETURNS   @Budget TABLE  (   -- Add the column definitions for the TABLE variable here    BudgetVersion_ID INT   ,Project_ID INT   ,ProjectName VARCHAR(1000)   ,PlanProjectItemID INT   ,FinYear VARCHAR(10)   ,ScoaProjectID INT   ,SCOAItemID INT   ,SCOAFundId INT   ,DivisionId INT   ,SCOAFunctionId INT   ,SCOARegionId INT   ,SCOACostingID INT   ,BudgetAmount DECIMAL(16,2)   ,BudgetAmountCurP1 DECIMAL(16,2)   ,BudgetAmountCurP2 DECIMAL(16,2)   ,IsDeleted BIT   ,BudgetMonth1 DECIMAL(16,2)   ,BudgetMonth2 DECIMAL(16,2)   ,BudgetMonth3 DECIMAL(16,2)   ,BudgetMonth4 DECIMAL(16,2)   ,BudgetMonth5 DECIMAL(16,2)   ,BudgetMonth6 DECIMAL(16,2)   ,BudgetMonth7 DECIMAL(16,2)   ,BudgetMonth8 DECIMAL(16,2)   ,BudgetMonth9 DECIMAL(16,2)   ,BudgetMonth10 DECIMAL(16,2)   ,BudgetMonth11 DECIMAL(16,2)   ,BudgetMonth12 DECIMAL(16,2)   ,SingleMultiYear VARCHAR(5)   ,CapitalOperation INT   ,CreditDebit VARCHAR(6)  )  AS  BEGIN   -- Fill the table variable with the rows for your result set   DECLARE @budgetVersionID INT     SELECT @budgetVersionID = ISNULL(dbo.Section71_BudgetOriginalVersionID_fxn(@FinYear), -1)     IF (@budgetVersionID = -1)   BEGIN    INSERT INTO @Budget    SELECT        -1 AS BudgetVersion_ID,        Project_ID,        ProjectName,        PlanProjectItemID,        FinYear,        ScoaProjectID,        SCOAItemID,        SCOAFundId,        DivisionId,        SCOAFunctionId,        SCOARegionId,        SCOACostingID,        BudgetAmount,        BudgetAmountCurP1,        BudgetAmountCurP2,        IsDeleted,        BudgetMonth1,        BudgetMonth2,        BudgetMonth3,        BudgetMonth4,        BudgetMonth5,        BudgetMonth6,        BudgetMonth7,        BudgetMonth8,        BudgetMonth9,        BudgetMonth10,        BudgetMonth11,        BudgetMonth12,        SingleMultiYear,        CapitalOperation,        CreditDebit    FROM dbo.Section71_ProjectBudget_vw WHERE FinYear = @FinYear   END   ELSE   BEGIN    INSERT INTO @Budget    SELECT        BudgetVersion_ID,        Project_ID,        ProjectName,        PlanProjectItemID,        FinYear,        ScoaProjectID,        SCOAItemID,        SCOAFundId,        DivisionId,        SCOAFunctionId,        SCOARegionId,        SCOACostingID,        BudgetAmount,        BudgetAmountCurP1,        BudgetAmountCurP2,        IsDeleted,        BudgetMonth1,        BudgetMonth2,        BudgetMonth3,        BudgetMonth4,        BudgetMonth5,        BudgetMonth6,        BudgetMonth7,        BudgetMonth8,        BudgetMonth9,        BudgetMonth10,        BudgetMonth11,        BudgetMonth12,        SingleMultiYear,        CapitalOperation,        CreditDebit    FROM Section71_BudgetOriginal_vw WHERE BudgetVersion_ID = @BudgetVersionID   END     RETURN   END

GO

-- ============================================
-- Function: Section71_BudgetAdjustmentCouncilApprovedVersionID_fxn
-- Type: SQL_SCALAR_FUNCTION
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:   Chris Moodley  -- Create date: 12 March 2021  -- Description:   Returns adjustment version ID for council approved budget  -- =============================================  CREATE FUNCTION Section71_BudgetAdjustmentCouncilApprovedVersionID_fxn  (   -- Add the parameters for the function here   @finYear VARCHAR(10)  )  RETURNS INT  AS  BEGIN   -- Declare the return variable here   DECLARE @budgetAdjustmentVersionID INT = NULL     -- Add the T-SQL statements to compute the return value here   IF EXISTS (SELECT 1 FROM Plan_AdjustmentBudgetApproval WHERE IsCouncilApproved = 1 and FinancialYear = @finYear)   BEGIN    SELECT @budgetAdjustmentVersionID = AdjustmentVersionID    FROM Plan_AdjustmentBudgetApproval     WHERE IsCouncilApproved = 1 and FinancialYear = @finYear   END     -- Return the result of the function   RETURN @budgetAdjustmentVersionID    END

GO

-- ============================================
-- Function: Section71_BudgetAdjustmentMonthID_fxn
-- Type: SQL_SCALAR_FUNCTION
-- Schema: dbo
-- ============================================
-- ==============================================================================  -- Author:  Chris Moodley  -- Create date: 05 May 2018  -- Description: Return Adjustment Budget Month ID when adjustment budget approved  -- ==============================================================================  CREATE FUNCTION [dbo].[Section71_BudgetAdjustmentMonthID_fxn]  (   -- Add the parameters for the function here   @budgetAdjustmentVersionID INT  )  RETURNS INT  AS  BEGIN   -- Declare the return variable here   DECLARE @budgetAdjustmentMonthID INT     -- Add the T-SQL statements to compute the return value here   SELECT @budgetAdjustmentMonthID = MONTH(DateCaptured) FROM Plan_AdjustmentBudgetVersion WHERE AdjustmentBudgetVersion_ID = @budgetAdjustmentVersionID     IF @budgetAdjustmentMonthID <= 6 BEGIN SET @budgetAdjustmentMonthID = @budgetAdjustmentMonthID + 6 END ELSE BEGIN SET @budgetAdjustmentMonthID = @budgetAdjustmentMonthID - 6 END      -- Return the result of the function   RETURN @budgetAdjustmentMonthID    END  

GO

-- ============================================
-- Function: Section71_BudgetAdjustmentVersionCount_fxn
-- Type: SQL_SCALAR_FUNCTION
-- Schema: dbo
-- ============================================
-- ==============================================================================  -- Author:  Chris Moodley  -- Create date: 03 July 2020  -- Description: Return number of adjustments per financial year  -- ==============================================================================  CREATE FUNCTION [dbo].[Section71_BudgetAdjustmentVersionCount_fxn]  (   -- Add the parameters for the function here   @finYear VARCHAR(10)  )  RETURNS INT  AS  BEGIN   -- Declare the return variable here   DECLARE @budgetAdjustmentVersionCount INT     -- Add the T-SQL statements to compute the return value here   SELECT TOP 1 @budgetAdjustmentVersionCount = COUNT(DISTINCT AdjustmentBudgetVersion_ID)   FROM    (     SELECT       AdjustmentBudgetVersion_ID,       CASE WHEN MONTH(papv.DateCaptured) <= 6 THEN MONTH(papv.DateCaptured) + 6 ELSE MONTH(papv.DateCaptured) - 6 END AS MonthApproved     FROM Plan_AdjustmentBudgetVersion papv        INNER JOIN dbo.Plan_AdjustmentProject pap ON pap.AdjustmentVersionId = papv.AdjustmentBudgetVersion_ID     WHERE VersionName LIKE @finYear + '%' AND Comments LIKE '%Adjustment Budget approved by Council%'          ) a     -- Return the result of the function   RETURN @budgetAdjustmentVersionCount    END

GO

-- ============================================
-- Function: Section71_BudgetAdjustmentVersionID_fxn
-- Type: SQL_SCALAR_FUNCTION
-- Schema: dbo
-- ============================================
  -- ==============================================================================  -- Author:  Chris Moodley  -- Create date: 05 May 2018  -- Description: Return Adjustment Budget Version ID when adjustment budget approved  -- 20190802 by CM: Return latest version ID per month selected  -- ==============================================================================  CREATE FUNCTION [dbo].[Section71_BudgetAdjustmentVersionID_fxn]  (   -- Add the parameters for the function here   @finYear VARCHAR(10),   @monthID INT = 12  )  RETURNS INT  AS  BEGIN   -- Declare the return variable here   DECLARE @budgetAdjustmentVersionID INT     -- Add the T-SQL statements to compute the return value here   --SELECT @budgetAdjustmentVersionID = MAX(AdjustmentBudgetVersion_ID) FROM Plan_AdjustmentBudgetVersion WHERE SUBSTRING(VersionName, 1, 9) = @finYear AND Comments LIKE '%Adjustment Budget approved by Council%'      SELECT TOP 1 @budgetAdjustmentVersionID = AdjustmentBudgetVersion_ID   FROM    (     SELECT       AdjustmentBudgetVersion_ID,       CASE WHEN MONTH(papv.DateCaptured) <= 6 THEN MONTH(papv.DateCaptured) + 6 ELSE MONTH(papv.DateCaptured) - 6 END AS MonthApproved     FROM Plan_AdjustmentBudgetVersion papv        INNER JOIN dbo.Plan_AdjustmentProject pap ON pap.AdjustmentVersionId = papv.AdjustmentBudgetVersion_ID     WHERE VersionName LIKE @finYear + '%' AND Comments LIKE '%Adjustment Budget approved by Council%'          ) a   WHERE    MonthApproved <= @monthID   ORDER BY AdjustmentBudgetVersion_ID DESC     -- Return the result of the function   RETURN @budgetAdjustmentVersionID    END  

GO

-- ============================================
-- Function: Section71_BudgetAdjustmentVersionPreviousID_fxn
-- Type: SQL_SCALAR_FUNCTION
-- Schema: dbo
-- ============================================
-- ==============================================================================  -- Author:  Chris Moodley  -- Create date: 03 July 2020  -- Description: Return Previous Adjustment Budget Version ID when adjustment budget approved  -- ==============================================================================  CREATE FUNCTION [dbo].[Section71_BudgetAdjustmentVersionPreviousID_fxn]  (   -- Add the parameters for the function here   @finYear VARCHAR(10),   @maxAdjustmentVersionID INT,   @monthID INT = 12  )  RETURNS INT  AS  BEGIN   -- Declare the return variable here   DECLARE @budgetAdjustmentVersionID INT     -- Add the T-SQL statements to compute the return value here   SELECT TOP 1 @budgetAdjustmentVersionID = AdjustmentBudgetVersion_ID   FROM    (     SELECT       AdjustmentBudgetVersion_ID,       CASE WHEN MONTH(papv.DateCaptured) <= 6 THEN MONTH(papv.DateCaptured) + 6 ELSE MONTH(papv.DateCaptured) - 6 END AS MonthApproved     FROM Plan_AdjustmentBudgetVersion papv        INNER JOIN dbo.Plan_AdjustmentProject pap ON pap.AdjustmentVersionId = papv.AdjustmentBudgetVersion_ID     WHERE VersionName LIKE @finYear + '%' AND Comments LIKE '%Adjustment Budget approved by Council%'          ) a   WHERE    MonthApproved <= @monthID AND a.AdjustmentBudgetVersion_ID <> @maxAdjustmentVersionID   ORDER BY AdjustmentBudgetVersion_ID DESC     -- Return the result of the function   RETURN @budgetAdjustmentVersionID    END

GO

-- ============================================
-- Function: Section71_BudgetOriginalVersionID_fxn
-- Type: SQL_SCALAR_FUNCTION
-- Schema: dbo
-- ============================================
-- ==============================================================================  -- Author:  Chris Moodley  -- Create date: 05 May 2018  -- Description: Return Original Budget Version ID when original budget approved  -- ==============================================================================  CREATE FUNCTION [dbo].[Section71_BudgetOriginalVersionID_fxn]  (   -- Add the parameters for the function here   @finYear VARCHAR(10)  )  RETURNS INT  AS  BEGIN   -- Declare the return variable here   DECLARE @budgetOriginalVersionID INT     -- Add the T-SQL statements to compute the return value here   SELECT @budgetOriginalVersionID = MAX(BudgetVersion_ID) FROM Plan_BudgetVersion WHERE SUBSTRING(VersionName, 1, 9) = @finYear AND Comments LIKE '%Budget approved by Council%'     -- Return the result of the function   RETURN @budgetOriginalVersionID    END  

GO

-- ============================================
-- Function: Section71_BudgetSign
-- Type: SQL_SCALAR_FUNCTION
-- Schema: dbo
-- ============================================
-- =============================================  -- Author:  <Author,,Name>  -- Create date: <Create Date, ,>  -- Description: <Description, ,>  -- =============================================  CREATE FUNCTION Section71_BudgetSign   (   -- Add the parameters for the function here   @scoaItemCode NVARCHAR(50),   @capitalOperational INT,   @creditDebit NVARCHAR(1),   @scoaItemShortDesc NVARCHAR(200)  )  RETURNS INT  AS  BEGIN   -- Declare the return variable here   DECLARE @sign INT = 1     -- Add the T-SQL statements to compute the return value here   SELECT @sign =     CASE WHEN      --@type = 1 and --think we should exclude @type (CapitalOperation)     @scoaItemCode like 'IL%' and @scoaItemShortDesc in ('Deposits', 'Withdrawals')      THEN CASE WHEN @scoaItemShortDesc in ('Deposits') THEN -1 ELSE 1 END     ELSE CASE WHEN      (((@scoaItemCode like 'IL%' OR @scoaItemCode LIKE 'IR%') AND @capitalOperational IN (0,1,2)) OR @creditDebit = 'C') THEN -1 ELSE 1 END    END     -- Return the result of the function   RETURN @sign    END  

GO

